	public abstract class SkeletonDebugGizmos : MonoBehaviour
	{
		[Flags]
		public enum VisibilityFlags
		{
			Joints = 1,
			Axes = 2,
			Bones = 4
		}

		[Tooltip("Which components of the skeleton will be visualized.")]
		[SerializeField]
		private VisibilityFlags _visibility = VisibilityFlags.Joints | VisibilityFlags.Axes;

		[Tooltip("The joint debug spheres will be drawn with this color.")]
		[SerializeField]
		private Color _jointColor = Color.white;

		[Tooltip("The bone connecting lines will be drawn with this color.")]
		[SerializeField]
		private Color _boneColor = Color.gray;

		[Tooltip("The radius of the joint spheres and the thickness of the bone and axis lines.")]
		[SerializeField]
		private float _radius = 0.02f;

		public float Radius
		{
			get
			{
				return _radius;
			}
			set
			{
				_radius = value;
			}
		}

		public VisibilityFlags Visibility
		{
			get
			{
				return _visibility;
			}
			set
			{
				_visibility = value;
			}
		}

		public Color JointColor
		{
			get
			{
				return _jointColor;
			}
			set
			{
				_jointColor = value;
			}
		}

		public Color BoneColor
		{
			get
			{
				return _boneColor;
			}
			set
			{
				_boneColor = value;
			}
		}

		private float LineWidth => _radius / 2f;

		protected bool HasNegativeScale
		{
			get
			{
				if (!(base.transform.lossyScale.x < 0f) && !(base.transform.lossyScale.y < 0f))
				{
					return base.transform.lossyScale.z < 0f;
				}
				return true;
			}
		}

		protected abstract bool TryGetJointPose(int jointId, out Pose pose);

		protected abstract bool TryGetParentJointId(int jointId, out int parent);

		protected void Draw(int joint, VisibilityFlags visibility)
		{
			if (TryGetJointPose(joint, out var pose))
			{
				if (visibility.HasFlag(VisibilityFlags.Axes))
				{
					DebugGizmos.LineWidth = LineWidth;
					DebugGizmos.DrawAxis(pose, _radius);
				}
				if (visibility.HasFlag(VisibilityFlags.Joints))
				{
					DebugGizmos.Color = _jointColor;
					DebugGizmos.LineWidth = _radius;
					DebugGizmos.DrawPoint(pose.position);
				}
				if (visibility.HasFlag(VisibilityFlags.Bones) && TryGetParentJointId(joint, out var parent) && TryGetJointPose(parent, out var pose2))
				{
					DebugGizmos.Color = _boneColor;
					DebugGizmos.LineWidth = LineWidth;
					DebugGizmos.DrawLine(pose.position, pose2.position);
				}
			}
		}
	}
	public static class Collisions
	{
		public static Vector3 ClosestPointToColliders(Vector3 point, Collider[] colliders)
		{
			Vector3 result = point;
			float num = float.PositiveInfinity;
			foreach (Collider collider in colliders)
			{
				Vector3 vector = ClosestPointToCollider(point, collider);
				float num2 = Vector3.SqrMagnitude(vector - point);
				if (num2 <= float.Epsilon)
				{
					return vector;
				}
				if (num2 < num)
				{
					num = num2;
					result = vector;
				}
			}
			return result;
		}

		public static Vector3 ClosestPointToCollider(Vector3 point, Collider collider)
		{
			if (collider is MeshCollider meshCollider)
			{
				if (meshCollider.convex)
				{
					Vector3 vector = Physics.ClosestPoint(point, collider, collider.transform.position, collider.transform.rotation);
					if (Vector3.SqrMagnitude(vector - point) < collider.contactOffset * collider.contactOffset)
					{
						return point;
					}
					return vector;
				}
				return meshCollider.ClosestPointOnBounds(point);
			}
			return Physics.ClosestPoint(point, collider, collider.transform.position, collider.transform.rotation);
		}

		[Obsolete("This method is not in use and will soon be deleted.")]
		public static bool IsCapsuleWithinColliderApprox(Vector3 p0, Vector3 p1, float radius, Collider collider)
		{
			int num = Mathf.CeilToInt((p1 - p0).magnitude / radius) * 2;
			if (num == 0)
			{
				return IsSphereWithinCollider(p0, radius, collider);
			}
			float num2 = 1f / (float)num;
			for (int i = 0; i <= num; i++)
			{
				if (IsSphereWithinCollider(Vector3.Lerp(p0, p1, num2 * (float)i), radius, collider))
				{
					return true;
				}
			}
			return false;
		}

		public static bool IsPointWithinCollider(Vector3 point, Collider collider)
		{
			return Vector3.SqrMagnitude(ClosestPointToCollider(point, collider) - point) <= float.Epsilon;
		}

		public static bool IsSphereWithinCollider(Vector3 point, float radius, Collider collider)
		{
			return Vector3.SqrMagnitude(ClosestPointToCollider(point, collider) - point) <= radius * radius;
		}
	}
