			_filter = filter;
		}

		public void InjectRenderer(MeshRenderer renderer)
		{
			_renderer = renderer;
		}

		public void InjectDivisions(int divisions)
		{
			_divisions = divisions;
		}

		public void InjectBevel(int bevel)
		{
			_bevel = bevel;
		}
