	public static class HashSetExtensions
	{
		public static void UnionWithNonAlloc<T>(this HashSet<T> hashSetToModify, HashSet<T> other)
		{
			if (hashSetToModify == null)
			{
				throw new ArgumentNullException("hashSetToModify");
			}
			if (other == null)
			{
				throw new ArgumentNullException("other");
			}
			foreach (T item in other)
			{
				hashSetToModify.Add(item);
			}
		}

		public static void UnionWithNonAlloc<T>(this HashSet<T> hashSetToModify, IList<T> other)
		{
			if (hashSetToModify == null)
			{
				throw new ArgumentNullException("hashSetToModify");
			}
			if (other == null)
			{
				throw new ArgumentNullException("other");
			}
			for (int i = 0; i < other.Count; i++)
			{
				hashSetToModify.Add(other[i]);
			}
		}

		public static void ExceptWithNonAlloc<T>(this HashSet<T> hashSetToModify, HashSet<T> other)
		{
			if (hashSetToModify == null)
			{
				throw new ArgumentNullException("hashSetToModify");
			}
			if (other == null)
			{
				throw new ArgumentNullException("other");
			}
			if (hashSetToModify.Count == 0)
			{
				return;
			}
			if (other == hashSetToModify)
			{
				hashSetToModify.Clear();
				return;
			}
			foreach (T item in other)
			{
				hashSetToModify.Remove(item);
			}
		}

		public static void ExceptWithNonAlloc<T>(this HashSet<T> hashSetToModify, IList<T> other)
		{
			if (hashSetToModify == null)
			{
				throw new ArgumentNullException("hashSetToModify");
			}
			if (other == null)
			{
				throw new ArgumentNullException("other");
			}
			if (hashSetToModify.Count != 0)
			{
				for (int i = 0; i < other.Count; i++)
				{
					hashSetToModify.Remove(other[i]);
				}
			}
		}

		public static bool OverlapsNonAlloc<T>(this HashSet<T> hashSetToCheck, HashSet<T> other)
		{
			if (hashSetToCheck == null)
			{
				throw new ArgumentNullException("hashSetToCheck");
			}
			if (other == null)
			{
				throw new ArgumentNullException("other");
			}
			if (hashSetToCheck.Count == 0)
			{
				return false;
			}
			foreach (T item in other)
			{
				if (hashSetToCheck.Contains(item))
				{
					return true;
				}
			}
			return false;
		}

		public static bool OverlapsNonAlloc<T>(this HashSet<T> hashSetToCheck, IList<T> other)
		{
			if (hashSetToCheck == null)
			{
				throw new ArgumentNullException("hashSetToCheck");
			}
			if (other == null)
			{
				throw new ArgumentNullException("other");
			}
			if (hashSetToCheck.Count == 0)
			{
				return false;
			}
			for (int i = 0; i < other.Count; i++)
			{
				if (hashSetToCheck.Contains(other[i]))
				{
					return true;
				}
			}
			return false;
		}
	}
	public static class MonoBehaviourStartExtensions
	{
		public static void BeginStart(this MonoBehaviour monoBehaviour, ref bool started, Action baseStart = null)
		{
			if (!started)
			{
				monoBehaviour.enabled = false;
				started = true;
				baseStart?.Invoke();
				started = false;
			}
			else
			{
				baseStart?.Invoke();
			}
		}

		public static void EndStart(this MonoBehaviour monoBehaviour, ref bool started)
		{
			if (!started)
			{
				started = true;
				monoBehaviour.enabled = true;
			}
		}
	}
	public static class TransformExtensions
	{
		public static Vector3 InverseTransformPointUnscaled(this Transform transform, Vector3 position)
		{
			return Matrix4x4.TRS(transform.position, transform.rotation, Vector3.one).inverse.MultiplyPoint3x4(position);
		}

		public static Vector3 TransformPointUnscaled(this Transform transform, Vector3 position)
		{
			return Matrix4x4.TRS(transform.position, transform.rotation, Vector3.one).MultiplyPoint3x4(position);
		}

		public static Bounds TransformBounds(this Transform transform, in Bounds bounds)
		{
			Bounds result = default(Bounds);
			Vector3 min = bounds.min;
			Vector3 max = bounds.max;
			Vector3 position = transform.position;
			Vector3 position2 = transform.position;
			Matrix4x4 localToWorldMatrix = transform.localToWorldMatrix;
			for (int i = 0; i < 3; i++)
			{
				for (int j = 0; j < 3; j++)
				{
					float num = localToWorldMatrix[i, j] * min[j];
					float num2 = localToWorldMatrix[i, j] * max[j];
					position[i] += ((num < num2) ? num : num2);
					position2[i] += ((num < num2) ? num2 : num);
				}
			}
			result.SetMinMax(position, position2);
			return result;
		}

		public static Transform FindChildRecursive(this Transform parent, string name)
		{
			return parent.FindChildRecursive((Transform child) => child.name.Contains(name));
		}

		public static Transform FindChildRecursive(this Transform parent, Predicate<Transform> predicate)
		{
			foreach (Transform item in parent)
			{
				if (predicate(item))
				{
					return item;
				}
				Transform transform2 = item.FindChildRecursive(predicate);
				if (transform2 != null)
				{
					return transform2;
				}
			}
			return null;
		}
	}
	public static class VectorExtensions
	{
		public static bool Approximately(this Vector3 a, Vector3 b, float epsilon = 1E-05f)
		{
			return (a - b).sqrMagnitude <= epsilon * epsilon;
		}
	}
