		protected bool _started;

		private IHandGrabInteractor HandGrab { get; set; }

		private IInteractor Interactor { get; set; }

		public float GlowLerpSpeed
		{
			get
			{
				return _glowLerpSpeed;
			}
			set
			{
				_glowLerpSpeed = value;
			}
		}

		public float GlowColorLerpSpeed
		{
			get
			{
				return _glowColorLerpSpeed;
			}
			set
			{
				_glowColorLerpSpeed = value;
			}
		}

		public Color FingerGlowColorWithInteractable
		{
			get
			{
				return _fingerGlowColorWithInteractable;
			}
			set
			{
				_fingerGlowColorWithInteractable = value;
			}
		}

		public Color FingerGlowColorWithNoInteractable
		{
			get
			{
				return _fingerGlowColorWithNoInteractable;
			}
			set
			{
				_fingerGlowColorWithNoInteractable = value;
			}
		}

		public Color FingerGlowColorHover
		{
			get
			{
				return _fingerGlowColorHover;
			}
			set
			{
				_fingerGlowColorHover = value;
			}
		}

		private void Awake()
		{
			HandGrab = _handGrabInteractor as IHandGrabInteractor;
			Interactor = _handGrabInteractor as IInteractor;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Interactor.WhenPostprocessed += UpdateVisual;
				_currentGlowColor = _fingerGlowColorWithNoInteractable;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Interactor.WhenPostprocessed -= UpdateVisual;
			}
		}

		private void UpdateVisual()
		{
			bool flag = Interactor.State == InteractorState.Select;
			bool hasSelectedInteractable = Interactor.HasSelectedInteractable;
			bool hasCandidate = Interactor.HasCandidate;
			Color b = _fingerGlowColorHover;
			if (flag)
			{
				b = (hasSelectedInteractable ? _fingerGlowColorWithInteractable : _fingerGlowColorWithNoInteractable);
			}
			_currentGlowColor = Color.Lerp(_currentGlowColor, b, Time.deltaTime * _glowColorLerpSpeed);
			_handMaterialPropertyBlockEditor.MaterialPropertyBlock.SetColor(_fingerGlowColorPropertyId, _currentGlowColor);
			for (int i = 0; i < 5; i++)
			{
				if ((flag && !hasSelectedInteractable) || (!flag && !hasCandidate))
				{
					UpdateGlowValue(i, 0f);
					continue;
				}
				float num = 0f;
				Oculus.Interaction.Input.HandFinger handFinger = (Oculus.Interaction.Input.HandFinger)i;
				if ((HandGrab.SupportedGrabTypes & GrabTypeFlags.Pinch) != GrabTypeFlags.None && HandGrab.TargetInteractable != null && (HandGrab.TargetInteractable.SupportedGrabTypes & GrabTypeFlags.Pinch) != GrabTypeFlags.None && HandGrab.TargetInteractable.PinchGrabRules[handFinger] != FingerRequirement.Ignored)
				{
					num = Mathf.Max(num, HandGrab.HandGrabApi.GetFingerPinchStrength(handFinger));
				}
				if ((HandGrab.SupportedGrabTypes & GrabTypeFlags.Palm) != GrabTypeFlags.None && HandGrab.TargetInteractable != null && (HandGrab.TargetInteractable.SupportedGrabTypes & GrabTypeFlags.Palm) != GrabTypeFlags.None && HandGrab.TargetInteractable.PalmGrabRules[handFinger] != FingerRequirement.Ignored)
				{
					num = Mathf.Max(num, HandGrab.HandGrabApi.GetFingerPalmStrength(handFinger));
				}
				UpdateGlowValue(i, num);
			}
			_handMaterialPropertyBlockEditor.UpdateMaterialPropertyBlock();
		}

		private void UpdateGlowValue(int fingerIndex, float glowValue)
		{
			float value = Mathf.MoveTowards(_handMaterialPropertyBlockEditor.MaterialPropertyBlock.GetFloat(_handShaderGlowPropertyIds[fingerIndex]), glowValue, _glowLerpSpeed * Time.deltaTime);
			_handMaterialPropertyBlockEditor.MaterialPropertyBlock.SetFloat(_handShaderGlowPropertyIds[fingerIndex], value);
		}

		public void InjectAllGrabStrengthIndicator(IHandGrabInteractor handGrabInteractor, MaterialPropertyBlockEditor handMaterialPropertyBlockEditor)
		{
			InjectHandGrab(handGrabInteractor);
			InjectHandMaterialPropertyBlockEditor(handMaterialPropertyBlockEditor);
		}

		public void InjectHandGrab(IHandGrabInteractor handGrab)
		{
			_handGrabInteractor = handGrab as UnityEngine.Object;
			HandGrab = handGrab;
			Interactor = handGrab as IInteractor;
		}

		public void InjectHandMaterialPropertyBlockEditor(MaterialPropertyBlockEditor handMaterialPropertyBlockEditor)
		{
			_handMaterialPropertyBlockEditor = handMaterialPropertyBlockEditor;
		}
	}
	public class HandFingerMaskGenerator
	{
		private static readonly int[] _fingerLinesID = new int[5]
		{
			Shader.PropertyToID("_ThumbLine"),
			Shader.PropertyToID("_IndexLine"),
			Shader.PropertyToID("_MiddleLine"),
			Shader.PropertyToID("_RingLine"),
			Shader.PropertyToID("_PinkyLine")
		};

		private static readonly int[] _palmFingerLinesID = new int[5]
		{
			Shader.PropertyToID("_PalmThumbLine"),
			Shader.PropertyToID("_PalmIndexLine"),
			Shader.PropertyToID("_PalmMiddleLine"),
			Shader.PropertyToID("_PalmRingLine"),
			Shader.PropertyToID("_PalmPinkyLine")
		};

		private static float HandednessMultiplier(Oculus.Interaction.Input.Handedness hand)
		{
			if (hand == Oculus.Interaction.Input.Handedness.Right)
			{
				return 1f;
			}
			return -1f;
		}

		private static List<Vector2> GenerateModelUV(Oculus.Interaction.Input.Handedness handedness, Mesh sharedHandMesh, out Vector2 minPosition, out Vector2 maxPosition)
		{
			List<Vector3> list = new List<Vector3>();
			sharedHandMesh.GetVertices(list);
			minPosition = new Vector2(list[0].x, list[0].z);
			maxPosition = new Vector2(list[0].x, list[0].z);
			for (int i = 0; i < list.Count; i++)
			{
				Vector3 value = list[i] * HandednessMultiplier(handedness);
				Vector2 rhs = new Vector2(value.x, value.z);
				minPosition = Vector2.Min(minPosition, rhs);
				maxPosition = Vector2.Max(maxPosition, rhs);
				list[i] = value;
			}
			List<Vector2> list2 = new List<Vector2>();
			Vector2 vector = maxPosition - minPosition;
			float num = Mathf.Max(vector.x, vector.y);
			foreach (Vector3 item2 in list)
			{
				Vector2 item = (new Vector2(item2.x, item2.z) - minPosition) / num;
				list2.Add(item);
			}
			return list2;
		}

		private static Vector2 GetPositionOnRegion(HandVisual handVisual, Oculus.Interaction.Input.HandJointId jointId, Vector2 minRegion, float sideLength)
		{
			IHand hand = handVisual.Hand;
			Pose pose = handVisual.Joints[(int)jointId].GetPose();
			Vector3 vector = handVisual.Root.InverseTransformPoint(pose.position);
			return (new Vector2(vector.x, vector.z) * HandednessMultiplier(hand.Handedness) - minRegion) / sideLength;
		}

		private static Vector4[] GenerateFingerLines(HandVisual handVisual, Vector2 minPosition, float maxLength, float[] lineScale)
		{
			Vector4 vector = GenerateLineData(handVisual, Oculus.Interaction.Input.HandJointId.HandThumbTip, Oculus.Interaction.Input.HandJointId.HandThumb1, minPosition, maxLength, lineScale[0]);
			Vector4 vector2 = GenerateLineData(handVisual, Oculus.Interaction.Input.HandJointId.HandIndexTip, Oculus.Interaction.Input.HandJointId.HandIndex1, minPosition, maxLength, lineScale[1]);
			Vector4 vector3 = GenerateLineData(handVisual, Oculus.Interaction.Input.HandJointId.HandMiddleTip, Oculus.Interaction.Input.HandJointId.HandMiddle1, minPosition, maxLength, lineScale[2]);
			Vector4 vector4 = GenerateLineData(handVisual, Oculus.Interaction.Input.HandJointId.HandRingTip, Oculus.Interaction.Input.HandJointId.HandRing1, minPosition, maxLength, lineScale[3]);
			Vector4 vector5 = GenerateLineData(handVisual, Oculus.Interaction.Input.HandJointId.HandPinkyTip, Oculus.Interaction.Input.HandJointId.HandPinky1, minPosition, maxLength, lineScale[4]);
			return new Vector4[5] { vector, vector2, vector3, vector4, vector5 };
		}

		private static Vector4 GenerateLineData(HandVisual handVisual, Oculus.Interaction.Input.HandJointId jointIdStart, Oculus.Interaction.Input.HandJointId jointIdEnd, Vector2 minRegion, float sideLength, float lineScale)
		{
			Vector2 positionOnRegion = GetPositionOnRegion(handVisual, jointIdStart, minRegion, sideLength);
			Vector2 positionOnRegion2 = GetPositionOnRegion(handVisual, jointIdEnd, minRegion, sideLength);
			positionOnRegion2 = Vector2.LerpUnclamped(positionOnRegion, positionOnRegion2, lineScale);
			return new Vector4(positionOnRegion.x, positionOnRegion.y, positionOnRegion2.x, positionOnRegion2.y);
		}

		private static void SetGlowModelUV(SkinnedMeshRenderer handRenderer, Oculus.Interaction.Input.Handedness handedness, out Vector2 minPosition, out Vector2 maxPosition)
		{
			Mesh sharedMesh = handRenderer.sharedMesh;
			List<Vector2> uvs = GenerateModelUV(handedness, sharedMesh, out minPosition, out maxPosition);
			sharedMesh.SetUVs(1, uvs);
			sharedMesh.UploadMeshData(markNoLongerReadable: false);
		}

		private static void SetFingerMaskUniforms(HandVisual handVisual, MaterialPropertyBlock materialPropertyBlock, Vector2 minPosition, Vector2 maxPosition)
		{
			Vector2 vector = maxPosition - minPosition;
			float maxLength = Mathf.Max(vector.x, vector.y);
			float[] lineScale = new float[5] { 0.9f, 0.91f, 0.9f, 0.87f, 0.87f };
			Vector4[] array = GenerateFingerLines(handVisual, minPosition, maxLength, lineScale);
			array[0].z = Mathf.Lerp(array[0].z, array[0].x, 0.3f);
			array[0].x = array[0].z;
			float[] lineScale2 = new float[5] { 1.2f, 1.25f, 1.25f, 1.25f, 1.25f };
			Vector4[] array2 = GenerateFingerLines(handVisual, minPosition, maxLength, lineScale2);
			float num = Mathf.Abs(array2[0].x - array2[0].z) * 0.1f;
			array2[0].z += num;
			for (int i = 0; i < 5; i++)
			{
				materialPropertyBlock.SetVector(_fingerLinesID[i], array[i]);
				materialPropertyBlock.SetVector(_palmFingerLinesID[i], array2[i]);
			}
		}

		public static void GenerateFingerMask(SkinnedMeshRenderer handRenderer, HandVisual handVisual, MaterialPropertyBlock materialPropertyBlock)
		{
			SetGlowModelUV(handRenderer, handVisual.Hand.Handedness, out var minPosition, out var maxPosition);
			SetFingerMaskUniforms(handVisual, materialPropertyBlock, minPosition, maxPosition);
		}
	}
	public class HandGrabGlow : MonoBehaviour
	{
		public enum GlowType
		{
			Fill = 27,
			Outline,
			Both
		}

		private enum GlowState
		{
			None,
			Hover,
			Selected,
			SelectedGlowOut
		}

		private enum GrabState
		{
			None,
			Pinch,
			Palm
		}

		[SerializeField]
		[Interface(typeof(IHandGrabInteractor), new Type[] { typeof(IInteractor) })]
		private UnityEngine.Object _handGrabInteractor;

		[SerializeField]
		private HandVisual _handVisual;

		[SerializeField]
		private SkinnedMeshRenderer _handRenderer;

		[SerializeField]
		private MaterialPropertyBlockEditor _materialEditor;

		[SerializeField]
		private Color _glowColorGrabing;

		[SerializeField]
		private Color _glowColorHover;

		[SerializeField]
		[Range(0f, 1f)]
		private float _colorChangeSpeed = 0.5f;

		[SerializeField]
		[Range(0f, 0.25f)]
		private float _glowFadeStartTime = 0.2f;

		[SerializeField]
		[Range(0f, 1f)]
		private float _glowStrengthChangeSpeed = 0.5f;

		[SerializeField]
		private bool _fadeOut;

		[SerializeField]
		[Range(0f, 1f)]
		[Tooltip("Recommended from 0.7 to 1.0")]
		private float _gradientLength = 0.85f;

		[SerializeField]
		private GlowType _glowType = GlowType.Outline;

		private GlowState _state;

		private float _accumulatedSelectedTime;

		private GrabState _grabState;

		private float _glowFadeValue;

		private Color _currentColor;

		private IHandGrabInteractor HandGrabInteractor;

		private IInteractor Interactor;

		private float[] _glowStregth = new float[5];

		private readonly int _generateGlowID = Shader.PropertyToID("_GenerateGlow");

		private readonly int _glowColorID = Shader.PropertyToID("_GlowColor");

		private readonly int _glowTypeID = Shader.PropertyToID("_GlowType");

		private readonly int _glowParameterID = Shader.PropertyToID("_GlowParameter");

		private readonly int[] _fingersGlowIDs = new int[5]
		{
			Shader.PropertyToID("_ThumbGlowValue"),
			Shader.PropertyToID("_IndexGlowValue"),
			Shader.PropertyToID("_MiddleGlowValue"),
			Shader.PropertyToID("_RingGlowValue"),
			Shader.PropertyToID("_PinkyGlowValue")
		};

		protected bool _started;

		protected virtual void Awake()
		{
			_glowFadeValue = 1f;
			_state = GlowState.None;
			_grabState = GrabState.None;
			HandGrabInteractor = _handGrabInteractor as IHandGrabInteractor;
			Interactor = _handGrabInteractor as IInteractor;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			HandFingerMaskGenerator.GenerateFingerMask(_handRenderer, _handVisual, _materialEditor.MaterialPropertyBlock);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Interactor.WhenPostprocessed += UpdateVisual;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Interactor.WhenPostprocessed -= UpdateVisual;
			}
		}

		private void SetMaterialPropertyBlockValues()
		{
			MaterialPropertyBlock materialPropertyBlock = _materialEditor.MaterialPropertyBlock;
			if (materialPropertyBlock == null)
			{
				return;
			}
			materialPropertyBlock.SetInt(_generateGlowID, 1);
			materialPropertyBlock.SetColor(_glowColorID, _currentColor);
			if (_glowType == GlowType.Fill || _glowType == GlowType.Both)
			{
				float num = _gradientLength;
				if (_fadeOut)
				{
					num *= _glowFadeValue;
				}
				materialPropertyBlock.SetFloat(_glowParameterID, num);
			}
			else
			{
				materialPropertyBlock.SetFloat(_glowParameterID, _glowFadeValue);
			}
			for (int i = 0; i < _fingersGlowIDs.Length; i++)
			{
				materialPropertyBlock.SetFloat(_fingersGlowIDs[i], Mathf.Clamp01(_glowStregth[i]));
			}
			materialPropertyBlock.SetInt(_glowTypeID, (int)_glowType);
		}

		private void UpdateFingerGlowStrength(int fingerIndex, float strength)
		{
			float num = Mathf.Lerp(_glowStregth[fingerIndex], strength, _glowStrengthChangeSpeed);
			_glowStregth[fingerIndex] = num;
		}

		private bool FingerOptionalOrRequired(GrabbingRule rules, Oculus.Interaction.Input.HandFinger finger)
		{
			if (rules[finger] != FingerRequirement.Optional)
			{
				return rules[finger] == FingerRequirement.Required;
			}
			return true;
		}

		private void UpdateGlowStrength()
		{
			float b = 0f;
			for (int i = 1; i < 5; i++)
			{
				Oculus.Interaction.Input.HandFinger finger = (Oculus.Interaction.Input.HandFinger)i;
				bool flag = FingerOptionalOrRequired(HandGrabInteractor.TargetInteractable.PinchGrabRules, finger);
				float a = ((TargetSupportsPinch() && flag) ? HandGrabInteractor.HandGrabApi.GetFingerPinchStrength(finger) : 0f);
				bool flag2 = FingerOptionalOrRequired(HandGrabInteractor.TargetInteractable.PalmGrabRules, finger);
				float b2 = ((TargetSupportsPalm() && flag2) ? HandGrabInteractor.HandGrabApi.GetFingerPalmStrength(finger) : 0f);
				float strength = Mathf.Max(a, b2);
				UpdateFingerGlowStrength(i, strength);
				b = Mathf.Max(a, b);
			}
			bool flag3 = FingerOptionalOrRequired(HandGrabInteractor.TargetInteractable.PalmGrabRules, Oculus.Interaction.Input.HandFinger.Thumb);
			float a2 = ((TargetSupportsPalm() && flag3) ? HandGrabInteractor.HandGrabApi.GetFingerPalmStrength(Oculus.Interaction.Input.HandFinger.Thumb) : 0f);
			UpdateFingerGlowStrength(0, Mathf.Max(a2, b));
		}

		private void UpdateGlowState()
		{
			if (Interactor.State == InteractorState.Hover)
			{
				_state = GlowState.Hover;
			}
			else if (Interactor.State == InteractorState.Select)
			{
				if (_state == GlowState.Hover || _state == GlowState.None)
				{
					_accumulatedSelectedTime = 0f;
					_state = GlowState.Selected;
				}
				else if (_state == GlowState.Selected)
				{
					_accumulatedSelectedTime += Time.deltaTime;
					if (_fadeOut && _accumulatedSelectedTime >= _glowFadeStartTime)
					{
						_state = GlowState.SelectedGlowOut;
					}
				}
			}
			else
			{
				_state = GlowState.None;
			}
		}

		private void UpdateGlowColorAndFade()
		{
			if (_state == GlowState.Hover)
			{
				_glowFadeValue = 1f;
				_currentColor = Color.Lerp(_currentColor, _fadeOut ? _glowColorGrabing : _glowColorHover, _colorChangeSpeed);
			}
			else if (_state == GlowState.Selected)
			{
				if (_fadeOut)
				{
					_glowFadeValue = Mathf.Lerp(_glowFadeValue, 0.5f, 0.8f);
					_currentColor = _glowColorGrabing;
				}
				else
				{
					_glowFadeValue = 1f;
					_currentColor = Color.Lerp(_currentColor, _glowColorGrabing, _colorChangeSpeed);
				}
			}
			else if (_state == GlowState.SelectedGlowOut)
			{
				_glowFadeValue = Mathf.Lerp(_glowFadeValue, 1.15f, 0.3f);
				_currentColor = _glowColorGrabing;
			}
			else
			{
				_glowFadeValue = Mathf.Lerp(_glowFadeValue, 0f, 0.15f);
			}
		}

		private bool TargetSupportsPinch()
		{
			if (HandGrabInteractor.TargetInteractable == null)
			{
				return false;
			}
			return (HandGrabInteractor.SupportedGrabTypes & HandGrabInteractor.TargetInteractable.SupportedGrabTypes & GrabTypeFlags.Pinch) != 0;
		}

		private bool TargetSupportsPalm()
		{
			if (HandGrabInteractor.TargetInteractable == null)
			{
				return false;
			}
			return (HandGrabInteractor.SupportedGrabTypes & HandGrabInteractor.TargetInteractable.SupportedGrabTypes & GrabTypeFlags.Palm) != 0;
		}

		private void UpdateGrabState()
		{
			if (HandGrabInteractor.TargetInteractable == null)
			{
				_grabState = GrabState.None;
				return;
			}
			GrabbingRule fingers = HandGrabInteractor.TargetInteractable.PinchGrabRules;
			bool flag = HandGrabInteractor.HandGrabApi.IsHandPinchGrabbing(in fingers);
			if (TargetSupportsPinch() && flag && (_grabState == GrabState.None || _grabState == GrabState.Pinch))
			{
				_grabState = GrabState.Pinch;
				return;
			}
			GrabbingRule fingers2 = HandGrabInteractor.TargetInteractable.PalmGrabRules;
			bool flag2 = HandGrabInteractor.HandGrabApi.IsHandPalmGrabbing(in fingers2);
			if (TargetSupportsPalm() && flag2 && (_grabState == GrabState.None || _grabState == GrabState.Palm))
			{
				_grabState = GrabState.Palm;
			}
			else
			{
				_grabState = GrabState.None;
			}
		}

		private void ClearGlow()
		{
			MaterialPropertyBlock materialPropertyBlock = _materialEditor.MaterialPropertyBlock;
			int[] fingersGlowIDs = _fingersGlowIDs;
			foreach (int nameID in fingersGlowIDs)
			{
				materialPropertyBlock.SetFloat(nameID, 0f);
			}
			materialPropertyBlock.SetInt(_generateGlowID, 0);
		}

		private void UpdateVisual()
		{
			GlowState state = _state;
			UpdateGrabState();
			UpdateGlowState();
			if (state != _state && _state == GlowState.None)
			{
				ClearGlow();
			}
			else if (_state != GlowState.None)
			{
				UpdateGlowStrength();
				UpdateGlowColorAndFade();
				SetMaterialPropertyBlockValues();
			}
		}

		public void InjectAllHandGrabGlow(IHandGrabInteractor handGrabInteractor, SkinnedMeshRenderer handRenderer, MaterialPropertyBlockEditor materialEditor, HandVisual handVisual, Color grabbingColor, Color hoverColor, float colorChangeSpeed, float fadeStartTime, float glowStrengthChangeSpeed, bool fadeOut, float gradientLength, GlowType glowType)
		{
			InjectHandGrabInteractor(handGrabInteractor);
			InjectHandRenderer(handRenderer);
			InjectMaterialPropertyBlockEditor(materialEditor);
			InjectHandVisual(handVisual);
			InjectGlowColors(grabbingColor, hoverColor);
			InjectVisualChangeSpeed(colorChangeSpeed, fadeStartTime, glowStrengthChangeSpeed);
			InjectFadeOut(fadeOut);
			InjectGradientLength(gradientLength);
			InjectGlowType(glowType);
		}

		public void InjectHandGrabInteractor(IHandGrabInteractor handGrabInteractor)
		{
			_handGrabInteractor = handGrabInteractor as UnityEngine.Object;
			Interactor = handGrabInteractor as IInteractor;
			HandGrabInteractor = handGrabInteractor;
		}

		public void InjectHandRenderer(SkinnedMeshRenderer handRenderer)
		{
			_handRenderer = handRenderer;
		}

		public void InjectMaterialPropertyBlockEditor(MaterialPropertyBlockEditor materialEditor)
		{
			_materialEditor = materialEditor;
		}

		public void InjectHandVisual(HandVisual handVisual)
		{
			_handVisual = handVisual;
		}

		public void InjectGlowColors(Color grabbingColor, Color hoverColor)
		{
			_glowColorGrabing = grabbingColor;
			_glowColorHover = hoverColor;
		}

		public void InjectVisualChangeSpeed(float colorChangeSpeed, float fadeStartTime, float glowStrengthChangeSpeed)
		{
			_colorChangeSpeed = colorChangeSpeed;
			_glowFadeStartTime = fadeStartTime;
			_glowStrengthChangeSpeed = glowStrengthChangeSpeed;
		}

		public void InjectFadeOut(bool fadeOut)
		{
			_fadeOut = fadeOut;
		}

		public void InjectGradientLength(float gradientLength)
		{
			_gradientLength = Mathf.Clamp01(gradientLength);
		}

		public void InjectGlowType(GlowType glowType)
		{
			_glowType = glowType;
		}
	}
	public class HandPokeOvershootGlow : MonoBehaviour
	{
		public enum GlowType
		{
			Fill = 30,
			Outline,
			Both
		}

		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _hand;

		[SerializeField]
		private PokeInteractor _pokeInteractor;

		[SerializeField]
		private HandVisual _handVisual;

		[SerializeField]
		private SkinnedMeshRenderer _handRenderer;

		[SerializeField]
		private MaterialPropertyBlockEditor _materialEditor;

		[SerializeField]
		private Color _glowColor;

		[SerializeField]
