		public StatePrecedence Precedence
		{
			get
			{
				return _precedence;
			}
			set
			{
				_precedence = value;
			}
		}

		public bool Active
		{
			get
			{
				if (Precedence == StatePrecedence.Off)
				{
					if (Off.Active)
					{
						_internalActive = false;
					}
					else if (On.Active)
					{
						_internalActive = true;
					}
				}
				else if (Precedence == StatePrecedence.On)
				{
					if (On.Active)
					{
						_internalActive = true;
					}
					else if (Off.Active)
					{
						_internalActive = false;
					}
				}
				if (_internalActive)
				{
					return base.isActiveAndEnabled;
				}
				return false;
			}
		}

