			}
		}

		public override bool ShouldUnhover
		{
			get
			{
				if (base.State != InteractorState.Hover)
				{
					return false;
				}
				if (!AnyInteractor(IsHoverAndShouldUnhoverPredicate))
				{
					return !AnyInteractor(IsHover);
				}
				return true;
			}
		}

		public override bool ShouldSelect
		{
			get
			{
				if (base.State != InteractorState.Hover)
				{
					return false;
				}
				return AnyInteractor(IsHoverAndShouldSelectPredicate);
			}
		}

		public override bool ShouldUnselect
		{
			get
			{
				if (base.State != InteractorState.Select)
				{
					return false;
				}
				if (_bestInteractor != null)
				{
					return _bestInteractor.ShouldUnselect;
				}
				return false;
			}
		}

		public override bool HasCandidate
		{
			get
			{
				if (_bestInteractor != null && _bestInteractor.HasCandidate)
				{
					return true;
				}
				return AnyInteractor(InteractorGroup.HasCandidatePredicate);
			}
		}

		public override bool HasInteractable
		{
			get
			{
				if (_bestInteractor != null)
				{
					return _bestInteractor.HasInteractable;
				}
				return AnyInteractor(InteractorGroup.HasInteractablePredicate);
			}
		}

		public override bool HasSelectedInteractable
		{
			get
			{
				if (_bestInteractor != null)
				{
					return _bestInteractor.HasSelectedInteractable;
				}
				return false;
			}
		}

		public override object CandidateProperties
		{
			get
			{
				if (_bestInteractor != null && _bestInteractor.HasCandidate)
				{
					return _bestInteractor.CandidateProperties;
				}
				if (TryGetBestCandidateIndex(InteractorGroup.TruePredicate, out var bestCandidateIndex))
				{
					return Interactors[bestCandidateIndex].CandidateProperties;
				}
				return null;
			}
		}

		public override void Hover()
		{
			if (TryHover())
			{
				base.State = InteractorState.Hover;
			}
		}

		private bool TryHover(Action<IInteractor> whenHover = null)
		{
			bool result = false;
			int bestCandidateIndex;
			while (TryGetBestCandidateIndex(IsNormalAndShouldHoverPredicate, out bestCandidateIndex))
			{
				Interactors[bestCandidateIndex].Hover();
				whenHover?.Invoke(Interactors[bestCandidateIndex]);
				result = true;
			}
			return result;
		}

		public override void Unhover()
		{
			if (base.State == InteractorState.Hover)
			{
				int bestCandidateIndex;
				while (TryGetBestCandidateIndex(IsHoverAndShouldUnhoverPredicate, out bestCandidateIndex))
				{
					Interactors[bestCandidateIndex].Unhover();
				}
				if (!AnyInteractor(IsHover))
				{
					base.State = InteractorState.Normal;
				}
			}
		}

		public override void Select()
		{
			if (TryGetBestCandidateIndex(IsHoverAndShouldSelectPredicate, out var bestCandidateIndex))
			{
				_bestInteractor = Interactors[bestCandidateIndex];
				_bestInteractor.Select();
				_bestInteractor.WhenStateChanged += HandleBestInteractorStateChanged;
				DisableAllExcept(_bestInteractor);
			}
			base.State = InteractorState.Select;
		}

		public override void Unselect()
		{
			if (base.State != InteractorState.Select)
			{
				return;
			}
			if (_bestInteractor != null)
			{
				_bestInteractor.Unselect();
				if (_bestInteractor != null && _bestInteractor.State == InteractorState.Select)
				{
					return;
				}
			}
			base.State = InteractorState.Hover;
		}

		public override void Preprocess()
		{
			base.Preprocess();
			if (_bestInteractor == null && base.State == InteractorState.Select)
			{
				ProcessCandidate();
				base.Process();
				if (TryHover(delegate(IInteractor interactor)
				{
					interactor.Process();
				}))
				{
					if (ShouldSelect)
					{
						Select();
						base.State = InteractorState.Select;
					}
					else
					{
						base.State = InteractorState.Hover;
					}
					return;
				}
				if (base.State == InteractorState.Select)
				{
					base.State = InteractorState.Hover;
				}
				if (base.State == InteractorState.Hover)
				{
					base.State = InteractorState.Normal;
				}
			}
			else if (_bestInteractor != null && base.State == InteractorState.Select && _bestInteractor.State == InteractorState.Hover)
			{
				base.State = InteractorState.Hover;
			}
		}

		public override void Process()
		{
			base.Process();
			if (base.State == InteractorState.Hover && AnyInteractor(IsNormalAndShouldHoverPredicate) && TryHover(delegate(IInteractor interactor2)
			{
				interactor2.Process();
			}))
			{
				base.State = InteractorState.Hover;
			}
			if (base.State != InteractorState.Hover || !AnyInteractor(IsHoverAndShouldUnhoverPredicate))
			{
				return;
			}
			int bestCandidateIndex;
			while (TryGetBestCandidateIndex(IsHoverAndShouldUnhoverPredicate, out bestCandidateIndex))
			{
				IInteractor interactor = Interactors[bestCandidateIndex];
				interactor.Unhover();
				if (interactor.State != InteractorState.Hover)
				{
					interactor.Process();
				}
			}
		}

		public override void Enable()
		{
			if (_bestInteractor != null)
			{
				_bestInteractor.Enable();
			}
			else
			{
				base.Enable();
			}
		}

		public override void Disable()
		{
			UnsuscribeBestInteractor();
			base.Disable();
		}

		private void UnsuscribeBestInteractor()
		{
			if (_bestInteractor != null)
			{
				_bestInteractor.WhenStateChanged -= HandleBestInteractorStateChanged;
				_bestInteractor = null;
			}
		}

		private void HandleBestInteractorStateChanged(InteractorStateChangeArgs stateChange)
		{
			if (stateChange.PreviousState == InteractorState.Select && stateChange.NewState == InteractorState.Hover)
			{
				IInteractor bestInteractor = _bestInteractor;
				UnsuscribeBestInteractor();
				EnableAllExcept(bestInteractor);
			}
		}

		public void InjectAllInteractorGroupBestSelect(List<IInteractor> interactors)
		{
			InjectAllInteractorGroupBase(interactors);
		}
	}
	public abstract class CandidateComparer<T> : MonoBehaviour, ICandidateComparer where T : class
	{
		public int Compare(object a, object b)
		{
			T val = a as T;
			T val2 = b as T;
			if (val != null && val2 != null)
			{
				return Compare(val, val2);
			}
			return 0;
		}

		public abstract int Compare(T a, T b);
	}
	public class CandidatePositionComparer : CandidateComparer<ICandidatePosition>
	{
		[SerializeField]
		private Transform _compareOrigin;

		public override int Compare(ICandidatePosition a, ICandidatePosition b)
		{
			float sqrMagnitude = (a.CandidatePosition - _compareOrigin.position).sqrMagnitude;
			float sqrMagnitude2 = (b.CandidatePosition - _compareOrigin.position).sqrMagnitude;
			if (sqrMagnitude == sqrMagnitude2)
			{
				return 0;
			}
			if (!(sqrMagnitude < sqrMagnitude2))
			{
				return 1;
			}
			return -1;
		}
	}
	public class CollisionInteractionRegistry<TInteractor, TInteractable> : InteractableRegistry<TInteractor, TInteractable> where TInteractor : Interactor<TInteractor, TInteractable>, IRigidbodyRef where TInteractable : Interactable<TInteractor, TInteractable>, IRigidbodyRef
	{
		private Dictionary<Rigidbody, HashSet<TInteractable>> _rigidbodyCollisionMap;

		private Dictionary<TInteractable, InteractableTriggerBroadcaster> _broadcasters;

		private static readonly InteractableSet _empty;

		public CollisionInteractionRegistry()
		{
			_rigidbodyCollisionMap = new Dictionary<Rigidbody, HashSet<TInteractable>>();
			_broadcasters = new Dictionary<TInteractable, InteractableTriggerBroadcaster>();
		}

		public override void Register(TInteractable interactable)
		{
			base.Register(interactable);
			GameObject gameObject = interactable.Rigidbody.gameObject;
			if (!_broadcasters.TryGetValue(interactable, out var value))
			{
				value = gameObject.AddComponent<InteractableTriggerBroadcaster>();
				value.InjectAllInteractableTriggerBroadcaster(interactable);
				_broadcasters.Add(interactable, value);
				InteractableTriggerBroadcaster interactableTriggerBroadcaster = value;
				interactableTriggerBroadcaster.WhenTriggerEntered = (Action<IInteractable, Rigidbody>)Delegate.Combine(interactableTriggerBroadcaster.WhenTriggerEntered, new Action<IInteractable, Rigidbody>(HandleTriggerEntered));
				InteractableTriggerBroadcaster interactableTriggerBroadcaster2 = value;
				interactableTriggerBroadcaster2.WhenTriggerExited = (Action<IInteractable, Rigidbody>)Delegate.Combine(interactableTriggerBroadcaster2.WhenTriggerExited, new Action<IInteractable, Rigidbody>(HandleTriggerExited));
			}
		}

		public override void Unregister(TInteractable interactable)
		{
			base.Unregister(interactable);
			if (_broadcasters.TryGetValue(interactable, out var value))
			{
				_broadcasters.Remove(interactable);
				if (value != null)
				{
					value.enabled = false;
					InteractableTriggerBroadcaster interactableTriggerBroadcaster = value;
					interactableTriggerBroadcaster.WhenTriggerEntered = (Action<IInteractable, Rigidbody>)Delegate.Remove(interactableTriggerBroadcaster.WhenTriggerEntered, new Action<IInteractable, Rigidbody>(HandleTriggerEntered));
					InteractableTriggerBroadcaster interactableTriggerBroadcaster2 = value;
					interactableTriggerBroadcaster2.WhenTriggerExited = (Action<IInteractable, Rigidbody>)Delegate.Remove(interactableTriggerBroadcaster2.WhenTriggerExited, new Action<IInteractable, Rigidbody>(HandleTriggerExited));
					UnityEngine.Object.Destroy(value);
				}
			}
		}

		private void HandleTriggerEntered(IInteractable interactable, Rigidbody rigidbody)
		{
			TInteractable item = interactable as TInteractable;
			if (!_rigidbodyCollisionMap.ContainsKey(rigidbody))
			{
				_rigidbodyCollisionMap.Add(rigidbody, new HashSet<TInteractable>());
			}
			_rigidbodyCollisionMap[rigidbody].Add(item);
		}

		private void HandleTriggerExited(IInteractable interactable, Rigidbody rigidbody)
		{
			TInteractable item = interactable as TInteractable;
			HashSet<TInteractable> hashSet = _rigidbodyCollisionMap[rigidbody];
			hashSet.Remove(item);
			if (hashSet.Count == 0)
			{
				_rigidbodyCollisionMap.Remove(rigidbody);
			}
		}

		public override InteractableSet List(TInteractor interactor)
		{
			if (_rigidbodyCollisionMap.TryGetValue(interactor.Rigidbody, out var value))
			{
				return List(interactor, value);
			}
			return _empty;
		}
	}
