				for (int i = 0; i < Interactables.Count; i++)
				{
					Interactables[i].MaxInteractors = ((_limits[i].MaxInteractors == -1) ? num : Mathf.Max(0, _limits[i].MaxInteractors - _interactors)) + Interactables[i].InteractorViews.Count();
