				for (int i = 0; i < Interactables.Count; i++)
				{
					Interactables[i].MaxSelectingInteractors = ((_limits[i].MaxSelectingInteractors == -1) ? num : Mathf.Max(0, _limits[i].MaxSelectingInteractors - _selectInteractors)) + Interactables[i].SelectingInteractorViews.Count();
