			CollectionPool<List<int>, int>.Release(_primaryToSecondaryMap[primaryInteractor.Identifier]);
			_primaryToSecondaryMap.Remove(primaryInteractor.Identifier);
			if (_primaryToSecondaryMap.Count == 0)
