	public class OneGrabSphereTransformer : MonoBehaviour, ITransformer
	{
		[SerializeField]
		private Transform _sphereCenter;

		[SerializeField]
		[Range(-90f, 90f)]
		private float _minAngle = -90f;

		[SerializeField]
		[Range(-90f, 90f)]
