		{
			Interactor = interactor;
			_interactor = interactor as UnityEngine.Object;
		}

		public void InjectSkinnedMeshRenderer(SkinnedMeshRenderer skinnedMeshRenderer)
		{
			_skinnedMeshRenderer = skinnedMeshRenderer;
		}
