			_minThresholds.Enabled = false;
			_dragThresholds.Enabled = false;
			_positionPinning.Enabled = true;
			_recoilAssist.Enabled = true;
			_recoilAssist.UseVelocityExpansion = true;
			_recoilAssist.UseDynamicDecay = true;
