		private void HandlePointerEventRaised(PointerEvent evt)
		{
			switch (evt.Type)
			{
			case PointerEventType.Hover:
				_hover = true;
				UpdateMaterialColor();
				break;
			case PointerEventType.Select:
				_select = true;
