			case PointerEventType.Unhover:
				_hover = false;
				UpdateMaterialColor();
				break;
			case PointerEventType.Move:
				break;
			}
		}

		private void UpdateMaterialColor()
		{
			_material.color = (_select ? _selectColor : (_hover ? _hoverColor : _normalColor));
		}

