	public class HandConfidenceVisual : MonoBehaviour
	{
		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _hand;

		[SerializeField]
		private MaterialPropertyBlockEditor _handMaterialPropertyBlockEditor;

		[SerializeField]
		private float _speed = 5f;

		private readonly int _handConfidenceId = Shader.PropertyToID("_JointsGlow");

		private float[] _jointsConfidence = new float[18];

		protected bool _started;

		private float _lastTime;

		private IHand Hand { get; set; }

		public float Speed
		{
			get
			{
				return _speed;
			}
			set
			{
				_speed = value;
			}
		}

		private void Awake()
		{
			Hand = _hand as IHand;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			_lastTime = Time.time;
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated += UpdateVisual;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated -= UpdateVisual;
			}
		}

		private void UpdateVisual()
		{
			float changeRate = (Time.time - _lastTime) * Speed;
			_lastTime = Time.time;
			float b = (Hand.IsHighConfidence ? 0f : 1f);
			_jointsConfidence[0] = Mathf.Lerp(_jointsConfidence[0], b, changeRate);
			FillConfidence(Oculus.Interaction.Input.HandFinger.Thumb, 1, 4);
			FillConfidence(Oculus.Interaction.Input.HandFinger.Index, 5, 3);
			FillConfidence(Oculus.Interaction.Input.HandFinger.Middle, 8, 3);
			FillConfidence(Oculus.Interaction.Input.HandFinger.Ring, 11, 3);
			FillConfidence(Oculus.Interaction.Input.HandFinger.Pinky, 14, 4);
			_handMaterialPropertyBlockEditor.MaterialPropertyBlock.SetFloatArray(_handConfidenceId, _jointsConfidence);
			_handMaterialPropertyBlockEditor.UpdateMaterialPropertyBlock();
			void FillConfidence(Oculus.Interaction.Input.HandFinger finger, int offset, int lenght)
			{
				int num = ((!Hand.GetFingerIsHighConfidence(finger)) ? 1 : 0);
				for (int i = offset; i < offset + lenght; i++)
				{
					_jointsConfidence[i] = Mathf.Lerp(_jointsConfidence[i], num, changeRate);
				}
			}
		}

		public void InjectAllHandConfidenceVisual(IHand hand, MaterialPropertyBlockEditor handMaterialPropertyBlockEditor)
		{
			InjectHand(hand);
			InjectHandMaterialPropertyBlockEditor(handMaterialPropertyBlockEditor);
		}

		public void InjectHand(IHand hand)
		{
			_hand = hand as UnityEngine.Object;
			Hand = hand;
		}

		public void InjectHandMaterialPropertyBlockEditor(MaterialPropertyBlockEditor handMaterialPropertyBlockEditor)
		{
			_handMaterialPropertyBlockEditor = handMaterialPropertyBlockEditor;
		}
	}
	public class HandDebugGizmos : SkeletonDebugGizmos, IHandVisual
	{
		public enum CoordSpace
		{
			World,
			Local
		}

		[Tooltip("The IHand that will drive the visuals.")]
		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _hand;

		[Tooltip("The coordinate space in which to draw the skeleton. World space draws the skeleton at the world Body location. Local draws the skeleton relative to this transform's position, and can be placed, scaled, or mirrored as desired.")]
		[SerializeField]
		private CoordSpace _space;

		private bool _isVisible;

		protected bool _started;

		public IHand Hand { get; private set; }

		public CoordSpace Space
		{
			get
			{
				return _space;
			}
			set
			{
				_space = value;
			}
		}

		public bool ForceOffVisibility { get; set; }

		public bool IsVisible => _isVisible;

		public event Action WhenHandVisualUpdated = delegate
		{
		};

		protected virtual void Awake()
		{
			Hand = _hand as IHand;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated += HandleHandUpdated;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated -= HandleHandUpdated;
			}
		}

		public Pose GetJointPose(Oculus.Interaction.Input.HandJointId jointId, Space space)
		{
			switch (space)
			{
			case UnityEngine.Space.Self:
			{
				if (Hand.GetJointPoseLocal(jointId, out var pose2))
				{
					return pose2;
				}
				break;
			}
			case UnityEngine.Space.World:
			{
				if (Hand.GetJointPose(jointId, out var pose))
				{
					return pose;
				}
				break;
			}
			}
			return default(Pose);
		}

		private void HandleHandUpdated()
		{
			_isVisible = Hand.IsTrackedDataValid && !ForceOffVisibility;
			if (_isVisible)
			{
				for (Oculus.Interaction.Input.HandJointId handJointId = Oculus.Interaction.Input.HandJointId.HandStart; handJointId < Oculus.Interaction.Input.HandJointId.HandEnd; handJointId++)
				{
					Draw((int)handJointId, base.Visibility);
				}
			}
			this.WhenHandVisualUpdated();
		}

		protected override bool TryGetParentJointId(int jointId, out int parent)
		{
			if (jointId >= Oculus.Interaction.Input.HandJointUtils.JointParentList.Length)
			{
				parent = -1;
				return false;
			}
			parent = (int)Oculus.Interaction.Input.HandJointUtils.JointParentList[jointId];
			return parent > -1;
		}

		protected override bool TryGetJointPose(int jointId, out Pose pose)
		{
			CoordSpace space = _space;
			bool result;
			if (space == CoordSpace.World || space != CoordSpace.Local)
			{
				result = Hand.GetJointPose((Oculus.Interaction.Input.HandJointId)jointId, out pose);
			}
			else
			{
				result = Hand.GetJointPoseFromWrist((Oculus.Interaction.Input.HandJointId)jointId, out pose);
				pose.position = base.transform.TransformPoint(pose.position);
				pose.rotation = base.transform.rotation * pose.rotation;
			}
			return result;
		}

		public void InjectAllHandDebugGizmos(IHand hand)
		{
			InjectHand(hand);
		}

		public void InjectHand(IHand hand)
		{
			_hand = hand as UnityEngine.Object;
			Hand = hand;
		}
	}
