	public class ObjectPull : IMovement
	{
		private float _speed = 1f;

		private float _deadZone;

		private Pose _current = Pose.identity;

		private Pose _grabberStartPose;

		private Pose _grabbableStartPose;

		private Pose _target;

		private Plane _pullingPlane;

		private Vector3 _translationDelta = Vector3.zero;

		private float _lastTime;

		private float _originalDistance;

		private bool _reachedGrabber;

		public Pose Pose => _current;

		public bool Stopped => _reachedGrabber;

		public ObjectPull(float speed, float deadZone)
		{
			_speed = speed;
			_deadZone = deadZone;
		}

		public void MoveTo(Pose target)
		{
			_target = (_grabberStartPose = target);
			_current = _grabbableStartPose;
			_lastTime = Time.time;
			_reachedGrabber = false;
			Vector3 vector = _grabbableStartPose.position - _grabberStartPose.position;
			_originalDistance = vector.magnitude;
			_pullingPlane = new Plane(vector.normalized, _grabberStartPose.position);
		}

		public void UpdateTarget(Pose target)
		{
			_target = target;
		}

		public void StopAndSetPose(Pose source)
		{
			_grabbableStartPose = source;
		}

		public void Tick()
		{
			if (_reachedGrabber)
			{
				_current = _target;
				return;
			}
			float num = Time.time - _lastTime;
			_lastTime = Time.time;
			float distanceToPoint = _pullingPlane.GetDistanceToPoint(_target.position);
			if (!(Mathf.Abs(distanceToPoint) < _deadZone))
			{
				Vector3 normalized = (_current.position - _target.position).normalized;
				_translationDelta = normalized * distanceToPoint * _speed * num;
				if (Vector3.Distance(_current.position, _target.position) < _translationDelta.magnitude)
				{
					_reachedGrabber = true;
					_current = _target;
					return;
				}
				_current.position += _translationDelta;
				float num2 = Vector3.Distance(_current.position, _target.position);
				float t = 1f - Mathf.Clamp01(num2 / _originalDistance);
				_current.rotation = Quaternion.Slerp(_grabbableStartPose.rotation, _target.rotation, t);
			}
		}
	}
	[Serializable]
	public struct PoseTravelData
	{
		[Tooltip("When attracting the object, indicates the rate (in m/s, or seconds if UseFixedTravelTime is enabled) for the object to realign with the hand after a grab.")]
		[SerializeField]
		private float _travelSpeed;

		[Tooltip("Changes the units of the TravelSpeed, disabled means m/s while enabled is fixed seconds")]
		[SerializeField]
		private bool _useFixedTravelTime;

		[Tooltip("Animation to use in conjunction with TravelSpeed to define the traveling motion.")]
		[SerializeField]
		private AnimationCurve _travelCurve;

		private const float DEGREES_TO_PERCEIVED_METERS = 0.0013888889f;

		public static PoseTravelData DEFAULT => new PoseTravelData
		{
			_travelSpeed = 1f,
			_useFixedTravelTime = false,
			_travelCurve = AnimationCurve.EaseInOut(0f, 0f, 1f, 1f)
		};

		public static PoseTravelData FAST => new PoseTravelData
		{
			_travelSpeed = 0.1f,
			_useFixedTravelTime = true,
			_travelCurve = AnimationCurve.EaseInOut(0f, 0f, 1f, 1f)
		};

		public Tween CreateTween(in Pose from, in Pose to)
		{
			float num = _travelSpeed;
			if (!_useFixedTravelTime && _travelSpeed != 0f)
			{
				num = PerceivedDistance(in from, in to) / _travelSpeed;
			}
			Tween tween = new Tween(from, num, num * 0.5f, _travelCurve);
			tween.MoveTo(to);
			return tween;
		}

		private static float PerceivedDistance(in Pose from, in Pose to)
		{
			float magnitude = PoseUtils.Delta(in from, in to).position.magnitude;
			float b = 0.0013888889f * Mathf.Max(Mathf.Max(Vector3.Angle(from.forward, to.forward), Vector3.Angle(from.up, to.up), Vector3.Angle(from.right, to.right)));
			return Mathf.Max(magnitude, b);
		}
	}
	[ExecuteAlways]
	public class DebugGizmos : MonoBehaviour
	{
		private List<Vector4> _points = new List<Vector4>();

		private List<Color> _colors = new List<Color>();

		private int _index;

		private bool _addedSegmentSinceLastUpdate;

		protected static DebugGizmos _root = null;

		private PolylineRenderer _polylineRenderer;

		private static bool _renderSinglePass = true;

		public static Color Color = Color.black;

		public static float LineWidth = 0.1f;

		private static readonly IReadOnlyList<Vector3> CUBE_POINTS = new List<Vector3>
		{
			new Vector3(-0.5f, -0.5f, -0.5f),
			new Vector3(0.5f, -0.5f, -0.5f),
			new Vector3(-0.5f, 0.5f, -0.5f),
			new Vector3(-0.5f, -0.5f, 0.5f),
			new Vector3(0.5f, 0.5f, -0.5f),
			new Vector3(0.5f, -0.5f, 0.5f),
			new Vector3(-0.5f, 0.5f, 0.5f),
			new Vector3(0.5f, 0.5f, 0.5f)
		};

		private static readonly IReadOnlyList<int> CUBE_SEGMENTS = new List<int>
		{
			0, 1, 1, 5, 3, 5, 0, 3, 0, 2,
			1, 4, 3, 6, 5, 7, 2, 4, 4, 7,
			7, 6, 6, 2
		};

		protected static DebugGizmos Root
		{
			get
			{
				if (_root == null)
				{
					GameObject gameObject = GameObject.Find("Polyline Gizmos");
					if (gameObject != null)
					{
						DebugGizmos component = gameObject.GetComponent<DebugGizmos>();
						if (component != null)
						{
							_root = component;
						}
					}
				}
				if (_root == null)
				{
					_root = new GameObject("Polyline Gizmos").AddComponent<DebugGizmos>();
				}
				return _root;
			}
		}

		private PolylineRenderer Renderer
		{
			get
			{
				if (_polylineRenderer == null)
				{
					_polylineRenderer = new PolylineRenderer(null, _renderSinglePass);
				}
				return _polylineRenderer;
			}
		}

		public static bool RenderSinglePass
		{
			get
			{
				return _renderSinglePass;
			}
			set
			{
				if (_renderSinglePass != value)
				{
					_renderSinglePass = value;
					if (Root != null)
					{
						UnityEngine.Object.Destroy(Root);
					}
				}
			}
		}

		protected virtual void OnEnable()
		{
			if (!(_root == null) && _root != this)
			{
				UnityEngine.Object.Destroy(this);
			}
		}

		protected virtual void OnDisable()
		{
			if (_polylineRenderer != null)
			{
				_polylineRenderer.Cleanup();
				_polylineRenderer = null;
			}
			_ = Application.isPlaying;
		}

		protected void ClearSegments()
		{
			_index = 0;
		}

		protected void RenderSegments()
		{
			Renderer.SetLines(_points, _colors, _index);
			Renderer.RenderLines();
		}

		protected virtual void LateUpdate()
		{
			if (Application.isPlaying)
			{
				RenderSegments();
				ClearSegments();
			}
		}

		protected void AddSegment(Vector3 p0, Vector3 p1, float width, Color color0, Color color1)
		{
			if (!_addedSegmentSinceLastUpdate)
			{
				ClearSegments();
				_addedSegmentSinceLastUpdate = true;
			}
			while (_index + 2 > _points.Count)
			{
				_points.Add(default(Vector4));
				_colors.Add(default(Color));
			}
			_points[_index] = new Vector4(p0.x, p0.y, p0.z, width);
			_points[_index + 1] = new Vector4(p1.x, p1.y, p1.z, width);
			_colors[_index] = color0;
			_colors[_index + 1] = color1;
			_index += 2;
		}

		public static void DrawPoint(Vector3 p0, Transform t = null)
		{
			if (t != null)
			{
				p0 = t.TransformPoint(p0);
			}
			Root.AddSegment(p0, p0, LineWidth, Color, Color);
		}

		public static void DrawLine(Vector3 p0, Vector3 p1, Transform t = null)
		{
			if (t != null)
			{
				p0 = t.TransformPoint(p0);
				p1 = t.TransformPoint(p1);
			}
			Root.AddSegment(p0, p1, LineWidth, Color, Color);
		}

		public static void DrawQuad(Vector3 center, float width, float height, Transform t = null)
		{
			Vector3 vector = new Vector3((0f - width) / 2f, height / 2f) + center;
			Vector3 vector2 = new Vector3(width / 2f, height / 2f) + center;
			Vector3 vector3 = new Vector3(width / 2f, (0f - height) / 2f) + center;
			Vector3 vector4 = new Vector3((0f - width) / 2f, (0f - height) / 2f) + center;
			DrawLine(vector, vector2, t);
			DrawLine(vector2, vector3, t);
			DrawLine(vector3, vector4, t);
			DrawLine(vector4, vector, t);
		}

		public static void DrawCurvedQuad(Vector3 center, float width, float height, float radius, Transform t = null, int divisions = 20)
		{
			Vector3[] array = new Vector3[divisions + 1];
			float num = width / radius;
			float num2 = num / (float)divisions;
			for (int i = 0; i <= divisions; i++)
			{
				float f = (float)i * num2 - num / 2f;
				Vector3 vector = new Vector3(Mathf.Sin(f), 0f, Mathf.Cos(f) - 1f) * radius;
				array[i] = vector + center;
			}
			Vector3 vector2 = new Vector3(0f, height / 2f, 0f);
			for (int j = 0; j < divisions; j++)
			{
				Vector3 vector3 = array[j];
				Vector3 vector4 = array[j + 1];
				DrawLine(vector3 + vector2, vector4 + vector2, t);
				DrawLine(vector3 - vector2, vector4 - vector2, t);
			}
			DrawLine(array[0] + vector2, array[0] - vector2, t);
			DrawLine(array[divisions] + vector2, array[divisions] - vector2, t);
		}

		public static void DrawWireCube(Vector3 center, float size, Transform t = null)
		{
			for (int i = 0; i < CUBE_SEGMENTS.Count; i += 2)
			{
				Vector3 p = CUBE_POINTS[CUBE_SEGMENTS[i]] * size + center;
				Vector3 p2 = CUBE_POINTS[CUBE_SEGMENTS[i + 1]] * size + center;
				DrawLine(p, p2, t);
			}
		}

		public static void DrawAxis(Vector3 position, Quaternion rotation, float size = 1f)
		{
			Color color = Color;
			Color = Color.red;
			DrawLine(position, position + rotation * Vector3.right * size);
			Color = Color.green;
			DrawLine(position, position + rotation * Vector3.up * size);
			Color = Color.blue;
			DrawLine(position, position + rotation * Vector3.forward * size);
			Color = color;
		}

		public static void DrawAxis(Pose pose, float size = 1f)
		{
			DrawAxis(pose.position, pose.rotation, size);
		}

		public static void DrawAxis(Transform t, float size = 1f)
		{
			DrawAxis(t.GetPose(), size);
		}
	}
	public class PolylineRenderer
	{
		private Vector4[] _positions;

		private bool _positionsNeedUpdate;

		private Color[] _colors;

		private bool _colorsNeedUpdate;

		private Bounds _bounds;

		private Mesh _baseMesh;

		private Material _material;

		private bool _renderSinglePass;

		private ComputeBuffer _positionBuffer;

		private ComputeBuffer _colorBuffer;

		private ComputeBuffer _argsBuffer;

		private uint[] _argsData;

		private int _positionBufferShaderID = Shader.PropertyToID("_PositionBuffer");

		private int _colorBufferShaderID = Shader.PropertyToID("_ColorBuffer");

		private int _localToWorldShaderID = Shader.PropertyToID("_LocalToWorld");

		private int _scaleShaderID = Shader.PropertyToID("_Scale");

		private int _maxLineCount = 1;

		private Matrix4x4 _matrix = Matrix4x4.identity;

		private float _lineScaleFactor = 1f;

		private int Copies
		{
			get
			{
				if (!_renderSinglePass)
				{
					return 1;
				}
				return 2;
			}
		}

		private int BufferSize => _maxLineCount * 2 * Copies;

		public float LineScaleFactor
		{
			get
			{
				return _lineScaleFactor;
			}
			set
			{
				_lineScaleFactor = value;
			}
		}

		public PolylineRenderer(Material material = null, bool renderSinglePass = true)
		{
			_renderSinglePass = renderSinglePass;
			if (material == null)
			{
				material = new Material(Shader.Find("Custom/PolylineUnlit"));
			}
			_material = new Material(material);
			GameObject gameObject = GameObject.CreatePrimitive(PrimitiveType.Cube);
			_baseMesh = gameObject.GetComponent<MeshFilter>().sharedMesh;
			UnityEngine.Object.DestroyImmediate(gameObject);
			_positions = new Vector4[BufferSize];
			_colors = new Color[BufferSize];
			_positionBuffer = new ComputeBuffer(BufferSize, 16);
			_positionBuffer.SetData(_positions);
			_colorBuffer = new ComputeBuffer(BufferSize, 16);
			_colorBuffer.SetData(_colors);
			_material.SetBuffer(_positionBufferShaderID, _positionBuffer);
			_material.SetBuffer(_colorBufferShaderID, _colorBuffer);
			_argsData = new uint[5];
			_argsData[0] = _baseMesh.GetIndexCount(0);
			_argsData[1] = (uint)(_maxLineCount * Copies);
			_argsBuffer = new ComputeBuffer(1, _argsData.Length * 4, ComputeBufferType.DrawIndirect);
			_argsBuffer.SetData(_argsData);
			_positionsNeedUpdate = true;
			_colorsNeedUpdate = true;
		}

		public void Cleanup()
		{
			_positionBuffer.Release();
			_colorBuffer.Release();
			_argsBuffer.Release();
			if (Application.isPlaying)
			{
				UnityEngine.Object.Destroy(_material);
			}
			else
			{
				UnityEngine.Object.DestroyImmediate(_material);
			}
		}

		public void SetLines(List<Vector4> positions, Color color)
		{
			SetPositions(positions.Count, positions);
			SetDrawCount(positions.Count / 2);
			SetColor(positions.Count, color);
		}

		public void SetLines(List<Vector4> positions, List<Color> colors, int maxCount = -1)
		{
			int num = ((maxCount < 0) ? positions.Count : maxCount);
			SetPositions(num, positions);
			SetDrawCount(num / 2);
			SetColors(num, colors);
		}

		private void SetPositions(int count, List<Vector4> positions)
		{
			if (count * Copies > _positions.Length)
			{
				_maxLineCount = count / 2;
				_positions = new Vector4[BufferSize];
				_positionBuffer.Release();
				_positionBuffer = new ComputeBuffer(BufferSize, 16);
				_positionBuffer.SetData(_positions);
			}
			_bounds = default(Bounds);
			Vector3 min = Vector3.zero;
			Vector3 max = Vector3.zero;
			for (int i = 0; i < count; i += 2)
			{
				for (int j = 0; j < 2; j++)
				{
					Vector4 vector = positions[i + j];
					for (int k = 0; k < Copies; k++)
					{
						_positions[(i + k) * Copies + j] = vector;
					}
					Vector3 vector2 = vector.w * Vector3.one;
					Vector3 vector3 = vector;
					Vector3 vector4 = vector3 - vector2 / 2f;
					Vector3 vector5 = vector3 + vector2 / 2f;
					if (i == 0 && j == 0)
					{
						min = vector4;
						max = vector5;
						continue;
					}
					min.x = Mathf.Min(vector4.x, min.x);
					min.y = Mathf.Min(vector4.y, min.y);
					min.z = Mathf.Min(vector4.z, min.z);
					max.x = Mathf.Max(vector5.x, max.x);
					max.y = Mathf.Max(vector5.y, max.y);
					max.z = Mathf.Max(vector5.z, max.z);
				}
			}
			_bounds.SetMinMax(min, max);
			_positionsNeedUpdate = true;
		}

		private void SetColors(int count, List<Color> colors)
		{
			PrepareColorBuffer(count);
			for (int i = 0; i < count; i += 2)
			{
				for (int j = 0; j < 2; j++)
				{
					for (int k = 0; k < Copies; k++)
					{
						_colors[(i + k) * Copies + j] = colors[i + j];
					}
				}
			}
			_colorsNeedUpdate = true;
		}

		private void SetColor(int count, Color color)
		{
			PrepareColorBuffer(count);
			for (int i = 0; i < count; i += 2)
			{
				for (int j = 0; j < 2; j++)
				{
					for (int k = 0; k < Copies; k++)
					{
						_colors[(i + k) * Copies + j] = color;
					}
				}
			}
			_colorsNeedUpdate = true;
		}

		private void SetDrawCount(int c)
		{
			_argsData[1] = (uint)(c * Copies);
			_argsBuffer.SetData(_argsData);
		}

		private void PrepareColorBuffer(int count)
		{
			if (count * Copies > _colors.Length)
			{
				_maxLineCount = count / 2;
				_colors = new Color[BufferSize];
				_colorBuffer.Release();
				_colorBuffer = new ComputeBuffer(BufferSize, 16);
				_colorBuffer.SetData(_colors);
			}
		}

		public void RenderLines()
		{
			if (_positionsNeedUpdate)
			{
				_positionBuffer.SetData(_positions);
				_material.SetBuffer(_positionBufferShaderID, _positionBuffer);
				_positionsNeedUpdate = false;
			}
			if (_colorsNeedUpdate)
			{
				_colorBuffer.SetData(_colors);
				_material.SetBuffer(_colorBufferShaderID, _colorBuffer);
				_colorsNeedUpdate = false;
			}
			_material.SetFloat(_scaleShaderID, _lineScaleFactor);
			_material.SetMatrix(_localToWorldShaderID, _matrix);
			Graphics.DrawMeshInstancedIndirect(bounds: new Bounds(_matrix.MultiplyPoint(_bounds.center), _matrix.MultiplyVector(_bounds.size)), mesh: _baseMesh, submeshIndex: 0, material: _material, bufferWithArgs: _argsBuffer);
		}

		public void SetTransform(Transform transform)
		{
			_matrix = transform.localToWorldMatrix;
		}
	}
