		private void HandleHandUpdated()
		{
			Pose pose = Pose.identity;
			float num = 0f;
			foreach (WeightedJoint weightedJoint in WeightedJoints)
			{
				if (!Hand.GetJointPose(weightedJoint.handJointId, out var pose2))
				{
					return;
