			Action<PointerEvent> value = _pointerCanvasActionMap[pointerCanvas];
			_pointerCanvasActionMap.Remove(pointerCanvas);
			pointerCanvas.WhenPointerEventRaised -= value;
			foreach (int item in new List<int>(_pointerMap.Keys))
			{
