				if (!(pointerImpl.Canvas != pointerCanvas.Canvas))
				{
					ClearPointerSelection(pointerImpl.PointerEventData);
					pointerImpl.MarkForDeletion();
					_pointersForDeletion.Add(pointerImpl);
					_pointerMap.Remove(item);
