				break;
			case PointerEventType.Select:
				if (_pointerMap.TryGetValue(evt.Identifier, out value))
				{
					value.SetPosition(evt.Pose.position);
					value.Press();
				}
				break;
			case PointerEventType.Unselect:
				if (_pointerMap.TryGetValue(evt.Identifier, out value))
				{
