		public const string FeatureCurlShortHelpText = "Convex angle (in degrees) representing the top 2 joints of the fingers. Angle increases as finger curl becomes closed.";

		public const string FeatureCurlDetailHelpText = "Calculated from the average of the convex angles formed by the 2 bones connected to Joint 2, and 2 bones connected to Joint 3.\nValues above 180 Positive show a curled state, while values below 180 represent hyper-extension.";

		public const string FeatureFlexionShortHelpText = "Convex angle (in degrees) of joint 1 of the finger. Angle increases as finger flexion becomes closed.";

		public const string FeatureFlexionDetailHelpText = "Calculated from the angle between the bones connected to finger Joint 1 around the Z axis of the joint.\nFor fingers, joint 1 is commonly known as the 'Knuckle'; but for the thumb it is alongside the wrist.\nValues above 180 Positive show a curled state, while values below 180 represent hyper-extension.upwards from the palm.";

		public const string FeatureAbductionShortHelpText = "Angle (in degrees) between the given finger, and the next finger towards the pinkie.";

		public const string FeatureAbductionDetailHelpText = "Zero value implies that the two fingers are parallel.\nPositive angles indicate that the fingertips are spread apart.\nSmall negative angles are possible, and indicate that the finger is pressed up against the next finger.";

		public const string FeatureOppositionShortHelpText = "Distance between the tip of the given finger and the tip of the thumb.\nCalculated tracking space, with a 1.0 hand scale.";

		public const string FeatureOppositionDetailHelpText = "Positive values indicate that the fingertips are spread apart.\nNegative values are not possible.";

		public const string FeatureStateThresholdMidpointHelpText = "The angle at which a state will transition from A > B (or B > A)";

		public const string FeatureStateThresholdWidthHelpText = "How far the angle must exceed the midpoint until the transition can occur. This is to prevent rapid flickering at transition edges.";

		public static IReadOnlyDictionary<FingerFeature, FeatureDescription> FeatureDescriptions { get; } = new Dictionary<FingerFeature, FeatureDescription>
		{
			[FingerFeature.Curl] = new FeatureDescription("Convex angle (in degrees) representing the top 2 joints of the fingers. Angle increases as finger curl becomes closed.", "Calculated from the average of the convex angles formed by the 2 bones connected to Joint 2, and 2 bones connected to Joint 3.\nValues above 180 Positive show a curled state, while values below 180 represent hyper-extension.", 180f, 260f, CurlFeatureStates),
			[FingerFeature.Flexion] = new FeatureDescription("Convex angle (in degrees) of joint 1 of the finger. Angle increases as finger flexion becomes closed.", "Calculated from the angle between the bones connected to finger Joint 1 around the Z axis of the joint.\nFor fingers, joint 1 is commonly known as the 'Knuckle'; but for the thumb it is alongside the wrist.\nValues above 180 Positive show a curled state, while values below 180 represent hyper-extension.upwards from the palm.", 180f, 260f, FlexionFeatureStates),
			[FingerFeature.Abduction] = new FeatureDescription("Angle (in degrees) between the given finger, and the next finger towards the pinkie.", "Zero value implies that the two fingers are parallel.\nPositive angles indicate that the fingertips are spread apart.\nSmall negative angles are possible, and indicate that the finger is pressed up against the next finger.", 8f, 90f, AbductionFeatureStates),
			[FingerFeature.Opposition] = new FeatureDescription("Distance between the tip of the given finger and the tip of the thumb.\nCalculated tracking space, with a 1.0 hand scale.", "Positive values indicate that the fingertips are spread apart.\nNegative values are not possible.", 0f, 0.2f, OppositionFeatureStates)
		};
	}
	internal class FingerFeatureStateDictionary
	{
		private struct HandFingerState
		{
			public FeatureStateProvider<FingerFeature, string> StateProvider;
		}

		private readonly HandFingerState[] _fingerState = new HandFingerState[5];

		public void InitializeFinger(Oculus.Interaction.Input.HandFinger finger, FeatureStateProvider<FingerFeature, string> stateProvider)
		{
			_fingerState[(int)finger] = new HandFingerState
			{
				StateProvider = stateProvider
			};
		}

		public FeatureStateProvider<FingerFeature, string> GetStateProvider(Oculus.Interaction.Input.HandFinger finger)
		{
			return _fingerState[(int)finger].StateProvider;
		}
	}
	public interface IFingerFeatureStateProvider
	{
		bool GetCurrentState(Oculus.Interaction.Input.HandFinger finger, FingerFeature fingerFeature, out string currentState);

		bool IsStateActive(Oculus.Interaction.Input.HandFinger finger, FingerFeature feature, FeatureStateActiveMode mode, string stateId);

		float? GetFeatureValue(Oculus.Interaction.Input.HandFinger finger, FingerFeature fingerFeature);
	}
	public class FingerFeatureStateProvider : MonoBehaviour, IFingerFeatureStateProvider, ITimeConsumer
	{
		[Serializable]
		public struct FingerStateThresholds
		{
			[Tooltip("Which finger the state thresholds apply to.")]
			public Oculus.Interaction.Input.HandFinger Finger;

			[Tooltip("State threshold configuration")]
			public FingerFeatureStateThresholds StateThresholds;
		}

		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		[Tooltip("Data source used to retrieve finger bone rotations.")]
		private UnityEngine.Object _hand;

		[SerializeField]
		[Tooltip("Contains state transition threasholds for each finger. Must contain 5 entries (one for each finger). Each finger must exist in the list exactly once.")]
		private List<FingerStateThresholds> _fingerStateThresholds;

		[Header("Advanced Settings")]
		[SerializeField]
		[Tooltip("If true, disables proactive evaluation of any FingerFeature that has been queried at least once. This will force lazy-evaluation of state within calls to IsStateActive, which means you must call IsStateActive for each feature manually each frame to avoid missing transitions between states.")]
		private bool _disableProactiveEvaluation;

		protected bool _started;

		private FingerFeatureStateDictionary _state;

		private Func<float> _timeProvider = () => Time.time;

		private FingerShapes _fingerShapes = DefaultFingerShapes;

		private Oculus.Interaction.Input.ReadOnlyHandJointPoses _handJointPoses;

		public IHand Hand { get; private set; }

		public static FingerShapes DefaultFingerShapes { get; } = new FingerShapes();

		public void SetTimeProvider(Func<float> timeProvider)
		{
			_timeProvider = timeProvider;
		}

		protected virtual void Awake()
		{
			Hand = _hand as IHand;
			_state = new FingerFeatureStateDictionary();
			_handJointPoses = Oculus.Interaction.Input.ReadOnlyHandJointPoses.Empty;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated += HandDataAvailable;
				ReadStateThresholds();
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated -= HandDataAvailable;
				_handJointPoses = Oculus.Interaction.Input.ReadOnlyHandJointPoses.Empty;
			}
		}

		private void ReadStateThresholds()
		{
			Oculus.Interaction.Input.HandFingerFlags handFingerFlags = Oculus.Interaction.Input.HandFingerFlags.None;
			foreach (FingerStateThresholds fingerStateThreshold in _fingerStateThresholds)
			{
				handFingerFlags |= Oculus.Interaction.Input.HandFingerUtils.ToFlags(fingerStateThreshold.Finger);
				Oculus.Interaction.Input.HandFinger finger = fingerStateThreshold.Finger;
				FeatureStateProvider<FingerFeature, string> featureStateProvider = _state.GetStateProvider(finger);
				if (featureStateProvider == null)
				{
					Func<float> timeProvider = () => _timeProvider();
					featureStateProvider = new FeatureStateProvider<FingerFeature, string>((FingerFeature feature) => GetFeatureValue(finger, feature), (FingerFeature feature) => (int)feature, timeProvider);
					_state.InitializeFinger(fingerStateThreshold.Finger, featureStateProvider);
				}
				featureStateProvider.InitializeThresholds(fingerStateThreshold.StateThresholds);
			}
		}

		private void HandDataAvailable()
		{
			int currentDataVersion = Hand.CurrentDataVersion;
			if (!Hand.GetJointPosesFromWrist(out _handJointPoses))
			{
				return;
			}
			if (!_disableProactiveEvaluation)
			{
				for (int i = 0; i < 5; i++)
				{
					FeatureStateProvider<FingerFeature, string> stateProvider = _state.GetStateProvider((Oculus.Interaction.Input.HandFinger)i);
					stateProvider.LastUpdatedFrameId = currentDataVersion;
					stateProvider.ReadTouchedFeatureStates();
				}
			}
			else
			{
				for (int j = 0; j < 5; j++)
				{
					_state.GetStateProvider((Oculus.Interaction.Input.HandFinger)j).LastUpdatedFrameId = currentDataVersion;
				}
			}
		}

		public bool GetCurrentState(Oculus.Interaction.Input.HandFinger finger, FingerFeature fingerFeature, out string currentState)
		{
			if (!IsDataValid())
			{
				currentState = null;
				return false;
			}
			currentState = GetCurrentFingerFeatureState(finger, fingerFeature);
			return currentState != null;
		}

		private string GetCurrentFingerFeatureState(Oculus.Interaction.Input.HandFinger finger, FingerFeature fingerFeature)
		{
			return _state.GetStateProvider(finger).GetCurrentFeatureState(fingerFeature);
		}

		public float? GetFeatureValue(Oculus.Interaction.Input.HandFinger finger, FingerFeature fingerFeature)
		{
			if (!IsDataValid())
			{
				return null;
			}
			return _fingerShapes.GetValue(finger, fingerFeature, Hand);
		}

		private bool IsDataValid()
		{
			return _handJointPoses.Count > 0;
		}

		public FingerShapes GetValueProvider(Oculus.Interaction.Input.HandFinger finger)
		{
			return _fingerShapes;
		}

		public bool IsStateActive(Oculus.Interaction.Input.HandFinger finger, FingerFeature feature, FeatureStateActiveMode mode, string stateId)
		{
			string currentFingerFeatureState = GetCurrentFingerFeatureState(finger, feature);
			return mode switch
			{
				FeatureStateActiveMode.Is => currentFingerFeatureState == stateId, 
				FeatureStateActiveMode.IsNot => currentFingerFeatureState != stateId, 
				_ => false, 
			};
		}

		public void InjectAllFingerFeatureStateProvider(IHand hand, List<FingerStateThresholds> fingerStateThresholds, FingerShapes fingerShapes, bool disableProactiveEvaluation)
		{
			InjectHand(hand);
			InjectFingerStateThresholds(fingerStateThresholds);
			InjectFingerShapes(fingerShapes);
			InjectDisableProactiveEvaluation(disableProactiveEvaluation);
		}

		public void InjectHand(IHand hand)
		{
			_hand = hand as UnityEngine.Object;
			Hand = hand;
		}

		public void InjectFingerStateThresholds(List<FingerStateThresholds> fingerStateThresholds)
		{
			_fingerStateThresholds = fingerStateThresholds;
		}

		public void InjectFingerShapes(FingerShapes fingerShapes)
		{
			_fingerShapes = fingerShapes;
		}

		public void InjectDisableProactiveEvaluation(bool disableProactiveEvaluation)
		{
			_disableProactiveEvaluation = disableProactiveEvaluation;
		}

		[Obsolete("Use SetTimeProvider()")]
		public void InjectOptionalTimeProvider(Func<float> timeProvider)
		{
			_timeProvider = timeProvider;
		}
	}
	[Serializable]
	public class FingerFeatureStateThreshold : IFeatureStateThreshold<string>
	{
		[SerializeField]
		[Tooltip("The angle at which a state will transition from A > B (or B > A)")]
		private float _thresholdMidpoint;

		[SerializeField]
		[Tooltip("How far the angle must exceed the midpoint until the transition can occur. This is to prevent rapid flickering at transition edges.")]
		private float _thresholdWidth;

		[SerializeField]
		[Tooltip("State to transition to when value passes below the threshold")]
		private string _firstState;

		[SerializeField]
		[Tooltip("State to transition to when value passes above the threshold")]
		private string _secondState;

		public float ThresholdMidpoint => _thresholdMidpoint;

		public float ThresholdWidth => _thresholdWidth;

		public float ToFirstWhenBelow => _thresholdMidpoint - _thresholdWidth * 0.5f;

		public float ToSecondWhenAbove => _thresholdMidpoint + _thresholdWidth * 0.5f;

		public string FirstState => _firstState;

		public string SecondState => _secondState;

		public FingerFeatureStateThreshold()
		{
		}

		public FingerFeatureStateThreshold(float thresholdMidpoint, float thresholdWidth, string firstState, string secondState)
		{
			_thresholdMidpoint = thresholdMidpoint;
			_thresholdWidth = thresholdWidth;
			_firstState = firstState;
			_secondState = secondState;
		}
	}
	[Serializable]
	public class FingerFeatureThresholds : IFeatureStateThresholds<FingerFeature, string>
	{
		[SerializeField]
		[Tooltip("Which feature this collection of thresholds controls. Each feature should exist at most once.")]
		private FingerFeature _feature;

		[SerializeField]
		[Tooltip("List of state transitions, with thresold settings. The entries in this list must be in ascending order, based on their 'midpoint' values.")]
		private List<FingerFeatureStateThreshold> _thresholds;

		public FingerFeature Feature => _feature;

		public IReadOnlyList<IFeatureStateThreshold<string>> Thresholds => _thresholds;

		public FingerFeatureThresholds()
		{
		}

		public FingerFeatureThresholds(FingerFeature feature, IEnumerable<FingerFeatureStateThreshold> thresholds)
		{
			_feature = feature;
			_thresholds = new List<FingerFeatureStateThreshold>(thresholds);
		}
	}
	[CreateAssetMenu(menuName = "Meta/Interaction/SDK/Pose Detection/Finger Thresholds")]
	public class FingerFeatureStateThresholds : ScriptableObject, IFeatureThresholds<FingerFeature, string>
