		public virtual float GetValue(Oculus.Interaction.Input.HandFinger finger, FingerFeature feature, IHand hand)
		{
			return feature switch
			{
				FingerFeature.Curl => GetCurlValue(finger, hand), 
				FingerFeature.Flexion => GetFlexionValue(finger, hand), 
				FingerFeature.Abduction => GetAbductionValue(finger, hand), 
				FingerFeature.Opposition => GetOppositionValue(finger, hand), 
				_ => 0f, 
			};
		}

		private static float PosesCurlValue(Pose p0, Pose p1, Pose p2)
		{
			Vector3 vector = p0.position - p1.position;
			Vector3 to = p2.position - p1.position;
			Vector3 axis = p1.rotation * Oculus.Interaction.Input.Constants.LeftThumbSide;
			float num = Vector3.SignedAngle(vector, to, axis);
			if (num < 0f)
			{
				num += 360f;
			}
			return num;
		}

		public static float PosesListCurlValue(Pose[] poses)
		{
			float num = 0f;
			for (int i = 0; i < poses.Length - 2; i++)
			{
				num += PosesCurlValue(poses[i], poses[i + 1], poses[i + 2]);
			}
			return num;
		}

		protected float JointsCurlValue(Oculus.Interaction.Input.HandJointId[] joints, IHand hand)
		{
			if (!hand.GetJointPosesFromWrist(out var jointPosesFromWrist))
			{
				return 0f;
			}
			float num = 0f;
			for (int i = 0; i < joints.Length - 2; i++)
			{
				num += PosesCurlValue(jointPosesFromWrist[(int)joints[i]], jointPosesFromWrist[(int)joints[i + 1]], jointPosesFromWrist[(int)joints[i + 2]]);
			}
			return num;
		}

		public float GetCurlValue(Oculus.Interaction.Input.HandFinger finger, IHand hand)
		{
			Oculus.Interaction.Input.HandJointId[] array = CURL_ANGLE_JOINTS[(int)finger];
			return JointsCurlValue(array, hand) / (float)(array.Length - 2);
		}

		public float GetFlexionValue(Oculus.Interaction.Input.HandFinger finger, IHand hand)
		{
			if (!hand.GetJointPosesFromWrist(out var jointPosesFromWrist))
			{
				return 0f;
			}
			Oculus.Interaction.Input.HandJointId handFingerProximal = Oculus.Interaction.Input.HandJointUtils.GetHandFingerProximal(finger);
			Vector3 rightDorsal = Oculus.Interaction.Input.Constants.RightDorsal;
			Vector3 to = Vector3.ProjectOnPlane(jointPosesFromWrist[handFingerProximal].rotation * Oculus.Interaction.Input.Constants.RightDorsal, Oculus.Interaction.Input.Constants.RightThumbSide);
			return 180f + Vector3.SignedAngle(rightDorsal, to, Oculus.Interaction.Input.Constants.RightPinkySide);
		}

		public float GetAbductionValue(Oculus.Interaction.Input.HandFinger finger, IHand hand)
		{
			if (finger == Oculus.Interaction.Input.HandFinger.Pinky || !hand.GetJointPosesFromWrist(out var jointPosesFromWrist))
			{
				return 0f;
			}
			Oculus.Interaction.Input.HandFinger finger2 = finger + 1;
			Vector3 position = jointPosesFromWrist[Oculus.Interaction.Input.HandJointUtils.GetHandFingerProximal(finger)].position;
			Vector3 vector = Vector3.Lerp(position, jointPosesFromWrist[Oculus.Interaction.Input.HandJointUtils.GetHandFingerProximal(finger2)].position, 0.5f);
			Vector3 vector2 = ((finger != Oculus.Interaction.Input.HandFinger.Thumb) ? (jointPosesFromWrist[Oculus.Interaction.Input.HandJointUtils.GetHandFingerTip(finger)].position - vector) : (jointPosesFromWrist[Oculus.Interaction.Input.HandJointUtils.GetHandFingerTip(finger)].position - position));
			Vector3 vector3 = jointPosesFromWrist[Oculus.Interaction.Input.HandJointUtils.GetHandFingerTip(finger2)].position - vector;
			Vector3 axis = Vector3.Cross(vector2, vector3);
			return Vector3.SignedAngle(vector2, vector3, axis);
		}

		public float GetOppositionValue(Oculus.Interaction.Input.HandFinger finger, IHand hand)
		{
			if (finger == Oculus.Interaction.Input.HandFinger.Thumb || !hand.GetJointPosesFromWrist(out var jointPosesFromWrist))
			{
				return 0f;
			}
			Vector3 position = jointPosesFromWrist[Oculus.Interaction.Input.HandJointUtils.GetHandFingerTip(finger)].position;
			Vector3 position2 = jointPosesFromWrist[Oculus.Interaction.Input.HandJointId.HandThumbTip].position;
			return Vector3.Magnitude(position - position2);
		}

		public virtual IReadOnlyList<Oculus.Interaction.Input.HandJointId> GetJointsAffected(Oculus.Interaction.Input.HandFinger finger, FingerFeature feature)
		{
			return feature switch
			{
				FingerFeature.Curl => CURL_LINE_JOINTS[(int)finger], 
				FingerFeature.Flexion => FLEXION_LINE_JOINTS[(int)finger], 
				FingerFeature.Abduction => ABDUCTION_LINE_JOINTS[(int)finger], 
				FingerFeature.Opposition => OPPOSITION_LINE_JOINTS[(int)finger], 
				_ => null, 
			};
		}
	}
	public class HmdOffset : MonoBehaviour
	{
		[SerializeField]
		[Interface(typeof(IHmd), new Type[] { })]
		private UnityEngine.Object _hmd;

		private IHmd Hmd;

		[SerializeField]
		private Vector3 _offsetTranslation = Vector3.zero;

		[SerializeField]
		private Vector3 _offsetRotation = Vector3.zero;

		[SerializeField]
		private bool _disablePitchFromSource;

		[SerializeField]
		private bool _disableYawFromSource;

		[SerializeField]
		private bool _disableRollFromSource;

		protected bool _started;

		protected virtual void Awake()
		{
			Hmd = _hmd as IHmd;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Hmd.WhenUpdated += HandleHmdUpdated;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Hmd.WhenUpdated -= HandleHmdUpdated;
			}
		}

		protected virtual void HandleHmdUpdated()
		{
			if (Hmd.TryGetRootPose(out var pose))
			{
				Vector3 position = pose.position;
				Quaternion rotation = pose.rotation;
				Vector3 eulerAngles = rotation.eulerAngles;
				Quaternion quaternion = Quaternion.Euler(new Vector3(eulerAngles.x, 0f, 0f));
				Quaternion quaternion2 = Quaternion.Euler(new Vector3(0f, eulerAngles.y, 0f));
				Quaternion quaternion3 = Quaternion.Euler(new Vector3(0f, 0f, eulerAngles.z));
				Quaternion identity = Quaternion.identity;
				if (!_disableYawFromSource)
				{
					identity *= quaternion2;
				}
				if (!_disablePitchFromSource)
				{
					identity *= quaternion;
				}
				if (!_disableRollFromSource)
				{
					identity *= quaternion3;
				}
				Quaternion quaternion4 = identity * Quaternion.Euler(_offsetRotation);
				base.transform.position = position + quaternion4 * _offsetTranslation;
				base.transform.rotation = quaternion4;
			}
		}

		public void InjectAllHmdOffset(IHmd hmd)
		{
			InjectHmd(hmd);
		}

		public void InjectHmd(IHmd hmd)
		{
			_hmd = hmd as UnityEngine.Object;
			Hmd = hmd;
		}

		public void InjectOptionalOffsetTranslation(Vector3 val)
		{
			_offsetTranslation = val;
		}

		public void InjectOptionalOffsetRotation(Vector3 val)
		{
			_offsetRotation = val;
		}

		public void InjectOptionalDisablePitchFromSource(bool val)
		{
			_disablePitchFromSource = val;
		}

		public void InjectOptionalDisableYawFromSource(bool val)
		{
			_disableYawFromSource = val;
		}

		public void InjectOptionalDisableRollFromSource(bool val)
		{
			_disableRollFromSource = val;
		}
	}
