	public interface IJointDeltaProvider
	{
		bool GetPositionDelta(Oculus.Interaction.Input.HandJointId joint, out Vector3 delta);

		bool GetRotationDelta(Oculus.Interaction.Input.HandJointId joint, out Quaternion delta);

		void RegisterConfig(JointDeltaConfig config);

		void UnRegisterConfig(JointDeltaConfig config);
	}
	public class JointDeltaProvider : MonoBehaviour, IJointDeltaProvider
	{
		private class PoseData
		{
			public bool IsValid;

			public Pose Pose = Pose.identity;
		}

		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _hand;

		private IHand Hand;

		private Dictionary<Oculus.Interaction.Input.HandJointId, PoseData[]> _poseDataCache = new Dictionary<Oculus.Interaction.Input.HandJointId, PoseData[]>();

		private HashSet<Oculus.Interaction.Input.HandJointId> _trackedJoints = new HashSet<Oculus.Interaction.Input.HandJointId>();

		private Dictionary<int, List<Oculus.Interaction.Input.HandJointId>> _requestors = new Dictionary<int, List<Oculus.Interaction.Input.HandJointId>>();

		private int CurDataIndex;

		private int _lastUpdateDataVersion;

		protected bool _started;

		private int PrevDataIndex => 1 - CurDataIndex;

		public bool GetPositionDelta(Oculus.Interaction.Input.HandJointId joint, out Vector3 delta)
		{
			UpdateData();
			PoseData poseData = _poseDataCache[joint][PrevDataIndex];
			PoseData poseData2 = _poseDataCache[joint][CurDataIndex];
			if (!poseData.IsValid || !poseData2.IsValid)
			{
				delta = Vector3.zero;
				return false;
			}
			delta = poseData2.Pose.position - poseData.Pose.position;
			return true;
		}

		public bool GetRotationDelta(Oculus.Interaction.Input.HandJointId joint, out Quaternion delta)
		{
			UpdateData();
			PoseData poseData = _poseDataCache[joint][PrevDataIndex];
			PoseData poseData2 = _poseDataCache[joint][CurDataIndex];
			if (!poseData.IsValid || !poseData2.IsValid)
			{
				delta = Quaternion.identity;
				return false;
			}
			delta = poseData2.Pose.rotation * Quaternion.Inverse(poseData.Pose.rotation);
			return true;
		}

		public bool GetPrevJointPose(Oculus.Interaction.Input.HandJointId joint, out Pose pose)
		{
			UpdateData();
			PoseData poseData = _poseDataCache[joint][PrevDataIndex];
			pose = poseData.Pose;
			return poseData.IsValid;
		}

		public void RegisterConfig(JointDeltaConfig config)
		{
			_requestors.ContainsKey(config.InstanceID);
			_requestors.Add(config.InstanceID, new List<Oculus.Interaction.Input.HandJointId>(config.JointIDs));
			foreach (Oculus.Interaction.Input.HandJointId jointID in config.JointIDs)
			{
				if (!_poseDataCache.ContainsKey(jointID))
				{
					_poseDataCache.Add(jointID, new PoseData[2]
					{
						new PoseData(),
						new PoseData()
					});
					PoseData poseData = _poseDataCache[jointID][CurDataIndex];
					poseData.IsValid = Hand.GetJointPose(jointID, out poseData.Pose);
				}
			}
		}

		public void UnRegisterConfig(JointDeltaConfig config)
		{
			_requestors.Remove(config.InstanceID);
		}

		protected virtual void Awake()
		{
			Hand = _hand as IHand;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated += UpdateData;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Hand.WhenHandUpdated -= UpdateData;
			}
		}

		private void UpdateData()
		{
			if (Hand.CurrentDataVersion <= _lastUpdateDataVersion)
			{
				return;
			}
			_lastUpdateDataVersion = Hand.CurrentDataVersion;
			CurDataIndex = 1 - CurDataIndex;
			_trackedJoints.Clear();
			foreach (int key in _requestors.Keys)
			{
				IList<Oculus.Interaction.Input.HandJointId> other = _requestors[key];
				_trackedJoints.UnionWithNonAlloc(other);
			}
			foreach (Oculus.Interaction.Input.HandJointId key2 in _poseDataCache.Keys)
			{
				PoseData poseData = _poseDataCache[key2][CurDataIndex];
				poseData.IsValid = _trackedJoints.Contains(key2) && Hand.GetJointPose(key2, out poseData.Pose);
			}
		}
	}
	public class JointDistanceActiveState : MonoBehaviour, IActiveState
	{
		[Tooltip("The IHand that JointIdA will be sourced from.")]
		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _handA;

		private IHand HandA;

		[Tooltip("The joint of HandA to use for distance check.")]
		[SerializeField]
		private Oculus.Interaction.Input.HandJointId _jointIdA;

		[Tooltip("The joint of HandA to use for distance check.")]
		[SerializeField]
		private Oculus.Interaction.Input.HandJointId _jointA;

		[Tooltip("The IHand that JointIdB will be sourced from.")]
		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _handB;

		private IHand HandB;

		[Tooltip("The joint of HandB to use for distance check.")]
		[SerializeField]
		private Oculus.Interaction.Input.HandJointId _jointIdB;

		[Tooltip("The joint of HandB to use for distance check.")]
		[SerializeField]
		private Oculus.Interaction.Input.HandJointId _jointB;

		[Tooltip("The ActiveState will become Active when joints are within this distance from each other.")]
		[SerializeField]
		private float _distance = 0.05f;

		[Tooltip("The distance value will be modified by this width to create differing enter/exit thresholds. Used to prevent chattering at the threshold edge.")]
		[SerializeField]
		private float _thresholdWidth = 0.02f;

		[Tooltip("A new state must be maintaned for at least this many seconds before the Active property changes.")]
		[SerializeField]
		private float _minTimeInState = 0.05f;

		private bool _activeState;

		private bool _internalState;

		private float _lastStateChangeTime;

		private int _lastStateUpdateFrame;

		public Oculus.Interaction.Input.HandJointId JointIdA
		{
			get
			{
				return _jointA;
			}
			set
			{
				_jointA = value;
			}
		}

		public Oculus.Interaction.Input.HandJointId JointIdB
		{
			get
			{
				return _jointB;
			}
			set
			{
				_jointB = value;
			}
		}

		public bool Active
		{
			get
			{
				if (!base.isActiveAndEnabled)
				{
					return false;
				}
				UpdateActiveState();
				return _activeState;
			}
		}

		protected virtual void Awake()
		{
			HandA = _handA as IHand;
			HandB = _handB as IHand;
		}

		protected virtual void Start()
		{
		}

		protected virtual void Update()
		{
			UpdateActiveState();
		}

		private void UpdateActiveState()
		{
			if (Time.frameCount > _lastStateUpdateFrame)
			{
				_lastStateUpdateFrame = Time.frameCount;
				bool flag = JointDistanceWithinThreshold();
				if (flag != _internalState)
				{
					_internalState = flag;
					_lastStateChangeTime = Time.unscaledTime;
				}
				if (Time.unscaledTime - _lastStateChangeTime >= _minTimeInState)
				{
					_activeState = _internalState;
				}
			}
		}

		private bool JointDistanceWithinThreshold()
		{
			if (HandA.GetJointPose(JointIdA, out var pose) && HandB.GetJointPose(JointIdB, out var pose2))
			{
				float num = (_internalState ? (_distance + _thresholdWidth * 0.5f) : (_distance - _thresholdWidth * 0.5f));
				return Vector3.Distance(pose.position, pose2.position) <= num;
			}
			return false;
		}

		public void InjectAllJointDistanceActiveState(IHand handA, IHand handB)
		{
			InjectHandA(handA);
			InjectHandB(handB);
		}

		public void InjectHandA(IHand handA)
		{
			_handA = handA as UnityEngine.Object;
			HandA = handA;
		}

		[Obsolete("Use the JointIdA setter instead")]
		public void InjectJointIdA(Oculus.Interaction.Input.HandJointId jointIdA)
		{
			JointIdA = jointIdA;
		}

		public void InjectHandB(IHand handB)
		{
			_handB = handB as UnityEngine.Object;
			HandB = handB;
		}

		[Obsolete("Use the JointIdB setter instead")]
		public void InjectJointIdB(Oculus.Interaction.Input.HandJointId jointIdB)
		{
			JointIdB = jointIdB;
		}

		public void InjectOptionalDistance(float val)
		{
			_distance = val;
		}

		public void InjectOptionalThresholdWidth(float val)
		{
			_thresholdWidth = val;
		}

		public void InjectOptionalMinTimeInState(float val)
		{
			_minTimeInState = val;
		}
	}
	public class JointRotationActiveState : MonoBehaviour, IActiveState, ITimeConsumer
	{
		public enum RelativeTo
		{
			Hand,
			World
		}

		public enum WorldAxis
		{
			PositiveX,
			NegativeX,
			PositiveY,
			NegativeY,
			PositiveZ,
			NegativeZ
		}

		public enum HandAxis
		{
			Pronation,
			Supination,
			RadialDeviation,
			UlnarDeviation,
			Extension,
			Flexion
		}

		[Serializable]
		public struct JointRotationFeatureState(Vector3 targetAxis, float amount)
		{
			public readonly Vector3 TargetAxis = targetAxis;

			public readonly float Amount = amount;
		}

		[Serializable]
		public class JointRotationFeatureConfigList
		{
			[SerializeField]
			private List<JointRotationFeatureConfig> _values;

			public List<JointRotationFeatureConfig> Values => _values;
		}

		[Serializable]
		public class JointRotationFeatureConfig : FeatureConfigBase<Oculus.Interaction.Input.HandJointId>
		{
			[Tooltip("The detection axis will be in this coordinate space.")]
			[SerializeField]
			private RelativeTo _relativeTo;

			[Tooltip("The world axis used for detection.")]
			[SerializeField]
			private WorldAxis _worldAxis = WorldAxis.PositiveZ;

			[Tooltip("The axis of the hand root pose used for detection.")]
			[SerializeField]
			private HandAxis _handAxis = HandAxis.RadialDeviation;

			public RelativeTo RelativeTo
			{
				get
				{
					return _relativeTo;
				}
				set
				{
					_relativeTo = value;
				}
			}

			public WorldAxis WorldAxis
			{
				get
				{
					return _worldAxis;
				}
				set
				{
					_worldAxis = value;
				}
			}

			public HandAxis HandAxis
			{
				get
				{
					return _handAxis;
				}
				set
				{
					_handAxis = value;
				}
			}
		}

		[Tooltip("Provided joints will be sourced from this IHand.")]
		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _hand;

		[Tooltip("JointDeltaProvider caches joint deltas to avoid unnecessary recomputing of deltas.")]
		[SerializeField]
		[Interface(typeof(IJointDeltaProvider), new Type[] { })]
		private UnityEngine.Object _jointDeltaProvider;

		[SerializeField]
		private JointRotationFeatureConfigList _featureConfigs;

		[SerializeField]
		private JointRotationFeatureConfigList _featureConfigurations;

		[Tooltip("The angular velocity used for the detection threshold, in degrees per second.")]
		[SerializeField]
		[Min(0f)]
		private float _degreesPerSecond = 120f;

		[Tooltip("The degrees per second value will be modified by this width to create differing enter/exit thresholds. Used to prevent chattering at the threshold edge.")]
		[SerializeField]
		[Min(0f)]
		private float _thresholdWidth = 30f;

		[Tooltip("A new state must be maintaned for at least this many seconds before the Active property changes.")]
		[SerializeField]
		[Min(0f)]
		private float _minTimeInState = 0.05f;

		private Func<float> _timeProvider = () => Time.time;

		private Dictionary<JointRotationFeatureConfig, JointRotationFeatureState> _featureStates = new Dictionary<JointRotationFeatureConfig, JointRotationFeatureState>();

		private JointDeltaConfig _jointDeltaConfig;

		private IJointDeltaProvider JointDeltaProvider;

		private int _lastStateUpdateFrame;

		private float _lastStateChangeTime;

		private float _lastUpdateTime;

		private bool _internalState;

		private bool _activeState;

		protected bool _started;

		public IHand Hand { get; private set; }

		public bool Active
		{
			get
			{
				if (!base.isActiveAndEnabled)
				{
					return false;
				}
				UpdateActiveState();
				return _activeState;
			}
		}

		public IReadOnlyList<JointRotationFeatureConfig> FeatureConfigs => _featureConfigurations.Values;

		public IReadOnlyDictionary<JointRotationFeatureConfig, JointRotationFeatureState> FeatureStates => _featureStates;

		public void SetTimeProvider(Func<float> timeProvider)
		{
			_timeProvider = timeProvider;
		}

		protected virtual void Awake()
		{
			Hand = _hand as IHand;
			JointDeltaProvider = _jointDeltaProvider as IJointDeltaProvider;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			IList<Oculus.Interaction.Input.HandJointId> list = new List<Oculus.Interaction.Input.HandJointId>();
			foreach (JointRotationFeatureConfig featureConfig in FeatureConfigs)
			{
				list.Add(featureConfig.Feature);
				_featureStates.Add(featureConfig, default(JointRotationFeatureState));
			}
			_jointDeltaConfig = new JointDeltaConfig(GetInstanceID(), list);
			_lastUpdateTime = _timeProvider();
			this.EndStart(ref _started);
		}

		private bool CheckAllJointRotations()
		{
			bool flag = true;
			float num = _timeProvider() - _lastUpdateTime;
			float num2 = (_internalState ? (_degreesPerSecond + _thresholdWidth * 0.5f) : (_degreesPerSecond - _thresholdWidth * 0.5f));
			num2 *= num;
			foreach (JointRotationFeatureConfig featureConfig in FeatureConfigs)
			{
				if (Hand.GetJointPose(Oculus.Interaction.Input.HandJointId.HandWristRoot, out var pose) && Hand.GetJointPose(featureConfig.Feature, out var _) && JointDeltaProvider.GetRotationDelta(featureConfig.Feature, out var delta))
				{
					Vector3 worldTargetAxis = GetWorldTargetAxis(pose, featureConfig);
					delta.ToAngleAxis(out var angle, out var axis);
					float num3 = Mathf.Abs(Vector3.Dot(axis, worldTargetAxis));
					float num4 = angle * num3;
					_featureStates[featureConfig] = new JointRotationFeatureState(worldTargetAxis, (num2 <= 0f) ? 1f : Mathf.Clamp01(num4 / num2));
					bool flag2 = num4 > num2;
					flag = flag && flag2;
				}
				else
				{
					flag = false;
				}
			}
			return flag;
		}

		protected virtual void Update()
		{
			UpdateActiveState();
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				JointDeltaProvider.RegisterConfig(_jointDeltaConfig);
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				JointDeltaProvider.UnRegisterConfig(_jointDeltaConfig);
			}
		}

		private void UpdateActiveState()
		{
			if (Time.frameCount > _lastStateUpdateFrame)
			{
				_lastStateUpdateFrame = Time.frameCount;
				bool flag = CheckAllJointRotations();
				if (flag != _internalState)
				{
					_internalState = flag;
					_lastStateChangeTime = _timeProvider();
				}
				if (_timeProvider() - _lastStateChangeTime >= _minTimeInState)
				{
					_activeState = _internalState;
				}
				_lastUpdateTime = _timeProvider();
			}
		}

		private Vector3 GetWorldTargetAxis(Pose wristPose, JointRotationFeatureConfig config)
		{
			RelativeTo relativeTo = config.RelativeTo;
			if (relativeTo == RelativeTo.Hand || relativeTo != RelativeTo.World)
			{
				return GetHandAxisVector(config.HandAxis, wristPose);
			}
			return GetWorldAxisVector(config.WorldAxis);
		}

		private Vector3 GetWorldAxisVector(WorldAxis axis)
		{
			return axis switch
			{
				WorldAxis.NegativeX => Vector3.left, 
				WorldAxis.PositiveY => Vector3.up, 
				WorldAxis.NegativeY => Vector3.down, 
				WorldAxis.PositiveZ => Vector3.forward, 
				WorldAxis.NegativeZ => Vector3.back, 
				_ => Vector3.right, 
			};
		}

		private Vector3 GetHandAxisVector(HandAxis axis, Pose wristPose)
		{
			return axis switch
			{
				HandAxis.Pronation => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftProximal : Oculus.Interaction.Input.Constants.RightProximal), 
				HandAxis.Supination => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftDistal : Oculus.Interaction.Input.Constants.RightDistal), 
				HandAxis.RadialDeviation => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftPalmar : Oculus.Interaction.Input.Constants.RightPalmar), 
				HandAxis.UlnarDeviation => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftDorsal : Oculus.Interaction.Input.Constants.RightDorsal), 
				HandAxis.Extension => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftThumbSide : Oculus.Interaction.Input.Constants.RightThumbSide), 
				HandAxis.Flexion => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftPinkySide : Oculus.Interaction.Input.Constants.RightPinkySide), 
				_ => Vector3.zero, 
			};
		}

		public void InjectAllJointRotationActiveState(JointRotationFeatureConfigList featureConfigs, IHand hand, IJointDeltaProvider jointDeltaProvider)
		{
			InjectFeatureConfigList(featureConfigs);
			InjectHand(hand);
			InjectJointDeltaProvider(jointDeltaProvider);
		}

		public void InjectFeatureConfigList(JointRotationFeatureConfigList featureConfigs)
		{
			_featureConfigs = featureConfigs;
		}

		public void InjectHand(IHand hand)
		{
			_hand = hand as UnityEngine.Object;
			Hand = hand;
		}

		public void InjectJointDeltaProvider(IJointDeltaProvider jointDeltaProvider)
		{
			JointDeltaProvider = jointDeltaProvider;
			_jointDeltaProvider = jointDeltaProvider as UnityEngine.Object;
		}

		[Obsolete("Use SetTimeProvider()")]
