				{
					_activeState = _internalState;
				}
				_lastUpdateTime = _timeProvider();
			}
		}

		private Vector3 GetWorldTargetVector(Pose wristPose, JointVelocityFeatureConfig config)
		{
			return config.RelativeTo switch
			{
				RelativeTo.World => GetWorldAxisVector(config.WorldAxis), 
				RelativeTo.Head => GetHeadAxisVector(config.HeadAxis), 
				_ => GetHandAxisVector(config.HandAxis, wristPose), 
			};
		}

		private Vector3 GetWorldAxisVector(WorldAxis axis)
		{
			return axis switch
			{
				WorldAxis.NegativeX => Vector3.left, 
				WorldAxis.PositiveY => Vector3.up, 
				WorldAxis.NegativeY => Vector3.down, 
				WorldAxis.PositiveZ => Vector3.forward, 
				WorldAxis.NegativeZ => Vector3.back, 
				_ => Vector3.right, 
			};
		}

		private Vector3 GetHandAxisVector(HandAxis axis, Pose wristPose)
		{
			return axis switch
			{
				HandAxis.PalmForward => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftPalmar : Oculus.Interaction.Input.Constants.RightPalmar), 
				HandAxis.PalmBackward => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftDorsal : Oculus.Interaction.Input.Constants.RightDorsal), 
				HandAxis.WristUp => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftThumbSide : Oculus.Interaction.Input.Constants.RightThumbSide), 
				HandAxis.WristDown => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftPinkySide : Oculus.Interaction.Input.Constants.RightPinkySide), 
				HandAxis.WristForward => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftDistal : Oculus.Interaction.Input.Constants.RightDistal), 
				HandAxis.WristBackward => wristPose.rotation * ((Hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftProximal : Oculus.Interaction.Input.Constants.RightProximal), 
				_ => Vector3.zero, 
			};
		}

		private Vector3 GetHeadAxisVector(HeadAxis axis)
		{
			Hmd.TryGetRootPose(out var pose);
			return axis switch
			{
				HeadAxis.HeadForward => pose.forward, 
				HeadAxis.HeadBackward => -pose.forward, 
				HeadAxis.HeadUp => pose.up, 
				HeadAxis.HeadDown => -pose.up, 
				HeadAxis.HeadRight => pose.right, 
				HeadAxis.HeadLeft => -pose.right, 
				_ => Vector3.zero, 
			};
		}

		public void InjectAllJointVelocityActiveState(JointVelocityFeatureConfigList featureConfigs, IHand hand, IJointDeltaProvider jointDeltaProvider)
