					if (_wasRemainActive)
					{
						_cooldownExceededTime = num + _remainActiveCooldown;
					}
					if (_cooldownExceededTime <= num)
					{
						Active = false;
					}
				}
				_wasRemainActive = flag;
				if (!Active)
				{
					ResetState();
				}
			}
			else if (CurrentActivationStep < _stepsToActivate.Length)
			{
