		[SerializeField]
		private FingerFeatureConfigList _pinkyFeatureConfigs = new FingerFeatureConfigList();

		public IReadOnlyList<FingerFeatureConfig> ThumbFeatureConfigs => _thumbFeatureConfigs.Value;

		public IReadOnlyList<FingerFeatureConfig> IndexFeatureConfigs => _indexFeatureConfigs.Value;

		public IReadOnlyList<FingerFeatureConfig> MiddleFeatureConfigs => _middleFeatureConfigs.Value;

		public IReadOnlyList<FingerFeatureConfig> RingFeatureConfigs => _ringFeatureConfigs.Value;

		public IReadOnlyList<FingerFeatureConfig> PinkyFeatureConfigs => _pinkyFeatureConfigs.Value;

		public string ShapeName => _shapeName;

		public IReadOnlyList<FingerFeatureConfig> GetFingerFeatureConfigs(Oculus.Interaction.Input.HandFinger finger)
		{
			return finger switch
			{
				Oculus.Interaction.Input.HandFinger.Thumb => ThumbFeatureConfigs, 
				Oculus.Interaction.Input.HandFinger.Index => IndexFeatureConfigs, 
				Oculus.Interaction.Input.HandFinger.Middle => MiddleFeatureConfigs, 
				Oculus.Interaction.Input.HandFinger.Ring => RingFeatureConfigs, 
				Oculus.Interaction.Input.HandFinger.Pinky => PinkyFeatureConfigs, 
				_ => throw new ArgumentException("must be a HandFinger enum value", "finger"), 
			};
		}

		public IEnumerable<(Oculus.Interaction.Input.HandFinger, IReadOnlyList<FingerFeatureConfig>)> GetFingerFeatureConfigs()
		{
			int fingerIdx = 0;
			while (fingerIdx < 5)
			{
				Oculus.Interaction.Input.HandFinger handFinger = (Oculus.Interaction.Input.HandFinger)fingerIdx;
				IReadOnlyList<FingerFeatureConfig> fingerFeatureConfigs = GetFingerFeatureConfigs(handFinger);
				if (fingerFeatureConfigs.Count != 0)
				{
					yield return (handFinger, fingerFeatureConfigs);
				}
				int num = fingerIdx + 1;
				fingerIdx = num;
			}
		}

		public void InjectAllShapeRecognizer(IDictionary<Oculus.Interaction.Input.HandFinger, FingerFeatureConfig[]> fingerFeatureConfigs)
		{
			_thumbFeatureConfigs = ReadFeatureConfigs(Oculus.Interaction.Input.HandFinger.Thumb);
			_indexFeatureConfigs = ReadFeatureConfigs(Oculus.Interaction.Input.HandFinger.Index);
			_middleFeatureConfigs = ReadFeatureConfigs(Oculus.Interaction.Input.HandFinger.Middle);
			_ringFeatureConfigs = ReadFeatureConfigs(Oculus.Interaction.Input.HandFinger.Ring);
			_pinkyFeatureConfigs = ReadFeatureConfigs(Oculus.Interaction.Input.HandFinger.Pinky);
			FingerFeatureConfigList ReadFeatureConfigs(Oculus.Interaction.Input.HandFinger finger)
			{
				if (!fingerFeatureConfigs.TryGetValue(finger, out var value))
				{
					value = Array.Empty<FingerFeatureConfig>();
				}
				return new FingerFeatureConfigList(new List<FingerFeatureConfig>(value));
			}
		}

		public void InjectThumbFeatureConfigs(FingerFeatureConfig[] configs)
		{
			_thumbFeatureConfigs = new FingerFeatureConfigList(new List<FingerFeatureConfig>(configs));
		}

		public void InjectIndexFeatureConfigs(FingerFeatureConfig[] configs)
		{
