	public class FingerFeatureDebugVisual : MonoBehaviour
	{
		[SerializeField]
		private Renderer _target;

		[SerializeField]
		private Color _normalColor = Color.red;

		[SerializeField]
		private Color _activeColor = Color.green;

		[SerializeField]
		private TextMeshPro _targetText;

		private IFingerFeatureStateProvider _fingerFeatureState;

		private Material _material;

		private bool _lastActiveValue;

		private Oculus.Interaction.Input.HandFinger _handFinger;

		private ShapeRecognizer.FingerFeatureConfig _featureConfig;

		private bool _initialized;

		protected virtual void Awake()
		{
			_material = _target.material;
			_material.color = (_lastActiveValue ? _activeColor : _normalColor);
		}

		protected virtual void OnDestroy()
		{
			UnityEngine.Object.Destroy(_material);
		}

		public void Initialize(Oculus.Interaction.Input.HandFinger handFinger, ShapeRecognizer.FingerFeatureConfig config, IFingerFeatureStateProvider fingerFeatureState)
		{
			_initialized = true;
			_handFinger = handFinger;
			_featureConfig = config;
			_fingerFeatureState = fingerFeatureState;
		}

		protected virtual void Update()
		{
			if (_initialized)
			{
				FingerFeature feature = _featureConfig.Feature;
				bool flag = false;
				if (_fingerFeatureState.GetCurrentState(_handFinger, feature, out var currentState))
				{
					float? featureValue = _fingerFeatureState.GetFeatureValue(_handFinger, feature);
					flag = _fingerFeatureState.IsStateActive(_handFinger, feature, _featureConfig.Mode, _featureConfig.State);
					string text = (featureValue.HasValue ? featureValue.Value.ToString("F2") : "--");
					_targetText.text = $"{_handFinger} {feature}" + currentState + " (" + text + ")";
				}
				else
				{
					_targetText.text = $"{_handFinger} {feature}\n";
				}
				if (flag != _lastActiveValue)
				{
					_material.color = (flag ? _activeColor : _normalColor);
					_lastActiveValue = flag;
				}
			}
		}
	}
	public class FingerFeatureSkeletalDebugVisual : MonoBehaviour
	{
		[SerializeField]
		private FingerFeatureStateProvider _fingerFeatureStateProvider;

		[SerializeField]
		private LineRenderer _lineRenderer;

		[SerializeField]
		private Color _normalColor = Color.red;

		[SerializeField]
		private Color _activeColor = Color.green;

		[SerializeField]
		private float _lineWidth = 0.005f;

		private IHand _hand;

		private bool _lastFeatureActiveValue;

		private IReadOnlyList<Oculus.Interaction.Input.HandJointId> _jointsCovered;

		private Oculus.Interaction.Input.HandFinger _finger;

		private ShapeRecognizer.FingerFeatureConfig _fingerFeatureConfig;

		private bool _initializedPositions;

		private bool _initialized;

		protected virtual void Awake()
		{
			UpdateFeatureActiveValueAndVisual(newValue: false);
		}

		private void UpdateFeatureActiveValueAndVisual(bool newValue)
		{
			Color color = (newValue ? _activeColor : _normalColor);
			_lineRenderer.startColor = color;
			_lineRenderer.endColor = color;
			_lastFeatureActiveValue = newValue;
		}

		public void Initialize(IHand hand, Oculus.Interaction.Input.HandFinger finger, ShapeRecognizer.FingerFeatureConfig fingerFeatureConfig)
		{
			_hand = hand;
			_initialized = true;
			FingerShapes valueProvider = _fingerFeatureStateProvider.GetValueProvider(finger);
			_jointsCovered = valueProvider.GetJointsAffected(finger, fingerFeatureConfig.Feature);
			_finger = finger;
			_fingerFeatureConfig = fingerFeatureConfig;
			_initializedPositions = false;
		}

		protected virtual void Update()
		{
			if (!_initialized || !_hand.IsTrackedDataValid)
			{
				ToggleLineRendererEnableState(enableState: false);
				return;
			}
			ToggleLineRendererEnableState(enableState: true);
			UpdateDebugSkeletonLineRendererJoints();
			UpdateFeatureActiveValue();
		}

		private void ToggleLineRendererEnableState(bool enableState)
		{
			if (_lineRenderer.enabled != enableState)
			{
				_lineRenderer.enabled = enableState;
			}
		}

		private void UpdateDebugSkeletonLineRendererJoints()
		{
			if (!_initializedPositions)
			{
				_lineRenderer.positionCount = _jointsCovered.Count;
				_initializedPositions = true;
			}
			if (Mathf.Abs(_lineRenderer.startWidth - _lineWidth) > Mathf.Epsilon)
			{
				_lineRenderer.startWidth = _lineWidth;
				_lineRenderer.endWidth = _lineWidth;
			}
			int count = _jointsCovered.Count;
			for (int i = 0; i < count; i++)
			{
				if (_hand.GetJointPose(_jointsCovered[i], out var pose))
				{
					_lineRenderer.SetPosition(i, pose.position);
				}
			}
		}

		private void UpdateFeatureActiveValue()
		{
			bool flag = _fingerFeatureStateProvider.IsStateActive(_finger, _fingerFeatureConfig.Feature, _fingerFeatureConfig.Mode, _fingerFeatureConfig.State);
			if (flag != _lastFeatureActiveValue)
			{
				UpdateFeatureActiveValueAndVisual(flag);
			}
		}
	}
	public class HandShapeDebugVisual : MonoBehaviour
	{
		[SerializeField]
		[Interface(typeof(IFingerFeatureStateProvider), new Type[] { })]
		private UnityEngine.Object _fingerFeatureStateProvider;

		private IFingerFeatureStateProvider FingerFeatureStateProvider;

		[SerializeField]
		private ShapeRecognizerActiveState _shapeRecognizerActiveState;

		[SerializeField]
		private Renderer _target;

		[SerializeField]
		private Color _normalColor = Color.red;

		[SerializeField]
		private Color _activeColor = Color.green;

		[SerializeField]
		private GameObject _fingerFeatureDebugVisualPrefab;

		[SerializeField]
		private Transform _fingerFeatureParent;

		[SerializeField]
		private Vector3 _fingerSpacingVec = new Vector3(0f, -1f, 0f);

		[SerializeField]
		private Vector3 _fingerFeatureSpacingVec = new Vector3(1f, 0f, 0f);

		[SerializeField]
		private Vector3 _fingerFeatureDebugLocalScale = new Vector3(0.3f, 0.3f, 0.3f);

		[SerializeField]
		private TextMeshPro _targetText;

		private Material _material;

		private bool _lastActiveValue;

		protected virtual void Awake()
		{
			FingerFeatureStateProvider = _fingerFeatureStateProvider as IFingerFeatureStateProvider;
			_material = _target.material;
			_material.color = (_lastActiveValue ? _activeColor : _normalColor);
			if (_fingerFeatureParent == null)
			{
				_fingerFeatureParent = base.transform;
			}
		}

		protected virtual void Start()
		{
			Vector3 zero = Vector3.zero;
			foreach (var item in from s in AllFeatureStates()
				group s by s.Item1 into @group
				select new
				{
					HandFinger = @group.Key,
					FingerFeatures = @group.SelectMany(((Oculus.Interaction.Input.HandFinger, IReadOnlyList<ShapeRecognizer.FingerFeatureConfig>) item) => item.Item2)
				})
			{
				Vector3 localPosition = zero;
				foreach (ShapeRecognizer.FingerFeatureConfig fingerFeature in item.FingerFeatures)
				{
					FingerFeatureDebugVisual component = UnityEngine.Object.Instantiate(_fingerFeatureDebugVisualPrefab, _fingerFeatureParent).GetComponent<FingerFeatureDebugVisual>();
					component.Initialize(item.HandFinger, fingerFeature, FingerFeatureStateProvider);
					Transform obj = component.transform;
					obj.localScale = _fingerFeatureDebugLocalScale;
					obj.localRotation = Quaternion.identity;
					obj.localPosition = localPosition;
					localPosition += _fingerFeatureSpacingVec;
				}
				zero += _fingerSpacingVec;
			}
			string text = "";
			foreach (ShapeRecognizer shape in _shapeRecognizerActiveState.Shapes)
			{
				text += shape.ShapeName;
			}
			_targetText.text = $"{_shapeRecognizerActiveState.Handedness} Hand: {text} ";
		}

		private IEnumerable<(Oculus.Interaction.Input.HandFinger, IReadOnlyList<ShapeRecognizer.FingerFeatureConfig>)> AllFeatureStates()
		{
			foreach (ShapeRecognizer shape in _shapeRecognizerActiveState.Shapes)
			{
				foreach (var fingerFeatureConfig in shape.GetFingerFeatureConfigs())
				{
					yield return fingerFeatureConfig;
				}
			}
		}

		protected virtual void OnDestroy()
		{
			UnityEngine.Object.Destroy(_material);
		}

		protected virtual void Update()
		{
			bool active = _shapeRecognizerActiveState.Active;
			if (_lastActiveValue != active)
			{
				_material.color = (active ? _activeColor : _normalColor);
				_lastActiveValue = active;
			}
		}
	}
