namespace Oculus.Interaction.DebugTree
{
	public interface ITreeNode<TLeaf> where TLeaf : class
	{
		TLeaf Value { get; }

		IEnumerable<ITreeNode<TLeaf>> Children { get; }
	}
	public abstract class DebugTree<TLeaf> where TLeaf : class
	{
		private class Node : ITreeNode<TLeaf>
		{
			TLeaf ITreeNode<TLeaf>.Value => Value;

			IEnumerable<ITreeNode<TLeaf>> ITreeNode<TLeaf>.Children => Children;

			public TLeaf Value { get; set; }

			public List<Node> Children { get; set; }
		}

		private Dictionary<TLeaf, Node> _existingNodes = new Dictionary<TLeaf, Node>();

		private readonly TLeaf Root;

		private Node _rootNode;

		public DebugTree(TLeaf root)
		{
			Root = root;
		}

		public ITreeNode<TLeaf> GetRootNode()
		{
			return _rootNode;
		}

		[Obsolete("Use async method instead.", true)]
		public void Rebuild()
		{
			throw new NotImplementedException();
		}

		public async Task RebuildAsync()
		{
			_rootNode = await BuildTreeAsync(Root);
		}

		private async Task<Node> BuildTreeAsync(TLeaf root)
		{
			_existingNodes.Clear();
			return await BuildTreeRecursiveAsync(root);
		}

		private async Task<Node> BuildTreeRecursiveAsync(TLeaf value)
		{
			if (value == null)
			{
				return null;
			}
			if (_existingNodes.ContainsKey(value))
			{
				return _existingNodes[value];
			}
			List<Node> children = new List<Node>();
			foreach (TLeaf item in await TryGetChildrenAsync(value))
			{
				Node node = await BuildTreeRecursiveAsync(item);
				if (node != null)
				{
					children.Add(node);
				}
			}
			Node node2 = new Node
			{
				Value = value,
				Children = children
			};
			_existingNodes.Add(value, node2);
			return node2;
		}

		[Obsolete("Use async method instead.", true)]
		protected virtual bool TryGetChildren(TLeaf node, out IEnumerable<TLeaf> children)
		{
			throw new NotImplementedException();
		}

		protected abstract Task<IEnumerable<TLeaf>> TryGetChildrenAsync(TLeaf node);
	}
	public interface INodeUI<TLeaf> where TLeaf : class
	{
		RectTransform ChildArea { get; }

		void Bind(ITreeNode<TLeaf> node, bool isRoot, bool isDuplicate);
	}
	public abstract class DebugTreeUI<TLeaf> : MonoBehaviour where TLeaf : class
	{
		[Tooltip("Node prefabs will be instantiated inside of this content area.")]
		[SerializeField]
		private RectTransform _contentArea;

		[Tooltip("This title text will display the GameObject name of the IActiveState.")]
		[SerializeField]
		[Optional]
		private TMP_Text _title;

		[Tooltip("If true, the tree UI will be built on Start.")]
		[SerializeField]
		private bool _buildTreeOnStart;

		private DebugTree<TLeaf> _tree;

		private Dictionary<ITreeNode<TLeaf>, INodeUI<TLeaf>> _nodeToUI = new Dictionary<ITreeNode<TLeaf>, INodeUI<TLeaf>>();

		protected abstract TLeaf Value { get; }

		protected abstract INodeUI<TLeaf> NodePrefab { get; }

		protected virtual void Start()
		{
			if (_buildTreeOnStart)
			{
				StartCoroutine(BuildTree());
			}
		}

		public IEnumerator BuildTree()
		{
			_tree = CreateTree(Value);
			Task task = _tree.RebuildAsync();
			yield return new WaitUntil(() => task.IsCompleted);
			_nodeToUI.Clear();
			ClearContentArea();
			SetTitleText();
			BuildTreeRecursive(_contentArea, _tree.GetRootNode(), isRoot: true);
		}

		private void BuildTreeRecursive(RectTransform parent, ITreeNode<TLeaf> node, bool isRoot)
		{
			INodeUI<TLeaf> nodeUI = UnityEngine.Object.Instantiate(NodePrefab as UnityEngine.Object, parent) as INodeUI<TLeaf>;
			bool flag = _nodeToUI.ContainsKey(node);
			nodeUI.Bind(node, isRoot, flag);
			if (flag)
			{
				return;
			}
			_nodeToUI.Add(node, nodeUI);
			foreach (ITreeNode<TLeaf> child in node.Children)
			{
				BuildTreeRecursive(nodeUI.ChildArea, child, isRoot: false);
			}
		}

		private void ClearContentArea()
		{
			for (int i = 0; i < _contentArea.childCount; i++)
			{
				Transform child = _contentArea.GetChild(i);
				if (child != null && child.TryGetComponent<INodeUI<TLeaf>>(out var _))
				{
					UnityEngine.Object.Destroy(child.gameObject);
				}
			}
		}

		private void SetTitleText()
		{
			if (_title != null)
			{
				_title.text = TitleForValue(Value);
			}
		}

		protected abstract DebugTree<TLeaf> CreateTree(TLeaf value);

		protected abstract string TitleForValue(TLeaf value);
	}
	public class InteractorGroupDebugTreeUI : DebugTreeUI<IInteractor>
	{
		private class InteractorGroupDebugTree : DebugTree<IInteractor>
		{
			public InteractorGroupDebugTree(IInteractor root)
				: base(root)
			{
			}

			protected override Task<IEnumerable<IInteractor>> TryGetChildrenAsync(IInteractor node)
			{
				if (node is InteractorGroup)
				{
					return Task.FromResult((IEnumerable<IInteractor>)(node as InteractorGroup).Interactors);
				}
				return Task.FromResult(Enumerable.Empty<IInteractor>());
			}
		}

		[SerializeField]
		[Interface(typeof(IInteractor), new Type[] { })]
		private UnityEngine.Object _root;

		[Tooltip("The node prefab which will be used to build the visual tree.")]
		[SerializeField]
		[Interface(typeof(INodeUI<IInteractor>), new Type[] { })]
		private UnityEngine.Component _nodePrefab;

		protected override IInteractor Value => _root as IInteractor;

		protected override INodeUI<IInteractor> NodePrefab => _nodePrefab as INodeUI<IInteractor>;

		protected override DebugTree<IInteractor> CreateTree(IInteractor value)
		{
			return new InteractorGroupDebugTree(value);
		}

		protected override string TitleForValue(IInteractor value)
		{
			UnityEngine.Object obj = value as UnityEngine.Object;
			if (!(obj != null))
			{
				return "";
			}
			return obj.name;
		}
	}
	public class InteractorGroupNodeUI : MonoBehaviour, INodeUI<IInteractor>
	{
		[SerializeField]
		private RectTransform _childArea;

		[SerializeField]
		private RectTransform _connectingLine;

		[SerializeField]
		private TextMeshProUGUI _label;

		[SerializeField]
		private Image _activeImage;

		[SerializeField]
		private Color _selectColor = Color.green;

		[SerializeField]
		private Color _hoverColor = Color.blue;

		[SerializeField]
		private Color _normalColor = Color.red;

		[SerializeField]
		private Color _disabledColor = Color.grey;

		private const string OBJNAME_FORMAT = "<color=#dddddd><size=85%>{0}</size></color>";

		private ITreeNode<IInteractor> _boundNode;

		private bool _isRoot;

		private bool _isDuplicate;

		public RectTransform ChildArea => _childArea;

		public void Bind(ITreeNode<IInteractor> node, bool isRoot, bool isDuplicate)
		{
			_isRoot = isRoot;
			_isDuplicate = isDuplicate;
			_boundNode = node;
			_label.text = GetLabelText(node);
		}

		protected virtual void Start()
		{
		}

		protected virtual void Update()
		{
			switch (_boundNode.Value.State)
			{
			case InteractorState.Select:
				_activeImage.color = _selectColor;
				break;
			case InteractorState.Hover:
				_activeImage.color = _hoverColor;
				break;
			case InteractorState.Normal:
				_activeImage.color = _normalColor;
				break;
			case InteractorState.Disabled:
				_activeImage.color = _disabledColor;
				break;
			}
			_childArea.gameObject.SetActive(_childArea.childCount > 0);
			_connectingLine.gameObject.SetActive(!_isRoot);
		}

		private string GetLabelText(ITreeNode<IInteractor> node)
		{
			string text = (_isDuplicate ? "<i>" : "");
			if (node.Value is UnityEngine.Object obj)
			{
				text = text + obj.name + " - ";
			}
			return text + $"<color=#dddddd><size=85%>{node.Value.GetType().Name}</size></color>";
		}
	}
}
namespace Oculus.Interaction.Surfaces
{
	public class AxisAlignedBox : MonoBehaviour, ISurface
	{
		private enum BoxSurface
		{
			XMin,
			YMin,
			ZMin,
			XMax,
			YMax,
			ZMax
		}

		[SerializeField]
		[Tooltip("Size of the axis-aligned box, default to mesh size")]
		private Vector3 _size = new Vector3(0f, 0f, 0f);

		private readonly Dictionary<BoxSurface, float> _distances = new Dictionary<BoxSurface, float>
		{
			{
				BoxSurface.XMin,
				0f
			},
			{
				BoxSurface.YMin,
				0f
			},
			{
				BoxSurface.ZMin,
				0f
			},
			{
				BoxSurface.XMax,
				0f
			},
			{
				BoxSurface.YMax,
				0f
			},
			{
				BoxSurface.ZMax,
				0f
			}
		};

		public Vector3 Size
		{
			get
			{
				return _size;
			}
			set
			{
				_size = value;
			}
		}

		public Transform Transform => base.transform;

		public Bounds Bounds => new Bounds(base.transform.position, _size);

		public bool ClosestSurfacePoint(in Vector3 point, out SurfaceHit hit, float maxDistance)
		{
			hit = default(SurfaceHit);
			Vector3 vector = Vector3.Min(Vector3.Max(point, Bounds.min), Bounds.max);
			BoxSurface boxSurface = FindClosestBoxSide(point);
			hit.Normal = ClosestSurfaceNormal(point, boxSurface);
			if (!IsWithinVolume(point))
			{
				hit.Point = vector;
				hit.Distance = (point - vector).magnitude;
				if (!(maxDistance <= 0f))
				{
					return hit.Distance <= maxDistance;
				}
				return true;
			}
			switch (boxSurface)
			{
			case BoxSurface.XMin:
				vector.x = Bounds.min.x;
				break;
			case BoxSurface.YMin:
				vector.y = Bounds.min.y;
				break;
			case BoxSurface.ZMin:
				vector.z = Bounds.min.z;
				break;
			case BoxSurface.XMax:
				vector.x = Bounds.max.x;
				break;
			case BoxSurface.YMax:
				vector.y = Bounds.max.y;
				break;
			case BoxSurface.ZMax:
				vector.z = Bounds.max.z;
				break;
			}
			hit.Point = vector;
			hit.Distance = Vector3.Distance(hit.Point, point);
			if (maxDistance > 0f && hit.Distance > maxDistance)
			{
				return false;
			}
			return true;
		}

		public bool Raycast(in Ray ray, out SurfaceHit hit, float maxDistance)
		{
			hit = default(SurfaceHit);
			Vector3 b = new Vector3(1f / ray.direction.x, 1f / ray.direction.y, 1f / ray.direction.z);
			Vector3 vector = Vector3.Scale(Bounds.min - ray.origin, b);
			Vector3 vector2 = Vector3.Scale(Bounds.max - ray.origin, b);
			float num = Mathf.Max(Mathf.Max(Mathf.Min(vector.x, vector2.x), Mathf.Min(vector.y, vector2.y)), Mathf.Min(vector.z, vector2.z));
			float num2 = Mathf.Min(Mathf.Min(Mathf.Max(vector.x, vector2.x), Mathf.Max(vector.y, vector2.y)), Mathf.Max(vector.z, vector2.z));
			if (num2 < 0f)
			{
				hit.Distance = num2;
				return false;
			}
			if (num > num2)
			{
				hit.Distance = num2;
				return false;
			}
			hit.Distance = num;
			if (maxDistance > 0f && hit.Distance > maxDistance)
			{
				return false;
			}
			if (Mathf.Sign(num) != Mathf.Sign(num2))
			{
				hit.Distance = Mathf.Max(num2, num);
			}
			hit.Point = ray.origin + ray.direction * hit.Distance;
			hit.Normal = ClosestSurfaceNormal(hit.Point);
			return true;
		}

		protected void Start()
		{
			if ((bool)GetComponent<MeshFilter>())
			{
				_size = Vector3.Scale(base.transform.localScale, GetComponent<MeshFilter>().mesh.bounds.size);
			}
			if (_size.magnitude == 0f)
			{
				_size = new Vector3(0.1f, 0.1f, 0.1f);
			}
			Size = _size;
		}

		private bool IsWithinVolume(Vector3 point)
		{
			return Bounds.Contains(point);
		}

		private BoxSurface FindClosestBoxSide(Vector3 point)
		{
			Vector3 vector = base.transform.position - point;
			Vector3 extents = Bounds.extents;
			_distances[BoxSurface.XMin] = extents.x - vector.x;
			_distances[BoxSurface.YMin] = extents.y - vector.y;
			_distances[BoxSurface.ZMin] = extents.z - vector.z;
			_distances[BoxSurface.XMax] = extents.x + vector.x;
			_distances[BoxSurface.YMax] = extents.y + vector.y;
			_distances[BoxSurface.ZMax] = extents.z + vector.z;
			BoxSurface boxSurface = BoxSurface.XMin;
			foreach (BoxSurface key in _distances.Keys)
			{
				if (_distances[key] < _distances[boxSurface])
				{
					boxSurface = key;
				}
			}
			return boxSurface;
		}

		private Vector3 ClosestSurfaceNormal(Vector3 point, BoxSurface? side = null)
		{
			return (side ?? FindClosestBoxSide(point)) switch
			{
				BoxSurface.XMin => new Vector3(-1f, 0f, 0f), 
				BoxSurface.YMin => new Vector3(0f, -1f, 0f), 
				BoxSurface.ZMin => new Vector3(0f, 0f, -1f), 
				BoxSurface.XMax => new Vector3(1f, 0f, 0f), 
				BoxSurface.YMax => new Vector3(0f, 1f, 0f), 
				BoxSurface.ZMax => new Vector3(0f, 0f, 1f), 
				_ => throw new NotImplementedException(), 
			};
		}

		bool ISurface.Raycast(in Ray ray, out SurfaceHit hit, float maxDistance)
		{
			return Raycast(in ray, out hit, maxDistance);
		}

		bool ISurface.ClosestSurfacePoint(in Vector3 point, out SurfaceHit hit, float maxDistance)
		{
			return ClosestSurfacePoint(in point, out hit, maxDistance);
		}
	}
