		public Pose ArcOrigin
		{
			get
			{
				Vector3 vector = TeleportArc.PointAtIndex(0);
				Vector3 vector2 = TeleportArc.PointAtIndex(1);
				return new Pose(vector, Quaternion.LookRotation(vector2 - vector));
			}
		}

		public TeleportHit ArcEnd => _arcEnd;

