			if (base.Selector == null)
			{
				base.Selector = _selector as ISelector;
			}
			Hmd = _hmd as IHmd;
			_nativeId = 5507730199525946473uL;
			_computeCandidateTiebreaker = ComputeCandidateTiebreaker;
		}

		protected override void Start()
		{
			this.BeginStart(ref _started, delegate
			{
				base.Start();
			});
			if (TeleportArc == null)
			{
				TeleportArcGravity teleportArc = base.gameObject.AddComponent<TeleportArcGravity>();
				InjectOptionalTeleportArc(teleportArc);
			}
			if (_computeCandidate == null)
			{
				GameObject gameObject = new GameObject("Default CandidateComputer");
				TeleportCandidateComputer teleportCandidateComputer = gameObject.AddComponent<TeleportCandidateComputer>();
				teleportCandidateComputer.EqualDistanceThreshold = _equalDistanceThreshold;
				if (Hmd != null)
				{
					gameObject.AddComponent<HmdOffset>().InjectAllHmdOffset(Hmd);
					teleportCandidateComputer.BlockCheckOrigin = gameObject.transform;
