				}
				else if ((anchorMode & GrabTypeFlags.Palm) != GrabTypeFlags.None && handGrabInteractor.PalmPoint != null)
				{
					offset = PoseUtils.Delta(in pose, handGrabInteractor.PalmPoint.GetPose());
				}
			}
		}
	}
