	public static class HandGrabStateExtensions
	{
		public static Pose GetVisualWristPose(this IHandGrabState grabState)
		{
			if (grabState.HandGrabTarget.HandPose != null)
			{
				return grabState.HandGrabTarget.GetWorldPoseDisplaced(Pose.identity);
			}
			Pose result = Pose.identity;
			PoseUtils.Inverse(grabState.WristToGrabPoseOffset, ref result);
			return grabState.HandGrabTarget.GetWorldPoseDisplaced(in result);
		}

		public static Pose GetTargetGrabPose(this IHandGrabState grabState)
		{
			if (grabState.HandGrabTarget.HandPose != null)
			{
				return grabState.HandGrabTarget.GetWorldPoseDisplaced(grabState.WristToGrabPoseOffset);
			}
			return grabState.HandGrabTarget.GetWorldPoseDisplaced(Pose.identity);
		}
	}
	public class HandGrabUseInteractable : Interactable<HandGrabUseInteractor, HandGrabUseInteractable>
	{
		[SerializeField]
		[Interface(typeof(IHandGrabUseDelegate), new Type[] { })]
		[Optional(OptionalAttribute.Flag.DontHide)]
		private UnityEngine.Object _handUseDelegate;

		[SerializeField]
		private GrabbingRule _useFingers;

		[SerializeField]
		[Range(0f, 1f)]
		private float _strengthDeadzone = 0.2f;

		[SerializeField]
		[Optional(OptionalAttribute.Flag.DontHide)]
		private List<HandGrabPose> _relaxedHandGrabPoses = new List<HandGrabPose>();

		[SerializeField]
		[Optional(OptionalAttribute.Flag.DontHide)]
		private List<HandGrabPose> _tightHandGrabPoses = new List<HandGrabPose>();

		private IHandGrabUseDelegate HandUseDelegate { get; set; }

		public GrabbingRule UseFingers
		{
			get
			{
				return _useFingers;
			}
			set
			{
				_useFingers = value;
			}
		}

		public float StrengthDeadzone
		{
			get
			{
				return _strengthDeadzone;
			}
			set
			{
				_strengthDeadzone = value;
			}
		}

		public float UseProgress { get; private set; }

		public List<HandGrabPose> RelaxGrabPoints => _relaxedHandGrabPoses;

		public List<HandGrabPose> TightGrabPoints => _tightHandGrabPoses;

		public float UseStrengthDeadZone => _strengthDeadzone;

		protected virtual void Reset()
		{
			HandGrabInteractable componentInParent = GetComponentInParent<HandGrabInteractable>();
			if (componentInParent != null)
			{
				_relaxedHandGrabPoses = new List<HandGrabPose>(componentInParent.HandGrabPoses);
			}
		}

		protected override void Awake()
		{
			base.Awake();
			HandUseDelegate = _handUseDelegate as IHandGrabUseDelegate;
		}

		protected override void SelectingInteractorAdded(HandGrabUseInteractor interactor)
		{
			base.SelectingInteractorAdded(interactor);
			HandUseDelegate?.BeginUse();
		}

		protected override void SelectingInteractorRemoved(HandGrabUseInteractor interactor)
		{
			base.SelectingInteractorRemoved(interactor);
			HandUseDelegate?.EndUse();
		}

		public float ComputeUseStrength(float strength)
		{
			UseProgress = ((HandUseDelegate != null) ? HandUseDelegate.ComputeUseStrength(strength) : strength);
			return UseProgress;
		}

		public bool FindBestHandPoses(float handScale, ref HandPose relaxedHandPose, ref HandPose tightHandPose, out float score)
		{
			if (FindScaledHandPose(_relaxedHandGrabPoses, handScale, ref relaxedHandPose) && FindScaledHandPose(_tightHandGrabPoses, handScale, ref tightHandPose))
			{
				score = 1f;
				return true;
			}
			score = 0f;
			return false;
		}

		private bool FindScaledHandPose(List<HandGrabPose> _handGrabPoses, float handScale, ref HandPose handPose)
		{
			if (_handGrabPoses.Count == 1 && _handGrabPoses[0].HandPose != null)
			{
				handPose.CopyFrom(_handGrabPoses[0].HandPose);
				return true;
			}
			if (_handGrabPoses.Count > 1)
			{
				GrabPoseFinder.FindInterpolationRange(handScale / base.transform.lossyScale.x, _handGrabPoses, out var from, out var to, out var t);
				if (from.HandPose != null && to.HandPose != null)
				{
					HandPose.Lerp(from.HandPose, to.HandPose, t, ref handPose);
					return true;
				}
				if (from.HandPose != null)
				{
					handPose.CopyFrom(from.HandPose);
					return true;
				}
				if (to.HandPose != null)
				{
					handPose.CopyFrom(to.HandPose);
					return true;
				}
				return false;
			}
			return false;
		}

		public void InjectOptionalForwardUseDelegate(IHandGrabUseDelegate useDelegate)
		{
			_handUseDelegate = useDelegate as UnityEngine.Object;
			HandUseDelegate = useDelegate;
		}

		public void InjectOptionalRelaxedHandGrabPoints(List<HandGrabPose> relaxedHandGrabPoints)
		{
			_relaxedHandGrabPoses = relaxedHandGrabPoints;
		}

		public void InjectOptionalTightHandGrabPoints(List<HandGrabPose> tightHandGrabPoints)
		{
			_tightHandGrabPoses = tightHandGrabPoints;
		}
	}
	public class HandGrabUseInteractor : Interactor<HandGrabUseInteractor, HandGrabUseInteractable>, IHandGrabState
	{
		[Tooltip("The hand to use.")]
		[SerializeField]
		[Optional]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _hand;

		[Tooltip("API that gets the finger use strength.")]
		[SerializeField]
		[Interface(typeof(IFingerUseAPI), new Type[] { })]
		private UnityEngine.Object _useAPI;

		private HandPose _relaxedHandPose = new HandPose();

		private HandPose _tightHandPose = new HandPose();

		private HandPose _cachedRelaxedHandPose = new HandPose();

		private HandPose _cachedTightHandPose = new HandPose();

		private Oculus.Interaction.Input.HandFingerFlags _fingersInUse;

		private float[] _fingerUseStrength = new float[5];

		private bool _usesHandPose;

		private bool _handUseShouldSelect;

		private bool _handUseShouldUnselect;

		public IHand Hand { get; private set; }

		public IFingerUseAPI UseAPI { get; private set; }

		public HandGrabTarget HandGrabTarget { get; } = new HandGrabTarget();

		public bool IsGrabbing => base.SelectedInteractable != null;

		public float WristStrength => 0f;

		public float FingersStrength
		{
			get
			{
				if (!IsGrabbing)
				{
					return 0f;
				}
				return 1f;
			}
		}

		public Pose WristToGrabPoseOffset => Pose.identity;

		public Action<IHandGrabState> WhenHandGrabStarted { get; set; } = delegate
		{
		};

		public Action<IHandGrabState> WhenHandGrabEnded { get; set; } = delegate
		{
		};

		protected override bool ComputeShouldSelect()
		{
			return _handUseShouldSelect;
		}

		protected override bool ComputeShouldUnselect()
		{
			if (!_handUseShouldUnselect)
			{
				return base.SelectedInteractable == null;
			}
			return true;
		}

		protected override void Awake()
		{
			base.Awake();
			Hand = _hand as IHand;
			UseAPI = _useAPI as IFingerUseAPI;
			_nativeId = 5208257256664429413uL;
		}

		protected override void Start()
		{
			this.BeginStart(ref _started, delegate
			{
				base.Start();
			});
			this.EndStart(ref _started);
		}

		protected override void InteractableSelected(HandGrabUseInteractable interactable)
		{
			base.InteractableSelected(interactable);
			StartUsing();
		}

		protected override void InteractableUnselected(HandGrabUseInteractable interactable)
		{
			base.InteractableUnselected(interactable);
			_fingersInUse = Oculus.Interaction.Input.HandFingerFlags.None;
		}

		private void StartUsing()
		{
			HandGrabResult handGrabResult = new HandGrabResult
			{
				HasHandPose = true,
				HandPose = _relaxedHandPose
			};
			HandGrabTarget.Set(base.SelectedInteractable.transform, HandAlignType.AlignOnGrab, GrabTypeFlags.None, handGrabResult);
		}

		protected override void DoHoverUpdate()
		{
			base.DoHoverUpdate();
			_handUseShouldSelect = IsUsingInteractable(base.Interactable);
		}

		protected override void DoSelectUpdate()
		{
			base.DoSelectUpdate();
			if (!(base.SelectedInteractable == null))
			{
				float strength = CalculateUseStrength(ref _fingerUseStrength);
				float useProgress = base.SelectedInteractable.ComputeUseStrength(strength);
				_handUseShouldUnselect = !IsUsingInteractable(base.Interactable);
				if (_usesHandPose && !_handUseShouldUnselect)
				{
					MoveFingers(ref _fingerUseStrength, useProgress);
				}
			}
		}

		private bool IsUsingInteractable(HandGrabUseInteractable interactable)
		{
			if (interactable == null)
			{
				return false;
			}
			for (int i = 0; i < 5; i++)
			{
				Oculus.Interaction.Input.HandFinger handFinger = (Oculus.Interaction.Input.HandFinger)i;
				if (interactable.UseFingers[handFinger] != FingerRequirement.Ignored && UseAPI.GetFingerUseStrength(handFinger) > interactable.StrengthDeadzone)
				{
					return true;
				}
			}
			return false;
		}

		private float CalculateUseStrength(ref float[] fingerUseStrength)
		{
			float num = 1f;
			float num2 = 0f;
			bool flag = false;
			for (int i = 0; i < 5; i++)
			{
				Oculus.Interaction.Input.HandFinger handFinger = (Oculus.Interaction.Input.HandFinger)i;
				if (base.SelectedInteractable.UseFingers[handFinger] == FingerRequirement.Ignored)
				{
					fingerUseStrength[i] = 0f;
					continue;
				}
				float fingerUseStrength2 = UseAPI.GetFingerUseStrength(handFinger);
				fingerUseStrength[i] = Mathf.Clamp01((fingerUseStrength2 - base.SelectedInteractable.UseStrengthDeadZone) / (1f - base.SelectedInteractable.UseStrengthDeadZone));
				if (base.SelectedInteractable.UseFingers[handFinger] == FingerRequirement.Required)
				{
					flag = true;
					num = Mathf.Min(num, fingerUseStrength[i]);
				}
				else if (base.SelectedInteractable.UseFingers[handFinger] == FingerRequirement.Optional)
				{
					num2 = Mathf.Max(num2, fingerUseStrength[i]);
				}
				if (fingerUseStrength[i] > 0f)
				{
					MarkFingerInUse(handFinger);
				}
				else
				{
					UnmarkFingerInUse(handFinger);
				}
			}
			if (!flag)
			{
				return num2;
			}
			return num;
		}

		private void MoveFingers(ref float[] fingerUseProgress, float useProgress)
		{
			for (int i = 0; i < 5; i++)
			{
				Oculus.Interaction.Input.HandFinger finger = (Oculus.Interaction.Input.HandFinger)i;
				float t = Mathf.Min(useProgress, fingerUseProgress[i]);
				LerpFingerRotation(_relaxedHandPose.JointRotations, _tightHandPose.JointRotations, HandGrabTarget.HandPose.JointRotations, finger, t);
			}
		}

		private void MarkFingerInUse(Oculus.Interaction.Input.HandFinger finger)
		{
			_fingersInUse |= (Oculus.Interaction.Input.HandFingerFlags)(1 << (int)finger);
		}

		private void UnmarkFingerInUse(Oculus.Interaction.Input.HandFinger finger)
		{
			_fingersInUse &= (Oculus.Interaction.Input.HandFingerFlags)(~(1 << (int)finger));
		}

		private void LerpFingerRotation(Quaternion[] from, Quaternion[] to, Quaternion[] result, Oculus.Interaction.Input.HandFinger finger, float t)
		{
			int[] array = FingersMetadata.FINGER_TO_JOINT_INDEX[(int)finger];
			foreach (int num in array)
			{
				result[num] = Quaternion.Slerp(from[num], to[num], t);
			}
		}

		public Oculus.Interaction.Input.HandFingerFlags GrabbingFingers()
		{
			return _fingersInUse;
		}

		protected override HandGrabUseInteractable ComputeCandidate()
		{
			float num = float.NegativeInfinity;
			HandGrabUseInteractable result = null;
			_usesHandPose = false;
			foreach (HandGrabUseInteractable item in Interactable<HandGrabUseInteractor, HandGrabUseInteractable>.Registry.List(this))
			{
				item.FindBestHandPoses((Hand != null) ? Hand.Scale : 1f, ref _cachedRelaxedHandPose, ref _cachedTightHandPose, out var score);
				if (score > num)
				{
					num = score;
					result = item;
					_relaxedHandPose.CopyFrom(_cachedRelaxedHandPose);
					_tightHandPose.CopyFrom(_cachedTightHandPose);
					_usesHandPose = true;
				}
			}
			return result;
		}

		public void InjectAllHandGrabUseInteractor(IFingerUseAPI useApi)
		{
			InjectUseApi(useApi);
		}

		public void InjectUseApi(IFingerUseAPI useApi)
		{
			_useAPI = useApi as UnityEngine.Object;
			UseAPI = useApi;
		}

		public void InjectOptionalHand(IHand hand)
		{
			_hand = hand as UnityEngine.Object;
			Hand = hand;
		}
	}
	public interface IHandGrabUseDelegate
	{
		void BeginUse();

		void EndUse();

		float ComputeUseStrength(float strength);
	}
