	public class DistantInteractionTubeVisual : DistantInteractionLineVisual
	{
		[SerializeField]
		private TubeRenderer _tubeRenderer;

		private TubePoint[] _tubePoints;

		protected override void Start()
		{
			base.Start();
		}

		protected override void RenderLine(Vector3[] linePoints)
		{
			InitializeArcPoints(linePoints);
			_tubeRenderer.RenderTube(_tubePoints, Space.World);
		}

		protected override void HideLine()
		{
			_tubeRenderer.Hide();
		}

		private void InitializeArcPoints(Vector3[] linePoints)
		{
			if (_tubePoints == null || _tubePoints.Length < linePoints.Length)
			{
				_tubePoints = new TubePoint[linePoints.Length];
			}
			float num = 0f;
			for (int i = 1; i < linePoints.Length; i++)
			{
				num += (linePoints[i] - linePoints[i - 1]).magnitude;
			}
			for (int j = 0; j < linePoints.Length; j++)
			{
				Vector3 forward = ((j == 0) ? (linePoints[j + 1] - linePoints[j]) : (linePoints[j] - linePoints[j - 1]));
				_tubePoints[j].position = linePoints[j];
				_tubePoints[j].rotation = Quaternion.LookRotation(forward);
				_tubePoints[j].relativeLength = ((j == 0) ? 0f : (_tubePoints[j - 1].relativeLength + forward.magnitude / num));
			}
		}

		public void InjectAllDistantInteractionPolylineVisual(IDistanceInteractor interactor)
		{
			InjectDistanceInteractor(interactor);
		}
	}
	public abstract class InteractorReticle<TReticleData> : MonoBehaviour where TReticleData : class, IReticleData
	{
		[Tooltip("Should the reticle be visible when you're selecting an object?")]
		[SerializeField]
		private bool _visibleDuringSelect;

		protected bool _started;

		protected TReticleData _targetData;

		private bool _drawn;

		public bool VisibleDuringSelect
		{
			get
			{
				return _visibleDuringSelect;
			}
			set
			{
				_visibleDuringSelect = value;
			}
		}

		protected abstract IInteractorView Interactor { get; set; }

		protected abstract UnityEngine.Component InteractableComponent { get; }

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			Hide();
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Interactor.WhenStateChanged += HandleStateChanged;
				Interactor.WhenPostprocessed += HandlePostProcessed;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Interactor.WhenStateChanged -= HandleStateChanged;
				Interactor.WhenPostprocessed -= HandlePostProcessed;
			}
		}

		private void HandleStateChanged(InteractorStateChangeArgs args)
		{
			if (args.NewState == InteractorState.Normal || args.NewState == InteractorState.Disabled)
			{
				InteractableUnset();
			}
			else if (args.NewState == InteractorState.Hover && args.PreviousState != InteractorState.Select)
			{
				InteractableSet(InteractableComponent);
			}
		}

		private void HandlePostProcessed()
		{
			if (_targetData != null && (Interactor.State == InteractorState.Hover || (Interactor.State == InteractorState.Select && _visibleDuringSelect)))
			{
				if (!_drawn)
				{
					_drawn = true;
					Draw(_targetData);
				}
				Align(_targetData);
			}
			else if (_drawn)
			{
				_drawn = false;
				Hide();
			}
		}

		private void InteractableSet(UnityEngine.Component interactable)
		{
			if (interactable != null && interactable.TryGetComponent<TReticleData>(out _targetData))
			{
				_drawn = false;
			}
			else
			{
				_targetData = null;
			}
		}

		private void InteractableUnset()
		{
