namespace Oculus.Interaction.Body
{
	public class BodyDebugGizmos : SkeletonDebugGizmos
	{
		public enum CoordSpace
		{
			World,
			Local
		}

		[SerializeField]
		[Interface(typeof(IBody), new Type[] { })]
		private UnityEngine.Object _body;

		private IBody Body;

		[Tooltip("The coordinate space in which to draw the skeleton. World space draws the skeleton at the world Body location. Local draws the skeleton relative to this transform's position, and can be placed, scaled, or mirrored as desired.")]
		[SerializeField]
		private CoordSpace _space;

		protected bool _started;

		public CoordSpace Space
		{
			get
			{
				return _space;
			}
			set
			{
				_space = value;
			}
		}

		protected virtual void Awake()
		{
			Body = _body as IBody;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				Body.WhenBodyUpdated += HandleBodyUpdated;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				Body.WhenBodyUpdated -= HandleBodyUpdated;
			}
		}

		protected override bool TryGetJointPose(int jointId, out Pose pose)
		{
			CoordSpace space = _space;
			bool result;
			if (space == CoordSpace.World || space != CoordSpace.Local)
			{
				result = Body.GetJointPose((BodyJointId)jointId, out pose);
			}
			else
			{
				result = Body.GetJointPoseFromRoot((BodyJointId)jointId, out pose);
				pose.position = base.transform.TransformPoint(pose.position);
				pose.rotation = base.transform.rotation * pose.rotation;
			}
			return result;
		}

		protected override bool TryGetParentJointId(int jointId, out int parent)
		{
			if (Body.SkeletonMapping.TryGetParentJointId((BodyJointId)jointId, out var parent2))
			{
				parent = (int)parent2;
				return true;
			}
			parent = 0;
			return false;
		}

		private VisibilityFlags GetModifiedDrawFlags()
		{
			VisibilityFlags visibilityFlags = base.Visibility;
			if (base.HasNegativeScale && Space == CoordSpace.Local)
			{
				visibilityFlags &= ~VisibilityFlags.Axes;
			}
			return visibilityFlags;
		}

		private void HandleBodyUpdated()
		{
			foreach (BodyJointId joint in Body.SkeletonMapping.Joints)
			{
				Draw((int)joint, GetModifiedDrawFlags());
			}
		}

		public void InjectAllBodyJointDebugGizmos(IBody body)
		{
			InjectBody(body);
		}

		public void InjectBody(IBody body)
		{
			_body = body as UnityEngine.Object;
			Body = body;
		}
	}
}
namespace Oculus.Interaction.Body.PoseDetection
{
	public class BodyPoseComparerActiveState : MonoBehaviour, IActiveState, ITimeConsumer
	{
		public struct BodyPoseComparerFeatureState(float delta, float maxDelta)
		{
			public readonly float Delta = delta;

			public readonly float MaxDelta = maxDelta;
		}

		[Serializable]
		public class JointComparerConfig
		{
			[Tooltip("The joint to compare from each Body Pose")]
			public BodyJointId Joint = BodyJointId.Body_Head;

			[Min(0f)]
			[Tooltip("The maximum angle that two joint rotations can be from each other to be considered equal.")]
			public float MaxDelta = 30f;

			[Tooltip("The width of the threshold when transitioning states. Width / 2 is added to MaxDelta when leaving Active state, and subtracted when entering.")]
			[Min(0f)]
			public float Width = 4f;
		}

		[Tooltip("The first body pose to compare.")]
		[SerializeField]
		[Interface(typeof(IBodyPose), new Type[] { })]
		private UnityEngine.Object _poseA;

		private IBodyPose PoseA;

		[Tooltip("The second body pose to compare.")]
		[SerializeField]
		[Interface(typeof(IBodyPose), new Type[] { })]
		private UnityEngine.Object _poseB;

		private IBodyPose PoseB;

		[SerializeField]
		private List<JointComparerConfig> _configs = new List<JointComparerConfig>
		{
			new JointComparerConfig()
		};

		[Tooltip("A new state must be maintaned for at least this many seconds before the Active property changes.")]
		[SerializeField]
		private float _minTimeInState = 0.05f;

		private Func<float> _timeProvider = () => Time.time;

		private Dictionary<JointComparerConfig, BodyPoseComparerFeatureState> _featureStates = new Dictionary<JointComparerConfig, BodyPoseComparerFeatureState>();

		private bool _isActive;

		private bool _internalActive;

		private float _lastStateChangeTime;

		public float MinTimeInState
		{
			get
			{
				return _minTimeInState;
			}
			set
			{
				_minTimeInState = value;
			}
		}

		public IReadOnlyDictionary<JointComparerConfig, BodyPoseComparerFeatureState> FeatureStates => _featureStates;

		public bool Active
		{
			get
			{
				if (!base.isActiveAndEnabled)
				{
					return false;
				}
				bool internalActive = _internalActive;
				_internalActive = true;
				foreach (JointComparerConfig config in _configs)
				{
					float num = (internalActive ? (config.MaxDelta + config.Width / 2f) : (config.MaxDelta - config.Width / 2f));
					float delta;
					bool flag = GetJointDelta(config.Joint, out delta) && Mathf.Abs(delta) <= num;
					_featureStates[config] = new BodyPoseComparerFeatureState(delta, num);
					_internalActive &= flag;
				}
				float num2 = _timeProvider();
				if (internalActive != _internalActive)
				{
					_lastStateChangeTime = num2;
				}
				if (num2 - _lastStateChangeTime >= _minTimeInState)
				{
					_isActive = _internalActive;
				}
				return _isActive;
			}
		}

		public void SetTimeProvider(Func<float> timeProvider)
		{
			_timeProvider = timeProvider;
		}

		protected virtual void Awake()
		{
			PoseA = _poseA as IBodyPose;
			PoseB = _poseB as IBodyPose;
		}

		protected virtual void Start()
		{
		}

		private bool GetJointDelta(BodyJointId joint, out float delta)
		{
			if (!PoseA.GetJointPoseLocal(joint, out var pose) || !PoseB.GetJointPoseLocal(joint, out var pose2))
			{
				delta = 0f;
				return false;
			}
			delta = Quaternion.Angle(pose.rotation, pose2.rotation);
			return true;
		}

		public void InjectAllBodyPoseComparerActiveState(IBodyPose poseA, IBodyPose poseB, IEnumerable<JointComparerConfig> configs)
		{
			InjectPoseA(poseA);
			InjectPoseB(poseB);
			InjectJoints(configs);
		}

		public void InjectPoseA(IBodyPose poseA)
		{
			_poseA = poseA as UnityEngine.Object;
			PoseA = poseA;
		}

		public void InjectPoseB(IBodyPose poseB)
		{
			_poseB = poseB as UnityEngine.Object;
			PoseB = poseB;
		}

		public void InjectJoints(IEnumerable<JointComparerConfig> configs)
		{
			_configs = new List<JointComparerConfig>(configs);
		}

		[Obsolete("Use SetTimeProvider()")]
		public void InjectOptionalTimeProvider(Func<float> timeProvider)
		{
			_timeProvider = timeProvider;
		}
	}
	public class BodyPoseComparerActiveStateDebugVisual : MonoBehaviour
	{
		[Tooltip("The PoseComparer to debug.")]
		[SerializeField]
		private BodyPoseComparerActiveState _bodyPoseComparer;

		[Tooltip("The body pose to overlay onto. This gizmo simply draws gizmos at joint locations - you must provide a body pose in order for this component to place the gizmos accurately.")]
		[SerializeField]
		[Interface(typeof(IBodyPose), new Type[] { })]
		private UnityEngine.Object _bodyPose;

		private IBodyPose BodyPose;

		[Tooltip("The root transform of the body on which to overlay the spheres. For BodyPoseDebugGizmos, this is simply the transform of the component. For a skinned body model, this would be the Root transform.")]
		[SerializeField]
		private Transform _root;

		[Tooltip("The radius of the debug spheres.")]
		[SerializeField]
		[Delayed]
		private float _radius = 0.1f;

		public float Radius
		{
			get
			{
				return _radius;
			}
			set
			{
				_radius = value;
			}
		}

		protected virtual void Awake()
		{
			BodyPose = _bodyPose as IBodyPose;
		}

		protected virtual void Start()
		{
		}

		protected virtual void Update()
		{
			DrawJointSpheres();
		}

		private void DrawJointSpheres()
		{
			foreach (KeyValuePair<BodyPoseComparerActiveState.JointComparerConfig, BodyPoseComparerActiveState.BodyPoseComparerFeatureState> featureState in _bodyPoseComparer.FeatureStates)
			{
				BodyJointId joint = featureState.Key.Joint;
				BodyPoseComparerActiveState.BodyPoseComparerFeatureState value = featureState.Value;
				if (BodyPose.GetJointPoseFromRoot(joint, out var pose))
				{
					Vector3 p = _root.TransformPoint(pose.position);
					Color color = ((value.Delta <= value.MaxDelta) ? Color.green : ((!(value.MaxDelta > 0f)) ? Color.red : Color.Lerp(t: value.Delta / value.MaxDelta / 2f, a: Color.yellow, b: Color.red)));
					DebugGizmos.LineWidth = _radius / 2f;
					DebugGizmos.Color = color;
					DebugGizmos.DrawPoint(p);
				}
			}
		}

		public void InjectAllBodyPoseComparerActiveStateDebugVisual(BodyPoseComparerActiveState bodyPoseComparer, IBodyPose bodyPose, Transform root)
		{
			InjectBodyPoseComparer(bodyPoseComparer);
			InjectBodyPose(bodyPose);
			InjectRootTransform(root);
		}

		public void InjectRootTransform(Transform root)
		{
			_root = root;
		}

		public void InjectBodyPoseComparer(BodyPoseComparerActiveState bodyPoseComparer)
		{
			_bodyPoseComparer = bodyPoseComparer;
		}

		public void InjectBodyPose(IBodyPose bodyPose)
		{
			_bodyPose = bodyPose as UnityEngine.Object;
			BodyPose = bodyPose;
		}
	}
	[CreateAssetMenu(menuName = "Meta/Interaction/SDK/Pose Detection/Body Pose")]
	public class BodyPoseData : ScriptableObject, IBodyPose, ISerializationCallbackReceiver
	{
		[Serializable]
		internal struct JointData
		{
			public BodyJointId JointId;

			public BodyJointId ParentId;

			public Pose PoseFromRoot;

			public Pose LocalPose;
		}

		private class Mapping : ISkeletonMapping
		{
			public EnumerableHashSet<BodyJointId> Joints = new EnumerableHashSet<BodyJointId>();

			public Dictionary<BodyJointId, BodyJointId> JointToParent = new Dictionary<BodyJointId, BodyJointId>();

			IEnumerableHashSet<BodyJointId> ISkeletonMapping.Joints => Joints;

			bool ISkeletonMapping.TryGetParentJointId(BodyJointId jointId, out BodyJointId parent)
			{
				return JointToParent.TryGetValue(jointId, out parent);
			}
		}

		internal const int DATA_VERSION = 1;

		[SerializeField]
		[HideInInspector]
		private int _serializedVersion;

		[SerializeField]
		[HideInInspector]
		private List<JointData> _jointData = new List<JointData>();

		private Dictionary<BodyJointId, Pose> _posesFromRoot = new Dictionary<BodyJointId, Pose>();

		private Dictionary<BodyJointId, Pose> _localPoses = new Dictionary<BodyJointId, Pose>();

		private Mapping _mapping = new Mapping();

		public ISkeletonMapping SkeletonMapping => _mapping;

		public event Action WhenBodyPoseUpdated = delegate
		{
		};

		public bool GetJointPoseFromRoot(BodyJointId bodyJointId, out Pose pose)
		{
			return _posesFromRoot.TryGetValue(bodyJointId, out pose);
		}

		public bool GetJointPoseLocal(BodyJointId bodyJointId, out Pose pose)
		{
			return _localPoses.TryGetValue(bodyJointId, out pose);
		}

		public void SetBodyPose(IBody body)
		{
			_jointData.Clear();
			foreach (BodyJointId joint in body.SkeletonMapping.Joints)
			{
				if (body.GetJointPoseLocal(joint, out var pose) && body.GetJointPoseFromRoot(joint, out var pose2) && body.SkeletonMapping.TryGetParentJointId(joint, out var parent))
				{
					_jointData.Add(new JointData
					{
						JointId = joint,
						ParentId = parent,
						PoseFromRoot = pose2,
						LocalPose = pose
					});
				}
			}
			_serializedVersion = 1;
			Rebuild();
			this.WhenBodyPoseUpdated();
		}

		public void OnBeforeSerialize()
		{
		}

		public void OnAfterDeserialize()
		{
			Rebuild();
		}

		private void Rebuild()
		{
			_localPoses.Clear();
			_posesFromRoot.Clear();
			_mapping.Joints.Clear();
			_mapping.JointToParent.Clear();
			for (int i = 0; i < _jointData.Count; i++)
			{
				_localPoses[_jointData[i].JointId] = _jointData[i].LocalPose;
				_posesFromRoot[_jointData[i].JointId] = _jointData[i].PoseFromRoot;
				_mapping.Joints.Add(_jointData[i].JointId);
				_mapping.JointToParent.Add(_jointData[i].JointId, _jointData[i].ParentId);
			}
		}
	}
