	public class ReadOnlyBodyJointPoses : IReadOnlyList<Pose>, IEnumerable<Pose>, IEnumerable, IReadOnlyCollection<Pose>
	{
		private Pose[] _poses;

		public static ReadOnlyBodyJointPoses Empty { get; } = new ReadOnlyBodyJointPoses(Array.Empty<Pose>());

		public int Count => _poses.Length;

		public Pose this[int index] => _poses[index];

		public ref readonly Pose this[BodyJointId index] => ref _poses[(int)index];

		public ReadOnlyBodyJointPoses(Pose[] poses)
		{
			_poses = poses;
		}

		public IEnumerator<Pose> GetEnumerator()
		{
			Pose[] poses = _poses;
			for (int i = 0; i < poses.Length; i++)
			{
				yield return poses[i];
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
	public abstract class BodySkeletonMapping<TSourceJointId> : ISkeletonMapping where TSourceJointId : Enum
	{
		private class SkeletonTree
		{
			public class Node
			{
				public readonly TSourceJointId SourceJointId;

				public readonly BodyJointId BodyJointId;

				public Node Parent;

				public List<Node> Children = new List<Node>();

				public Node(TSourceJointId sourceJointId, BodyJointId bodyJointId)
				{
					SourceJointId = sourceJointId;
					BodyJointId = bodyJointId;
				}
			}

			public readonly Node Root;

			public readonly IReadOnlyList<Node> Nodes;

			public SkeletonTree(TSourceJointId root, IReadOnlyDictionary<BodyJointId, JointInfo> mapping)
			{
				Dictionary<TSourceJointId, Node> dictionary = new Dictionary<TSourceJointId, Node>();
				foreach (KeyValuePair<BodyJointId, JointInfo> item in mapping)
				{
					BodyJointId key = item.Key;
					JointInfo value = item.Value;
					dictionary[value.SourceJointId] = new Node(value.SourceJointId, key);
				}
				foreach (JointInfo value2 in mapping.Values)
				{
					Node node = dictionary[value2.SourceJointId];
					node.Parent = dictionary[value2.ParentJointId];
					node.Parent.Children.Add(node);
				}
				Nodes = new List<Node>(dictionary.Values);
				Root = dictionary[root];
			}
		}

		protected readonly struct JointInfo(TSourceJointId sourceJointId, TSourceJointId parentJointId)
		{
			public readonly TSourceJointId SourceJointId = sourceJointId;

			public readonly TSourceJointId ParentJointId = parentJointId;
		}

		private readonly SkeletonTree _tree;

		private readonly IEnumerableHashSet<BodyJointId> _joints;

		private readonly IReadOnlyDictionary<TSourceJointId, BodyJointId> _forwardMap;

		private readonly IReadOnlyDictionary<BodyJointId, TSourceJointId> _reverseMap;

		private readonly IReadOnlyDictionary<BodyJointId, BodyJointId> _jointToParent;

		public IEnumerableHashSet<BodyJointId> Joints => _joints;

		public bool TryGetParentJointId(BodyJointId jointId, out BodyJointId parentJointId)
		{
			return _jointToParent.TryGetValue(jointId, out parentJointId);
		}

		public bool TryGetSourceJointId(BodyJointId jointId, out TSourceJointId sourceJointId)
		{
			return _reverseMap.TryGetValue(jointId, out sourceJointId);
		}

		public bool TryGetBodyJointId(TSourceJointId jointId, out BodyJointId bodyJointId)
		{
			return _forwardMap.TryGetValue(jointId, out bodyJointId);
		}

		protected TSourceJointId GetSourceJointFromBodyJoint(BodyJointId jointId)
		{
			return _reverseMap[jointId];
		}

		protected BodyJointId GetBodyJointFromSourceJoint(TSourceJointId sourceJointId)
		{
			return _forwardMap[sourceJointId];
		}

		protected BodySkeletonMapping(TSourceJointId root, IReadOnlyDictionary<BodyJointId, JointInfo> jointMapping)
		{
			_tree = new SkeletonTree(root, jointMapping);
			_joints = new EnumerableHashSet<BodyJointId>(_tree.Nodes.Select((SkeletonTree.Node n) => n.BodyJointId));
			_forwardMap = _tree.Nodes.ToDictionary((SkeletonTree.Node n) => n.SourceJointId, (SkeletonTree.Node n) => n.BodyJointId);
			_reverseMap = _tree.Nodes.ToDictionary((SkeletonTree.Node n) => n.BodyJointId, (SkeletonTree.Node n) => n.SourceJointId);
			_jointToParent = _tree.Nodes.ToDictionary((SkeletonTree.Node n) => n.BodyJointId, (SkeletonTree.Node n) => n.Parent.BodyJointId);
		}
	}
	public interface IBody
	{
		ISkeletonMapping SkeletonMapping { get; }

		bool IsConnected { get; }

		bool IsHighConfidence { get; }

		bool IsTrackedDataValid { get; }

		float Scale { get; }

		int CurrentDataVersion { get; }

		event Action WhenBodyUpdated;

		bool GetRootPose(out Pose pose);

		bool GetJointPose(BodyJointId bodyJointId, out Pose pose);

		bool GetJointPoseLocal(BodyJointId bodyJointId, out Pose pose);

		bool GetJointPoseFromRoot(BodyJointId bodyJointId, out Pose pose);
	}
	public interface ISkeletonMapping
	{
		IEnumerableHashSet<BodyJointId> Joints { get; }

		bool TryGetParentJointId(BodyJointId jointId, out BodyJointId parent);
	}
}
namespace Oculus.Interaction.GrabAPI
{
	public class PalmGrabAPI : IFingerAPI
	{
		private class FingerGrabData
		{
			private readonly Oculus.Interaction.Input.HandFinger _fingerID;

			private readonly Vector2 _curlNormalizationParams;

			public float GrabStrength;

			public bool IsGrabbing;

			public bool IsGrabbingChanged { get; private set; }

			public FingerGrabData(Oculus.Interaction.Input.HandFinger fingerId)
			{
				_fingerID = fingerId;
				Vector2 vector = CURL_RANGE[(int)_fingerID];
				_curlNormalizationParams = new Vector2(vector.x, vector.y - vector.x);
			}

			public void UpdateGrabStrength(IHand hand, FingerShapes fingerShapes)
			{
				float num = fingerShapes.GetCurlValue(_fingerID, hand);
				if (_fingerID != Oculus.Interaction.Input.HandFinger.Thumb)
				{
					num = (num * 2f + fingerShapes.GetFlexionValue(_fingerID, hand)) / 3f;
				}
				GrabStrength = Mathf.Clamp01((num - _curlNormalizationParams.x) / _curlNormalizationParams.y);
			}

			public void UpdateIsGrabbing(float startThreshold, float releaseThreshold)
			{
				if (GrabStrength > startThreshold)
				{
					if (!IsGrabbing)
					{
						IsGrabbing = true;
						IsGrabbingChanged = true;
					}
				}
				else if (GrabStrength < releaseThreshold && IsGrabbing)
				{
					IsGrabbing = false;
					IsGrabbingChanged = true;
				}
			}

			public void ClearState()
			{
				IsGrabbingChanged = false;
			}
		}

		private Vector3 _poseVolumeCenterOffset = Vector3.zero;

		private static readonly Vector3 POSE_VOLUME_OFFSET = new Vector3(0.07f, -0.03f, 0f);

		private static readonly float START_THRESHOLD = 0.9f;

		private static readonly float RELEASE_THRESHOLD = 0.6f;

		private static readonly Vector2[] CURL_RANGE = new Vector2[5]
		{
			new Vector2(190f, 220f),
			new Vector2(180f, 250f),
			new Vector2(180f, 250f),
			new Vector2(180f, 250f),
			new Vector2(180f, 245f)
		};

		private FingerShapes _fingerShapes = new FingerShapes();

		private readonly FingerGrabData[] _fingersGrabData = new FingerGrabData[5]
		{
			new FingerGrabData(Oculus.Interaction.Input.HandFinger.Thumb),
			new FingerGrabData(Oculus.Interaction.Input.HandFinger.Index),
			new FingerGrabData(Oculus.Interaction.Input.HandFinger.Middle),
			new FingerGrabData(Oculus.Interaction.Input.HandFinger.Ring),
			new FingerGrabData(Oculus.Interaction.Input.HandFinger.Pinky)
		};

		public bool GetFingerIsGrabbing(Oculus.Interaction.Input.HandFinger finger)
		{
			return _fingersGrabData[(int)finger].IsGrabbing;
		}

		public bool GetFingerIsGrabbingChanged(Oculus.Interaction.Input.HandFinger finger, bool targetGrabState)
		{
			if (_fingersGrabData[(int)finger].IsGrabbingChanged)
			{
				return _fingersGrabData[(int)finger].IsGrabbing == targetGrabState;
			}
			return false;
		}

		public float GetFingerGrabScore(Oculus.Interaction.Input.HandFinger finger)
		{
			return _fingersGrabData[(int)finger].GrabStrength;
		}

		public void Update(IHand hand)
		{
			ClearState();
			if (hand != null && hand.IsTrackedDataValid)
			{
				UpdateVolumeCenter(hand);
				for (int i = 0; i < 5; i++)
				{
					_fingersGrabData[i].UpdateGrabStrength(hand, _fingerShapes);
					_fingersGrabData[i].UpdateIsGrabbing(START_THRESHOLD, RELEASE_THRESHOLD);
				}
			}
		}

		private void UpdateVolumeCenter(IHand hand)
		{
			_poseVolumeCenterOffset = ((hand.Handedness == Oculus.Interaction.Input.Handedness.Left) ? (Oculus.Interaction.Input.Constants.LeftDistal * POSE_VOLUME_OFFSET.x + Oculus.Interaction.Input.Constants.LeftDorsal * POSE_VOLUME_OFFSET.y + Oculus.Interaction.Input.Constants.LeftThumbSide * POSE_VOLUME_OFFSET.z) : (Oculus.Interaction.Input.Constants.RightDistal * POSE_VOLUME_OFFSET.x + Oculus.Interaction.Input.Constants.RightDorsal * POSE_VOLUME_OFFSET.y + Oculus.Interaction.Input.Constants.RightThumbSide * POSE_VOLUME_OFFSET.z));
		}

		private void ClearState()
		{
			for (int i = 0; i < 5; i++)
			{
				_fingersGrabData[i].ClearState();
			}
		}

		public Vector3 GetWristOffsetLocal()
		{
			return _poseVolumeCenterOffset;
		}
	}
	public class PinchGrabAPI : IFingerAPI
	{
		private class FingerPinchData
		{
			private readonly Oculus.Interaction.Input.HandJointId _tipId;

			private float _minPinchDistance;

			public float PinchStrength;

			public bool IsPinching;

			public Vector3 TipPosition { get; private set; }

			public bool IsPinchingChanged { get; private set; }

			public FingerPinchData(Oculus.Interaction.Input.HandFinger fingerId)
			{
				_tipId = Oculus.Interaction.Input.HandJointUtils.GetHandFingerTip(fingerId);
			}

			public void UpdateTipPosition(ShadowHand hand)
			{
				TipPosition = hand.GetWorldPose(_tipId).position;
			}

			public void UpdateIsPinching(float distance, float start, float stopOffset, float stopMax)
			{
				if (!IsPinching)
				{
					if (distance < start)
					{
						IsPinching = true;
						IsPinchingChanged = true;
						_minPinchDistance = distance;
					}
					return;
				}
				_minPinchDistance = Mathf.Min(_minPinchDistance, distance);
				if (distance > stopMax || distance > _minPinchDistance + stopOffset)
				{
					IsPinching = false;
					IsPinchingChanged = true;
					_minPinchDistance = float.MaxValue;
				}
			}

			public void ClearState()
			{
				IsPinchingChanged = false;
			}
		}

		private bool _isPinchVisibilityGood;

		private const float PINCH_DISTANCE_START = 0.02f;

		private const float PINCH_DISTANCE_STOP_MAX = 0.1f;

		private const float PINCH_DISTANCE_STOP_OFFSET = 0.04f;

		private const float PINCH_HQ_DISTANCE_START = 0.016f;

		private const float PINCH_HQ_DISTANCE_STOP_MAX = 0.1f;

		private const float PINCH_HQ_DISTANCE_STOP_OFFSET = 0.016f;

		private const float THUMB_DISTANCE_START = 0.03f;

		private const float THUMB_DISTANCE_STOP_MAX = 0.05f;

		private const float THUMB_DISTANCE_STOP_OFFSET = 0.04f;

		private const float THUMB_MAX_DOT = 0.5f;

		private const float PINCH_HQ_VIEW_ANGLE_THRESHOLD = 40f;

		private readonly Oculus.Interaction.Input.HandJointId[] THUMB_JOINTS_SELECT = new Oculus.Interaction.Input.HandJointId[2]
		{
			Oculus.Interaction.Input.HandJointId.HandThumb3,
			Oculus.Interaction.Input.HandJointId.HandThumbTip
		};

		private readonly Oculus.Interaction.Input.HandJointId[] THUMB_JOINTS_MAINTAIN = new Oculus.Interaction.Input.HandJointId[3]
		{
			Oculus.Interaction.Input.HandJointId.HandThumb2,
			Oculus.Interaction.Input.HandJointId.HandThumb3,
			Oculus.Interaction.Input.HandJointId.HandThumbTip
		};

		private readonly Oculus.Interaction.Input.HandJointId[] INDEX_JOINTS = new Oculus.Interaction.Input.HandJointId[4]
		{
			Oculus.Interaction.Input.HandJointId.HandIndex1,
			Oculus.Interaction.Input.HandJointId.HandIndex2,
			Oculus.Interaction.Input.HandJointId.HandIndex3,
			Oculus.Interaction.Input.HandJointId.HandIndexTip
		};

		private readonly FingerPinchData[] _fingersPinchData = new FingerPinchData[5]
		{
			new FingerPinchData(Oculus.Interaction.Input.HandFinger.Thumb),
			new FingerPinchData(Oculus.Interaction.Input.HandFinger.Index),
			new FingerPinchData(Oculus.Interaction.Input.HandFinger.Middle),
			new FingerPinchData(Oculus.Interaction.Input.HandFinger.Ring),
			new FingerPinchData(Oculus.Interaction.Input.HandFinger.Pinky)
		};

		private IHmd _hmd;

		private readonly ShadowHand _shadowHand = new ShadowHand();

		private float _handScale;

		private Pose _rootPose;

		private float DistanceStart
		{
			get
			{
				if (!_isPinchVisibilityGood)
				{
					return 0.02f;
				}
				return 0.016f;
			}
		}

		private float DistanceStopMax
		{
			get
			{
				if (!_isPinchVisibilityGood)
				{
					return 0.1f;
				}
				return 0.1f;
			}
		}

		private float DistanceStopOffset
		{
			get
			{
				if (!_isPinchVisibilityGood)
				{
					return 0.04f;
				}
				return 0.016f;
			}
		}

		public PinchGrabAPI(IHmd hmd = null)
		{
			_hmd = hmd;
		}

		public bool GetFingerIsGrabbing(Oculus.Interaction.Input.HandFinger finger)
		{
			return _fingersPinchData[(int)finger].IsPinching;
		}

		public Vector3 GetWristOffsetLocal()
		{
			float num = _fingersPinchData[0].PinchStrength;
			Vector3 tipPosition = _fingersPinchData[0].TipPosition;
			Vector3 result = tipPosition;
			for (int i = 1; i < 5; i++)
			{
				float pinchStrength = _fingersPinchData[i].PinchStrength;
				if (pinchStrength > num)
				{
					num = pinchStrength;
					Vector3 tipPosition2 = _fingersPinchData[i].TipPosition;
					result = (tipPosition + tipPosition2) * 0.5f;
				}
			}
			return result;
		}

		public bool GetFingerIsGrabbingChanged(Oculus.Interaction.Input.HandFinger finger, bool targetPinchState)
		{
			if (_fingersPinchData[(int)finger].IsPinchingChanged)
			{
				return _fingersPinchData[(int)finger].IsPinching == targetPinchState;
			}
			return false;
		}

		public float GetFingerGrabScore(Oculus.Interaction.Input.HandFinger finger)
		{
			return _fingersPinchData[(int)finger].PinchStrength;
		}

		public void Update(IHand hand)
		{
			hand.GetRootPose(out var pose);
			hand.GetJointPosesLocal(out var localJointPoses);
			Update(localJointPoses, hand.Handedness, pose, hand.Scale);
		}

		internal void Update(IReadOnlyList<Pose> handPoses, Oculus.Interaction.Input.Handedness handedness, Pose rootPose, float handScale)
		{
			ClearState();
			_shadowHand.SetRoot(Pose.identity);
			_shadowHand.FromJoints(handPoses, flipHandedness: false);
			_rootPose = rootPose;
			_handScale = handScale;
			_isPinchVisibilityGood = PinchHasGoodVisibility(handedness);
			UpdateThumb(handedness);
			UpdateFinger(Oculus.Interaction.Input.HandFinger.Index);
			UpdateFinger(Oculus.Interaction.Input.HandFinger.Middle);
			UpdateFinger(Oculus.Interaction.Input.HandFinger.Ring);
			UpdateFinger(Oculus.Interaction.Input.HandFinger.Pinky);
		}

		private void UpdateThumb(Oculus.Interaction.Input.Handedness handedness)
		{
			int num = 0;
			_fingersPinchData[num].UpdateTipPosition(_shadowHand);
			float distance = float.PositiveInfinity;
			if (IsThumbNearIndex(handedness))
			{
				Vector3 position = _shadowHand.GetWorldPose(Oculus.Interaction.Input.HandJointId.HandThumb3).position;
				Vector3 tipPosition = _fingersPinchData[num].TipPosition;
				distance = GetClosestDistanceToJoints(position, tipPosition, INDEX_JOINTS, 0.5f);
			}
			UpdatePinchData(distance, num, 0.03f, 0.04f, 0.05f);
		}

		private bool IsThumbNearIndex(Oculus.Interaction.Input.Handedness handedness)
		{
			Pose worldPose = _shadowHand.GetWorldPose(Oculus.Interaction.Input.HandJointId.HandThumbTip);
			Pose worldPose2 = _shadowHand.GetWorldPose(Oculus.Interaction.Input.HandJointId.HandIndex2);
			Vector3 inNormal = worldPose2.rotation * ((handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftThumbSide : Oculus.Interaction.Input.Constants.RightThumbSide);
			float num = Mathf.Abs(new Plane(inNormal, worldPose2.position).GetDistanceToPoint(worldPose.position));
			if (num > 0f)
			{
				return num < 0.05f;
			}
			return false;
		}

		private void UpdateFinger(Oculus.Interaction.Input.HandFinger finger)
		{
			_fingersPinchData[(int)finger].UpdateTipPosition(_shadowHand);
			float distance = float.PositiveInfinity;
			if (_fingersPinchData[(int)finger].IsPinching)
			{
				distance = GetClosestDistanceToJoints(_fingersPinchData[(int)finger].TipPosition, THUMB_JOINTS_MAINTAIN);
			}
			if (IsPointNearThumb(_fingersPinchData[(int)finger].TipPosition, THUMB_JOINTS_SELECT))
			{
				distance = GetClosestDistanceToJoints(_fingersPinchData[(int)finger].TipPosition, THUMB_JOINTS_SELECT);
			}
			UpdatePinchData(distance, (int)finger, DistanceStart, DistanceStopOffset, DistanceStopMax);
		}

		private void UpdatePinchData(float distance, int fingerIndex, float distanceStart, float distanceStopOffset, float distanceStopMax)
		{
			_fingersPinchData[fingerIndex].UpdateIsPinching(distance, distanceStart, distanceStopOffset, distanceStopMax);
			float value = (distance - distanceStart) / (distanceStopMax - distanceStart);
			float pinchStrength = 1f - Mathf.Clamp01(value);
			_fingersPinchData[fingerIndex].PinchStrength = pinchStrength;
		}

		private void ClearState()
		{
			for (int i = 0; i < 5; i++)
			{
				_fingersPinchData[i].ClearState();
			}
		}

		private bool IsPointNearThumb(Vector3 position, Oculus.Interaction.Input.HandJointId[] thumbJoints)
		{
			Pose worldPose = _shadowHand.GetWorldPose(thumbJoints[0]);
			Pose worldPose2 = _shadowHand.GetWorldPose(thumbJoints[1]);
			Vector3 position2 = worldPose.position;
			Vector3 rhs = worldPose2.position - position2;
			return Vector3.Dot(Vector3.Project(position - position2, rhs.normalized), rhs) > 0f;
		}

		private float GetClosestDistanceToJoints(Vector3 edgeStart, Vector3 edgeEnd, Oculus.Interaction.Input.HandJointId[] targetJoints, float maximumDotAllowed = 1f)
		{
			float num = float.PositiveInfinity;
			for (int i = 0; i < targetJoints.Length - 1; i++)
			{
				Pose worldPose = _shadowHand.GetWorldPose(targetJoints[i]);
				Pose worldPose2 = _shadowHand.GetWorldPose(targetJoints[i + 1]);
				if (!(maximumDotAllowed < 1f) || !(Vector3.Dot((edgeEnd - edgeStart).normalized, (worldPose2.position - worldPose.position).normalized) >= maximumDotAllowed))
				{
					float b = DistanceSegmentToSegment(edgeStart, edgeEnd, worldPose.position, worldPose2.position);
					num = Mathf.Min(num, b);
				}
			}
			return num;
		}

		private float GetClosestDistanceToJoints(Vector3 position, Oculus.Interaction.Input.HandJointId[] targetJoints)
		{
			float num = float.PositiveInfinity;
			for (int i = 0; i < targetJoints.Length - 1; i++)
			{
				Pose worldPose = _shadowHand.GetWorldPose(targetJoints[i]);
				Pose worldPose2 = _shadowHand.GetWorldPose(targetJoints[i + 1]);
				num = Mathf.Min(num, DistancePointToSegment(position, worldPose.position, worldPose2.position));
			}
			return num;
		}

		private float DistancePointToSegment(Vector3 point, Vector3 a0, Vector3 a1)
		{
			Vector3 vector = a1 - a0;
			float num = Mathf.Clamp01(Vector3.Dot(point - a0, vector) / Vector3.Dot(vector, vector));
			return (a0 + num * vector - point).magnitude;
		}

		private float DistanceSegmentToSegment(Vector3 a0, Vector3 a1, Vector3 b0, Vector3 b1)
		{
			Vector3 vector = a1 - a0;
			Vector3 vector2 = b1 - b0;
			Vector3 planeNormal = Vector3.Cross(vector, vector2);
			Vector3 vector3 = Vector3.ProjectOnPlane(a0, planeNormal);
			Vector3 vector4 = Vector3.ProjectOnPlane(b0, planeNormal);
			Vector3 vector5 = Vector3.ProjectOnPlane(vector, planeNormal);
			Vector3 onNormal = Vector3.ProjectOnPlane(vector2, planeNormal);
			Vector3 vector6 = vector4 + Vector3.Project(vector3 - vector4, onNormal) - vector3;
			float num = Vector3.Dot(vector5.normalized, vector6.normalized);
			float num2 = vector6.magnitude / num;
			Vector3 vector7 = a0 + vector * Mathf.Clamp01(num2 / vector5.magnitude);
			Vector3 vector8 = Vector3.Project(vector7 - b0, vector2);
			if (Vector3.Dot(vector8, vector2) < 0f)
			{
				vector8 = Vector3.zero;
			}
			else if (vector8.sqrMagnitude > vector2.sqrMagnitude)
			{
				vector8 = vector2;
			}
			Vector3 b2 = b0 + vector8;
			return Vector3.Distance(vector7, b2);
		}

		private bool PinchHasGoodVisibility(Oculus.Interaction.Input.Handedness handedness)
		{
			if (_hmd == null || !_hmd.TryGetRootPose(out var pose))
			{
				return false;
			}
			Vector3 vector = _rootPose.rotation * ((handedness == Oculus.Interaction.Input.Handedness.Left) ? Oculus.Interaction.Input.Constants.LeftPinkySide : Oculus.Interaction.Input.Constants.RightPinkySide);
			Vector3 forward = pose.forward;
			return Vector3.Angle(vector, forward) <= 40f;
		}
	}
	public class ControllerPinchInjector : MonoBehaviour
	{
		private class ControllerPinchAPI : IFingerAPI
		{
			private IController _controller;

			private float _triggerStrength;

			private float _gripStrength;

			private bool _triggerDown;

			private bool _gripDown;

			private bool _prevTriggerDown;

			private bool _prevGripDown;

			private Pose _indexPinchPose = Pose.identity;

			private Pose _middlePinchPose = Pose.identity;

			private Pose _pinchPose = Pose.identity;

			public ControllerPinchAPI(IController controller)
			{
				_controller = controller;
			}

			public float GetFingerGrabScore(Oculus.Interaction.Input.HandFinger finger)
			{
				switch (finger)
				{
				case Oculus.Interaction.Input.HandFinger.Thumb:
					return _triggerStrength;
				case Oculus.Interaction.Input.HandFinger.Index:
					return _triggerStrength;
				case Oculus.Interaction.Input.HandFinger.Middle:
				case Oculus.Interaction.Input.HandFinger.Ring:
				case Oculus.Interaction.Input.HandFinger.Pinky:
					return _gripStrength;
				default:
					return 0f;
				}
			}

			public bool GetFingerIsGrabbing(Oculus.Interaction.Input.HandFinger finger)
			{
				switch (finger)
				{
				case Oculus.Interaction.Input.HandFinger.Thumb:
					return _triggerDown;
				case Oculus.Interaction.Input.HandFinger.Index:
					return _triggerDown;
				case Oculus.Interaction.Input.HandFinger.Middle:
				case Oculus.Interaction.Input.HandFinger.Ring:
				case Oculus.Interaction.Input.HandFinger.Pinky:
					return _gripDown;
				default:
					return false;
				}
			}

			public bool GetFingerIsGrabbingChanged(Oculus.Interaction.Input.HandFinger finger, bool targetPinchState)
			{
				switch (finger)
				{
				case Oculus.Interaction.Input.HandFinger.Thumb:
					if (_triggerDown != targetPinchState || _triggerDown == _prevTriggerDown)
					{
						if (_gripDown == targetPinchState)
						{
							return _gripDown != _prevGripDown;
						}
						return false;
					}
					return true;
				case Oculus.Interaction.Input.HandFinger.Index:
					if (_triggerDown == targetPinchState)
					{
						return _triggerDown != _prevTriggerDown;
					}
					return false;
				case Oculus.Interaction.Input.HandFinger.Middle:
				case Oculus.Interaction.Input.HandFinger.Ring:
				case Oculus.Interaction.Input.HandFinger.Pinky:
					if (_gripDown == targetPinchState)
					{
						return _gripDown != _prevGripDown;
					}
					return false;
				default:
					return false;
				}
			}

			public Vector3 GetWristOffsetLocal()
			{
				return _pinchPose.position;
			}

			public void Update(IHand hand)
			{
				ControllerInput controllerInput = _controller.ControllerInput;
				_prevGripDown = _gripDown;
				_prevTriggerDown = _triggerDown;
				_triggerStrength = controllerInput.Trigger;
				_triggerDown = controllerInput.TriggerButton;
				_gripStrength = controllerInput.Grip;
				_gripDown = controllerInput.GripButton;
				hand.GetJointPoseFromWrist(Oculus.Interaction.Input.HandJointId.HandIndexTip, out _indexPinchPose);
				hand.GetJointPoseFromWrist(Oculus.Interaction.Input.HandJointId.HandMiddleTip, out _middlePinchPose);
				hand.GetJointPoseFromWrist(Oculus.Interaction.Input.HandJointId.HandThumbTip, out var pose);
				_indexPinchPose.Lerp(in pose, 0.5f);
				_middlePinchPose.Lerp(in pose, 0.5f);
				float num = _triggerStrength + _gripStrength;
				float t = ((num > 0f) ? (_gripStrength / num) : 0.5f);
				PoseUtils.Lerp(in _indexPinchPose, in _middlePinchPose, t, ref _pinchPose);
			}
		}

		[SerializeField]
		private HandGrabAPI _handGrabAPI;

		[SerializeField]
		[Interface(typeof(IController), new Type[] { })]
		private UnityEngine.Object _controller;

		protected bool _started;

		private IController Controller { get; set; }

		protected virtual void Awake()
		{
			Controller = _controller as IController;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			_handGrabAPI.InjectOptionalFingerPinchAPI(new ControllerPinchAPI(Controller));
			_handGrabAPI.InjectOptionalFingerGrabAPI(new ControllerPinchAPI(Controller));
			this.EndStart(ref _started);
		}

		public void InjectAll(HandGrabAPI handGrabAPI, IController controller)
		{
			InjectHandGrabAPI(handGrabAPI);
			InjectController(controller);
		}

		public void InjectHandGrabAPI(HandGrabAPI handGrabAPI)
		{
			_handGrabAPI = handGrabAPI;
		}

		public void InjectController(IController controller)
		{
			_controller = controller as UnityEngine.Object;
			Controller = controller;
		}
	}
