					return _pinkyRequirement != FingerRequirement.Required;
				}
				return false;
			}
		}

		public FingerRequirement this[Oculus.Interaction.Input.HandFinger fingerID]
		{
			get
			{
				return fingerID switch
				{
					Oculus.Interaction.Input.HandFinger.Thumb => _thumbRequirement, 
					Oculus.Interaction.Input.HandFinger.Index => _indexRequirement, 
					Oculus.Interaction.Input.HandFinger.Middle => _middleRequirement, 
					Oculus.Interaction.Input.HandFinger.Ring => _ringRequirement, 
					Oculus.Interaction.Input.HandFinger.Pinky => _pinkyRequirement, 
					_ => FingerRequirement.Ignored, 
