				case Oculus.Interaction.Input.HandFinger.Thumb:
					_thumbRequirement = value;
					break;
				case Oculus.Interaction.Input.HandFinger.Index:
					_indexRequirement = value;
					break;
				case Oculus.Interaction.Input.HandFinger.Middle:
					_middleRequirement = value;
					break;
				case Oculus.Interaction.Input.HandFinger.Ring:
					_ringRequirement = value;
					break;
				case Oculus.Interaction.Input.HandFinger.Pinky:
					_pinkyRequirement = value;
					break;
				}
			}
		}

		public static GrabbingRule DefaultPalmRule { get; } = new GrabbingRule
