		};

		public void StripIrrelevant(ref Oculus.Interaction.Input.HandFingerFlags fingerFlags)
		{
			for (int i = 0; i < 5; i++)
			{
				Oculus.Interaction.Input.HandFinger fingerID = (Oculus.Interaction.Input.HandFinger)i;
				if (this[fingerID] == FingerRequirement.Ignored)
				{
					fingerFlags &= (Oculus.Interaction.Input.HandFingerFlags)(~(1 << i));
				}
			}
		}

		public GrabbingRule(Oculus.Interaction.Input.HandFingerFlags mask, in GrabbingRule otherRule)
		{
			_thumbRequirement = (((mask & Oculus.Interaction.Input.HandFingerFlags.Thumb) != Oculus.Interaction.Input.HandFingerFlags.None) ? otherRule._thumbRequirement : FingerRequirement.Ignored);
			_indexRequirement = (((mask & Oculus.Interaction.Input.HandFingerFlags.Index) != Oculus.Interaction.Input.HandFingerFlags.None) ? otherRule._indexRequirement : FingerRequirement.Ignored);
			_middleRequirement = (((mask & Oculus.Interaction.Input.HandFingerFlags.Middle) != Oculus.Interaction.Input.HandFingerFlags.None) ? otherRule._middleRequirement : FingerRequirement.Ignored);
			_ringRequirement = (((mask & Oculus.Interaction.Input.HandFingerFlags.Ring) != Oculus.Interaction.Input.HandFingerFlags.None) ? otherRule._ringRequirement : FingerRequirement.Ignored);
			_pinkyRequirement = (((mask & Oculus.Interaction.Input.HandFingerFlags.Pinky) != Oculus.Interaction.Input.HandFingerFlags.None) ? otherRule._pinkyRequirement : FingerRequirement.Ignored);
			_unselectMode = otherRule.UnselectMode;
