				{
					Vector3 position = PoseUtils.Delta(in _lastStates.JointPoses[num], in _lastStates.JointPoses[i]).position;
					PoseUtils.Multiply(in data.JointPoses[num], new Pose(position, data.Joints[i]), ref data.JointPoses[i]);
				}
			}
		}

		private void UpdateRootPose(ref Pose root)
		{
			float t = (_wristPositionLocked ? _wristPositionLockCurve.Progress() : _wristPositionUnlockCurve.Progress());
			Vector3 b = Vector3.Lerp(root.position, _desiredWristPose.position, _wristPositionOverrideFactor);
			root.position = Vector3.Lerp(_constrainedWristPose.position, b, t);
			float t2 = (_wristRotationLocked ? _wristRotationLockCurve.Progress() : _wristRotationUnlockCurve.Progress());
			Quaternion b2 = Quaternion.Lerp(root.rotation, _desiredWristPose.rotation, _wristRotationOverrideFactor);
			root.rotation = Quaternion.Lerp(_constrainedWristPose.rotation, b2, t2);
			_lastWristPose.CopyFrom(in root);
		}

		private void UpdateJointsRotation(HandDataAsset data)
		{
			float num = 0f;
			Quaternion[] sourceRotations = data.Joints;
			for (int i = 0; i < FingersMetadata.HAND_JOINT_IDS.Length; i++)
			{
				JointFreedom jointFreedom = _jointsFreedomLevels[i];
				Quaternion quaternion = AmendMetacarpalRotation(i, in sourceRotations);
				float t = _jointsOverrideFactor[i];
				int num2 = (int)FingersMetadata.HAND_JOINT_IDS[i];
				switch (jointFreedom)
				{
				case JointFreedom.Locked:
					sourceRotations[num2] = Quaternion.Slerp(sourceRotations[num2], quaternion, t);
					break;
				case JointFreedom.Constrained:
				{
					bool flag = false;
					if (FingersMetadata.HAND_JOINT_CAN_SPREAD[i])
					{
						flag = true;
						num = 0f;
					}
					Vector3 rightThumbSide = Constants.RightThumbSide;
					Vector3 rightDorsal = Constants.RightDorsal;
					Quaternion maxLocalRot = quaternion * Quaternion.Euler(rightThumbSide * -90f * num);
					float num3 = OverFlex(in sourceRotations[num2], in maxLocalRot);
					num = Mathf.Max(num, num3);
					if (num3 < 0f)
					{
						sourceRotations[num2] = Quaternion.Slerp(sourceRotations[num2], maxLocalRot, t);
					}
					else if (flag)
					{
						Quaternion quaternion2 = sourceRotations[num2];
						float num4 = Vector3.SignedAngle(quaternion2 * rightThumbSide, maxLocalRot * rightThumbSide, quaternion2 * rightDorsal);
						float num5 = 1f - Mathf.Clamp01(num3 * _spreadAllowance);
						quaternion2 *= Quaternion.Euler(rightDorsal * num4 * num5);
						sourceRotations[num2] = quaternion2;
					}
					break;
				}
				}
				float t2 = ((_jointsFreedomLevels[i] == JointFreedom.Free) ? _jointUnlockProgressCurves[i].Progress() : _jointLockProgressCurves[i].Progress());
				sourceRotations[num2] = Quaternion.Slerp(_constrainedJointRotations[i], sourceRotations[num2], t2);
				_lastSyntheticRotation[i] = sourceRotations[num2];
			}
		}

		private Quaternion AmendMetacarpalRotation(int jointIndex, in Quaternion[] sourceRotations)
		{
			HandJointId handJointId = FingersMetadata.HAND_JOINT_IDS[jointIndex];
			int num = (int)handJointId;
			switch (handJointId)
			{
			case HandJointId.HandIndex0:
			case HandJointId.HandMiddle0:
			case HandJointId.HandRing0:
				return sourceRotations[num];
			case HandJointId.HandIndex1:
			case HandJointId.HandMiddle1:
			case HandJointId.HandRing1:
				return Quaternion.Inverse(sourceRotations[num - 1]) * _desiredJointsRotation[jointIndex];
			default:
				return _desiredJointsRotation[jointIndex];
			}
		}

		public void OverrideAllJoints(in Quaternion[] jointRotations, float overrideFactor)
		{
			for (int i = 0; i < FingersMetadata.HAND_JOINT_IDS.Length; i++)
			{
				_desiredJointsRotation[i] = jointRotations[i];
				_jointsOverrideFactor[i] = overrideFactor;
			}
		}

		public void OverrideFingerRotations(HandFinger finger, Quaternion[] rotations, float overrideFactor)
		{
			int[] array = FingersMetadata.FINGER_TO_JOINT_INDEX[(int)finger];
			for (int i = 0; i < array.Length; i++)
			{
				OverrideJointRotationAtIndex(array[i], rotations[i], overrideFactor);
			}
		}

		public void OverrideJointRotation(HandJointId jointId, Quaternion rotation, float overrideFactor)
		{
			int jointIndex = FingersMetadata.HandJointIdToIndex(jointId);
			OverrideJointRotationAtIndex(jointIndex, rotation, overrideFactor);
		}

		private void OverrideJointRotationAtIndex(int jointIndex, Quaternion rotation, float overrideFactor)
		{
			_desiredJointsRotation[jointIndex] = rotation;
			_jointsOverrideFactor[jointIndex] = overrideFactor;
		}

		public void LockFingerAtCurrent(in HandFinger finger)
		{
			SetFingerFreedom(in finger, JointFreedom.Locked);
			int num = (int)finger;
			int[] array = FingersMetadata.FINGER_TO_JOINT_INDEX[num];
			foreach (int num2 in array)
			{
				int num3 = (int)FingersMetadata.HAND_JOINT_IDS[num2];
				_desiredJointsRotation[num2] = _lastStates.Joints[num3];
				_jointsOverrideFactor[num2] = 1f;
			}
		}

		public void LockJoint(in HandJointId jointId, Quaternion rotation, float overrideFactor = 1f)
		{
			int num = FingersMetadata.HandJointIdToIndex(jointId);
			_desiredJointsRotation[num] = rotation;
			_jointsOverrideFactor[num] = 1f;
			SetJointFreedomAtIndex(num, JointFreedom.Locked);
		}

		public void SetFingerFreedom(in HandFinger finger, in JointFreedom freedomLevel, bool skipAnimation = false)
		{
			int[] array = FingersMetadata.FINGER_TO_JOINT_INDEX[(int)finger];
			for (int i = 0; i < array.Length; i++)
			{
				SetJointFreedomAtIndex(array[i], in freedomLevel, skipAnimation);
			}
		}

		public void SetJointFreedom(in HandJointId jointId, in JointFreedom freedomLevel, bool skipAnimation = false)
		{
			int jointId2 = FingersMetadata.HandJointIdToIndex(jointId);
			SetJointFreedomAtIndex(jointId2, in freedomLevel, skipAnimation);
		}

		public JointFreedom GetJointFreedom(in HandJointId jointId)
		{
			int num = FingersMetadata.HandJointIdToIndex(jointId);
			return _jointsFreedomLevels[num];
		}

		public void FreeAllJoints()
		{
			for (int i = 0; i < FingersMetadata.HAND_JOINT_IDS.Length; i++)
			{
				SetJointFreedomAtIndex(i, JointFreedom.Free);
			}
		}

		private void SetJointFreedomAtIndex(int jointId, in JointFreedom freedomLevel, bool skipAnimation = false)
		{
			if (_jointsFreedomLevels[jointId] != freedomLevel)
			{
				bool locked = freedomLevel == JointFreedom.Locked || freedomLevel == JointFreedom.Constrained;
				UpdateProgressCurve(ref _jointLockProgressCurves[jointId], ref _jointUnlockProgressCurves[jointId], locked, skipAnimation);
				_constrainedJointRotations[jointId] = _lastSyntheticRotation[jointId];
			}
			_jointsFreedomLevels[jointId] = freedomLevel;
		}

		public void LockWristPose(Pose wristPose, float overrideFactor = 1f, WristLockMode lockMode = WristLockMode.Full, bool worldPose = false, bool skipAnimation = false)
		{
			Pose pose = ((worldPose && base.TrackingToWorldTransformer != null) ? base.TrackingToWorldTransformer.ToTrackingPose(in wristPose) : wristPose);
			if ((lockMode & WristLockMode.Position) != 0)
			{
				LockWristPosition(pose.position, overrideFactor, skipAnimation);
			}
			if ((lockMode & WristLockMode.Rotation) != 0)
			{
				LockWristRotation(pose.rotation, overrideFactor, skipAnimation);
			}
		}

		public void LockWristPosition(Vector3 position, float overrideFactor = 1f, bool skipAnimation = false)
		{
			_wristPositionOverrideFactor = overrideFactor;
			_desiredWristPose.position = position;
			if (!_wristPositionLocked)
			{
				_wristPositionLocked = true;
				SyntheticWristLockChangedState(WristLockMode.Position, skipAnimation);
			}
		}

		public void LockWristRotation(Quaternion rotation, float overrideFactor = 1f, bool skipAnimation = false)
		{
			_wristRotationOverrideFactor = overrideFactor;
			_desiredWristPose.rotation = rotation;
			if (!_wristRotationLocked)
			{
				_wristRotationLocked = true;
				SyntheticWristLockChangedState(WristLockMode.Rotation, skipAnimation);
			}
		}

		public void FreeWrist(WristLockMode lockMode = WristLockMode.Full)
		{
			if ((lockMode & WristLockMode.Position) != 0 && _wristPositionLocked)
			{
				_wristPositionOverrideFactor = 0f;
				_wristPositionLocked = false;
				SyntheticWristLockChangedState(WristLockMode.Position);
			}
			if ((lockMode & WristLockMode.Rotation) != 0 && _wristRotationLocked)
			{
				_wristRotationOverrideFactor = 0f;
				_wristRotationLocked = false;
				SyntheticWristLockChangedState(WristLockMode.Rotation);
			}
		}

		private void SyntheticWristLockChangedState(WristLockMode lockMode, bool skipAnimation = false)
		{
			if ((lockMode & WristLockMode.Position) != 0)
			{
				UpdateProgressCurve(ref _wristPositionLockCurve, ref _wristPositionUnlockCurve, _wristPositionLocked, skipAnimation);
				_constrainedWristPose.position = _lastWristPose.position;
			}
			if ((lockMode & WristLockMode.Rotation) != 0)
			{
				UpdateProgressCurve(ref _wristRotationLockCurve, ref _wristRotationUnlockCurve, _wristRotationLocked, skipAnimation);
				_constrainedWristPose.rotation = _lastWristPose.rotation;
			}
		}

		private static float OverFlex(in Quaternion desiredLocalRot, in Quaternion maxLocalRot)
		{
			Vector3 lhs = desiredLocalRot * Constants.RightDistal;
			Vector3 lhs2 = desiredLocalRot * Constants.RightPinkySide;
			Vector3 rhs = maxLocalRot * Constants.RightDistal;
			Vector3 rhs2 = Vector3.Cross(lhs, rhs);
			return Vector3.Dot(lhs2, rhs2);
		}

		private static void UpdateProgressCurve(ref ProgressCurve lockProgress, ref ProgressCurve unlockProgress, bool locked, bool skipAnimation)
		{
			ProgressCurve progressCurve = (locked ? lockProgress : unlockProgress);
			if (skipAnimation)
			{
				progressCurve.End();
			}
			else
			{
				progressCurve.Start();
			}
		}

		public void InjectAllSyntheticHandModifier(UpdateModeFlags updateMode, IDataSource updateAfter, DataModifier<HandDataAsset> modifyDataFromSource, bool applyModifier, ProgressCurve wristPositionLockCurve, ProgressCurve wristPositionUnlockCurve, ProgressCurve wristRotationLockCurve, ProgressCurve wristRotationUnlockCurve, ProgressCurve jointLockCurve, ProgressCurve jointUnlockCurve, float spreadAllowance)
		{
			InjectAllHand(updateMode, updateAfter, modifyDataFromSource, applyModifier);
			InjectWristPositionLockCurve(wristPositionLockCurve);
			InjectWristPositionUnlockCurve(wristPositionUnlockCurve);
			InjectWristRotationLockCurve(wristRotationLockCurve);
			InjectWristRotationUnlockCurve(wristRotationUnlockCurve);
			InjectJointLockCurve(jointLockCurve);
			InjectJointUnlockCurve(jointUnlockCurve);
			InjectSpreadAllowance(spreadAllowance);
		}

		public void InjectWristPositionLockCurve(ProgressCurve wristPositionLockCurve)
		{
			_wristPositionLockCurve = wristPositionLockCurve;
		}

		public void InjectWristPositionUnlockCurve(ProgressCurve wristPositionUnlockCurve)
		{
			_wristPositionUnlockCurve = wristPositionUnlockCurve;
		}

		public void InjectWristRotationLockCurve(ProgressCurve wristRotationLockCurve)
		{
			_wristRotationLockCurve = wristRotationLockCurve;
		}

		public void InjectWristRotationUnlockCurve(ProgressCurve wristRotationUnlockCurve)
		{
			_wristRotationUnlockCurve = wristRotationUnlockCurve;
		}

		public void InjectJointLockCurve(ProgressCurve jointLockCurve)
		{
			_jointLockCurve = jointLockCurve;
		}

		public void InjectJointUnlockCurve(ProgressCurve jointUnlockCurve)
		{
			_jointUnlockCurve = jointUnlockCurve;
		}

		public void InjectSpreadAllowance(float spreadAllowance)
		{
			_spreadAllowance = spreadAllowance;
		}
	}
	public class DominantHandRef : MonoBehaviour, IHand, IActiveState
	{
		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _leftHand;

		[SerializeField]
		[Interface(typeof(IHand), new Type[] { })]
		private UnityEngine.Object _rightHand;

		[SerializeField]
		[Tooltip("If true, the HandRef will point to the Dominant hand. If false it will point to the Non Dominant Hand")]
		private bool _selectDominant = true;

		private Action _whenHandUpdated = delegate
		{
		};

		protected bool _started;

		public IHand LeftHand { get; private set; }

		public IHand RightHand { get; private set; }

		public bool SelectDominant
		{
			get
			{
				return _selectDominant;
			}
			set
			{
				_selectDominant = value;
			}
		}

		public IHand Hand
		{
			get
			{
				if (LeftHand.IsDominantHand != _selectDominant)
				{
					return RightHand;
				}
				return LeftHand;
			}
		}

		public Handedness Handedness => Hand.Handedness;

		public bool IsConnected => Hand.IsConnected;

		public bool IsHighConfidence => Hand.IsHighConfidence;

		public bool IsDominantHand => Hand.IsDominantHand;

		public float Scale => Hand.Scale;

		public bool IsPointerPoseValid => Hand.IsPointerPoseValid;

		public bool IsTrackedDataValid => Hand.IsTrackedDataValid;

		public int CurrentDataVersion => Hand.CurrentDataVersion;

		public bool Active => IsConnected;

		public event Action WhenHandUpdated
		{
			add
			{
				_whenHandUpdated = (Action)Delegate.Combine(_whenHandUpdated, value);
			}
			remove
			{
				_whenHandUpdated = (Action)Delegate.Remove(_whenHandUpdated, value);
			}
		}

		protected virtual void Awake()
		{
			LeftHand = _leftHand as IHand;
			RightHand = _rightHand as IHand;
		}

		protected virtual void Start()
		{
			this.BeginStart(ref _started);
			this.EndStart(ref _started);
		}

		protected virtual void OnEnable()
		{
			if (_started)
			{
				LeftHand.WhenHandUpdated += HandleLeftHandUpdated;
				RightHand.WhenHandUpdated += HandleRightHandUpdated;
			}
		}

		protected virtual void OnDisable()
		{
			if (_started)
			{
				LeftHand.WhenHandUpdated -= HandleLeftHandUpdated;
				RightHand.WhenHandUpdated -= HandleRightHandUpdated;
			}
		}

		private void HandleLeftHandUpdated()
		{
			if (LeftHand.IsDominantHand == _selectDominant)
			{
				_whenHandUpdated();
			}
		}

		private void HandleRightHandUpdated()
		{
			if (RightHand.IsDominantHand == _selectDominant)
			{
				_whenHandUpdated();
			}
		}

		public bool GetFingerIsPinching(HandFinger finger)
		{
			return Hand.GetFingerIsPinching(finger);
		}

		public bool GetIndexFingerIsPinching()
		{
			return Hand.GetIndexFingerIsPinching();
		}

		public bool GetPointerPose(out Pose pose)
		{
			return Hand.GetPointerPose(out pose);
		}

		public bool GetJointPose(HandJointId handJointId, out Pose pose)
		{
			return Hand.GetJointPose(handJointId, out pose);
		}

		public bool GetJointPoseLocal(HandJointId handJointId, out Pose pose)
		{
			return Hand.GetJointPoseLocal(handJointId, out pose);
		}

		public bool GetJointPosesLocal(out ReadOnlyHandJointPoses jointPosesLocal)
		{
			return Hand.GetJointPosesLocal(out jointPosesLocal);
		}

		public bool GetJointPoseFromWrist(HandJointId handJointId, out Pose pose)
		{
			return Hand.GetJointPoseFromWrist(handJointId, out pose);
		}

		public bool GetJointPosesFromWrist(out ReadOnlyHandJointPoses jointPosesFromWrist)
		{
			return Hand.GetJointPosesFromWrist(out jointPosesFromWrist);
		}

		public bool GetPalmPoseLocal(out Pose pose)
		{
			return Hand.GetPalmPoseLocal(out pose);
		}

		public bool GetFingerIsHighConfidence(HandFinger finger)
		{
			return Hand.GetFingerIsHighConfidence(finger);
		}

		public float GetFingerPinchStrength(HandFinger finger)
		{
			return Hand.GetFingerPinchStrength(finger);
		}

		public bool GetRootPose(out Pose pose)
		{
			return Hand.GetRootPose(out pose);
		}

		public void InjectAllDominantHandRef(IHand leftHand, IHand rightHand)
		{
			InjectLeftHand(leftHand);
			InjectRightHand(rightHand);
		}

		public void InjectLeftHand(IHand leftHand)
		{
			_leftHand = leftHand as UnityEngine.Object;
			LeftHand = leftHand;
		}

		public void InjectRightHand(IHand rightHand)
		{
			_rightHand = rightHand as UnityEngine.Object;
			RightHand = rightHand;
		}
	}
	public enum JointFreedom
	{
		Free,
		Constrained,
		Locked
	}
	public class FingersMetadata
	{
		public static readonly HandJointId[] HAND_JOINT_IDS = new HandJointId[19]
		{
			HandJointId.HandThumb1,
			HandJointId.HandThumb2,
			HandJointId.HandThumb3,
			HandJointId.HandIndex0,
			HandJointId.HandIndex1,
			HandJointId.HandIndex2,
			HandJointId.HandIndex3,
			HandJointId.HandMiddle0,
			HandJointId.HandMiddle1,
			HandJointId.HandMiddle2,
			HandJointId.HandMiddle3,
			HandJointId.HandRing0,
			HandJointId.HandRing1,
			HandJointId.HandRing2,
			HandJointId.HandRing3,
			HandJointId.HandPinky0,
			HandJointId.HandPinky1,
			HandJointId.HandPinky2,
			HandJointId.HandPinky3
		};

		public static readonly HandJointId[][] FINGER_TO_JOINTS = InitializeFingerToJoint();

		public static readonly int[][] FINGER_TO_JOINT_INDEX = InitializeFingerToJointIndex();

		public static readonly bool[] HAND_JOINT_CAN_SPREAD = InitializeCanSpread();

		public static readonly bool[] HAND_JOINT_CAN_MOVE = InitializeCanMove();

		public static readonly int[] JOINT_TO_FINGER_INDEX = InitializeJointToFingerIndex();

		[Obsolete("Use JointToFingerList instead")]
		public static readonly HandFinger[] JOINT_TO_FINGER = null;

		private static int[] JOINT_TO_INDEX = InitializeHandJointIdToIndex();

		public static JointFreedom[] DefaultFingersFreedom()
		{
			return new JointFreedom[5]
			{
				JointFreedom.Locked,
				JointFreedom.Locked,
				JointFreedom.Constrained,
				JointFreedom.Constrained,
				JointFreedom.Free
			};
		}

		public static int HandJointIdToIndex(HandJointId id)
		{
			return JOINT_TO_INDEX[(int)id];
		}

		private static int[] InitializeHandJointIdToIndex()
		{
			int[] array = new int[26];
			HandJointId jointId;
			for (jointId = HandJointId.HandStart; jointId < HandJointId.HandEnd; jointId++)
			{
				array[(int)jointId] = Array.FindIndex(HAND_JOINT_IDS, (HandJointId joint) => joint == jointId);
			}
			return array;
		}

		private static HandJointId[][] InitializeFingerToJoint()
		{
			HandJointId[][] array = new HandJointId[HandJointUtils.FingerToJointList.Count][];
			for (int i = 0; i < HandJointUtils.FingerToJointList.Count; i++)
			{
				int num = HandJointUtils.FingerToJointList[i].Length - 1;
				array[i] = new HandJointId[num];
				Array.Copy(HandJointUtils.FingerToJointList[i], array[i], num);
			}
			return array;
		}

		private static int[][] InitializeFingerToJointIndex()
		{
			HandJointId[][] array = InitializeFingerToJoint();
			int[] array2 = InitializeHandJointIdToIndex();
			int[][] array3 = new int[array.Length][];
			for (int i = 0; i < array.Length; i++)
			{
				int[] array4 = new int[array[i].Length];
				for (int j = 0; j < array[i].Length; j++)
				{
					array4[j] = array2[(int)array[i][j]];
				}
				array3[i] = array4;
			}
			return array3;
		}

		private static int[] InitializeJointToFingerIndex()
		{
			int[] array = new int[26];
			for (HandJointId handJointId = HandJointId.HandStart; handJointId < HandJointId.HandEnd; handJointId++)
			{
				int num = -1;
				HandJointId handJointId2 = handJointId;
				while (HandJointUtils.JointToFingerList[(int)handJointId2] != HandFinger.Invalid)
				{
					num++;
					handJointId2 = HandJointUtils.JointParentList[(int)handJointId2];
				}
				array[(int)handJointId] = num;
			}
			return array;
		}

		private static bool[] InitializeCanSpread()
		{
			int[] array = InitializeJointToFingerIndex();
			bool[] array2 = new bool[HAND_JOINT_IDS.Length];
			for (int i = 0; i < HAND_JOINT_IDS.Length; i++)
			{
				HandJointId handJointId = HAND_JOINT_IDS[i];
				int num = array[(int)handJointId];
				array2[i] = num <= 1 && handJointId != HandJointId.HandThumb2;
			}
			return array2;
		}

		private static bool[] InitializeCanMove()
		{
			bool[] array = new bool[HAND_JOINT_IDS.Length];
			for (int i = 0; i < HAND_JOINT_IDS.Length; i++)
			{
				HandJointId handJointId = HAND_JOINT_IDS[i];
				array[i] = handJointId != HandJointId.HandIndex0 && handJointId != HandJointId.HandMiddle0 && handJointId != HandJointId.HandRing0;
			}
			return array;
		}
	}
	public class FromHandPrefabDataSource : DataSource<HandDataAsset>
	{
		private readonly HandDataAsset _handDataAsset = new HandDataAsset();

		[SerializeField]
		private Handedness _handedness;

		[SerializeField]
		private bool _hidePrefabOnStart = true;

		[HideInInspector]
		[SerializeField]
		private List<Transform> _jointTransforms = new List<Transform>();

		[HideInInspector]
		[SerializeField]
		private List<Transform> _jointTransformsOpenXR = new List<Transform>();

		[SerializeField]
		[Interface(typeof(IHandSkeletonProvider), new Type[] { })]
		private UnityEngine.Object _handSkeletonProvider;

		private IHandSkeletonProvider HandSkeletonProvider;

		[SerializeField]
		[Interface(typeof(ITrackingToWorldTransformer), new Type[] { })]
		[Optional]
		private UnityEngine.Object _trackingToWorldTransformer;

		private ITrackingToWorldTransformer TrackingToWorldTransformer;

		protected override HandDataAsset DataAsset => _handDataAsset;

		public Handedness Handedness => _handedness;

		public List<Transform> JointTransforms => _jointTransformsOpenXR;

		protected virtual void Awake()
		{
			HandSkeletonProvider = _handSkeletonProvider as IHandSkeletonProvider;
			if (_trackingToWorldTransformer != null)
			{
				TrackingToWorldTransformer = _trackingToWorldTransformer as ITrackingToWorldTransformer;
			}
			_handDataAsset.Config.Handedness = _handedness;
		}

		protected override void Start()
		{
			base.Start();
			HandDataSourceConfig config = _handDataAsset.Config;
			config.TrackingToWorldTransformer = TrackingToWorldTransformer;
			config.HandSkeleton = HandSkeletonProvider[_handedness];
			if (_hidePrefabOnStart)
			{
				Renderer[] componentsInChildren = base.gameObject.GetComponentsInChildren<Renderer>();
				for (int i = 0; i < componentsInChildren.Length; i++)
				{
					componentsInChildren[i].enabled = false;
				}
			}
		}

		protected override void UpdateData()
		{
			_handDataAsset.IsDataValid = true;
			_handDataAsset.IsConnected = true;
			_handDataAsset.IsTracked = true;
			_handDataAsset.IsHighConfidence = true;
			_handDataAsset.RootPoseOrigin = PoseOrigin.SyntheticPose;
			_handDataAsset.Root = base.transform.GetPose();
			_handDataAsset.HandScale = 1f;
			for (int i = 0; i < 26; i++)
			{
				Transform transform = JointTransforms[i];
				if (transform == null)
				{
					_handDataAsset.Joints[i] = Quaternion.identity;
					_handDataAsset.JointPoses[i] = new Pose(Vector3.zero, Quaternion.identity);
					continue;
				}
				_handDataAsset.Joints[i] = transform.transform.localRotation;
				Pose to = transform.transform.GetPose();
				to = base.transform.Delta(in to);
				_handDataAsset.JointPoses[i] = to;
			}
		}

		public Transform GetTransformFor(HandJointId jointId)
		{
			return JointTransforms[(int)jointId];
		}
	}
	public class Hand : DataModifier<HandDataAsset>, IHand
	{
		private HandJointCache _jointPosesCache;

		private static readonly Vector3 PALM_LOCAL_OFFSET = new Vector3(0.08f, -0.01f, 0f);

		public Handedness Handedness => GetData().Config.Handedness;

		public ITrackingToWorldTransformer TrackingToWorldTransformer => GetData().Config.TrackingToWorldTransformer;

		public HandSkeleton HandSkeleton => GetData().Config.HandSkeleton;

		public bool IsConnected => GetData().IsDataValidAndConnected;

		public bool IsHighConfidence => GetData().IsHighConfidence;

		public bool IsDominantHand => GetData().IsDominantHand;

		public float Scale => ((TrackingToWorldTransformer != null) ? TrackingToWorldTransformer.Transform.lossyScale.x : 1f) * GetData().HandScale;

		public bool IsPointerPoseValid => IsPoseOriginAllowed(GetData().PointerPoseOrigin);

		public bool IsTrackedDataValid => IsPoseOriginAllowed(GetData().RootPoseOrigin);

		public event Action WhenHandUpdated = delegate
		{
		};

		protected override void Apply(HandDataAsset data)
		{
		}

		public override void MarkInputDataRequiresUpdate()
		{
			base.MarkInputDataRequiresUpdate();
			if (base.Started)
			{
				InitializeJointPosesCache();
				this.WhenHandUpdated();
			}
		}

		private void InitializeJointPosesCache()
		{
			if (_jointPosesCache == null && GetData().IsDataValidAndConnected)
			{
				_jointPosesCache = new HandJointCache();
			}
		}

		private void CheckJointPosesCacheUpdate()
		{
			if (_jointPosesCache != null && CurrentDataVersion != _jointPosesCache.LocalDataVersion)
			{
				_jointPosesCache.Update(GetData(), CurrentDataVersion, TrackingToWorldTransformer?.Transform);
			}
		}

		public bool GetFingerIsPinching(HandFinger finger)
		{
			HandDataAsset data = GetData();
			if (data.IsConnected)
			{
				return data.IsFingerPinching[(int)finger];
			}
			return false;
		}

		public bool GetIndexFingerIsPinching()
		{
			return GetFingerIsPinching(HandFinger.Index);
		}

		public bool GetPointerPose(out Pose pose)
		{
			HandDataAsset data = GetData();
			return ValidatePose(in data.PointerPose, data.PointerPoseOrigin, out pose);
		}

		public bool GetJointPose(HandJointId handJointId, out Pose pose)
		{
			pose = Pose.identity;
			if (!IsTrackedDataValid || _jointPosesCache == null || !GetRootPose(out var _))
			{
				return false;
			}
			CheckJointPosesCacheUpdate();
			pose = _jointPosesCache.GetWorldJointPose(handJointId);
			return true;
		}

		public bool GetJointPoseLocal(HandJointId handJointId, out Pose pose)
		{
			pose = Pose.identity;
			if (!GetJointPosesLocal(out var localJointPoses))
			{
				return false;
			}
			pose = localJointPoses[(int)handJointId];
			return true;
		}

		public bool GetJointPosesLocal(out ReadOnlyHandJointPoses localJointPoses)
		{
			if (!IsTrackedDataValid || _jointPosesCache == null)
			{
				localJointPoses = ReadOnlyHandJointPoses.Empty;
				return false;
			}
			CheckJointPosesCacheUpdate();
			return _jointPosesCache.GetAllLocalPoses(out localJointPoses);
		}

		public bool GetJointPoseFromWrist(HandJointId handJointId, out Pose pose)
		{
			pose = Pose.identity;
			if (!GetJointPosesFromWrist(out var jointPosesFromWrist))
			{
				return false;
			}
			pose = jointPosesFromWrist[(int)handJointId];
			return true;
		}

		public bool GetJointPosesFromWrist(out ReadOnlyHandJointPoses jointPosesFromWrist)
		{
			if (!IsTrackedDataValid || _jointPosesCache == null)
			{
				jointPosesFromWrist = ReadOnlyHandJointPoses.Empty;
				return false;
			}
			CheckJointPosesCacheUpdate();
			return _jointPosesCache.GetAllPosesFromWrist(out jointPosesFromWrist);
		}

		public bool GetPalmPoseLocal(out Pose pose)
		{
			Quaternion identity = Quaternion.identity;
			Vector3 vector = PALM_LOCAL_OFFSET;
			if (Handedness == Handedness.Left)
			{
				vector = -vector;
			}
			pose = new Pose(vector * Scale, identity);
			return true;
		}

		public bool GetFingerIsHighConfidence(HandFinger finger)
		{
			return GetData().IsFingerHighConfidence[(int)finger];
		}

		public float GetFingerPinchStrength(HandFinger finger)
		{
			return GetData().FingerPinchStrength[(int)finger];
		}

		public bool GetRootPose(out Pose pose)
		{
			HandDataAsset data = GetData();
			return ValidatePose(in data.Root, data.RootPoseOrigin, out pose);
		}

		private bool ValidatePose(in Pose sourcePose, PoseOrigin sourcePoseOrigin, out Pose pose)
		{
			if (IsPoseOriginDisallowed(sourcePoseOrigin))
			{
				pose = Pose.identity;
				return false;
			}
			pose = ((TrackingToWorldTransformer != null) ? TrackingToWorldTransformer.ToWorldPose(sourcePose) : sourcePose);
			return true;
		}

		private bool IsPoseOriginAllowed(PoseOrigin poseOrigin)
		{
			return poseOrigin != PoseOrigin.None;
		}

		private bool IsPoseOriginDisallowed(PoseOrigin poseOrigin)
		{
			return poseOrigin == PoseOrigin.None;
		}

		public void InjectAllHand(UpdateModeFlags updateMode, IDataSource updateAfter, DataModifier<HandDataAsset> modifyDataFromSource, bool applyModifier)
		{
			InjectAllDataModifier(updateMode, updateAfter, modifyDataFromSource, applyModifier);
		}
	}
	[Serializable]
	public class HandDataAsset : ICopyFrom<HandDataAsset>
	{
		public bool IsDataValid;

		public bool IsConnected;

		public bool IsTracked;

		public Pose Root;

		public PoseOrigin RootPoseOrigin;

		public Pose[] JointPoses = new Pose[26];

		public float[] JointRadii = new float[26];

		[Obsolete("Deprecated. Use JointPoses instead.")]
		public Quaternion[] Joints = new Quaternion[26];

		public bool IsHighConfidence;

		public bool[] IsFingerPinching = new bool[5];

		public bool[] IsFingerHighConfidence = new bool[5];

		public float[] FingerPinchStrength = new float[5];

		public float HandScale;

		public Pose PointerPose;

		public PoseOrigin PointerPoseOrigin;

		public bool IsDominantHand;

		public HandDataSourceConfig Config = new HandDataSourceConfig();

		public bool IsDataValidAndConnected
		{
			get
			{
				if (IsDataValid)
				{
					return IsConnected;
				}
				return false;
			}
		}

		public void CopyFrom(HandDataAsset source)
		{
			IsDataValid = source.IsDataValid;
			IsConnected = source.IsConnected;
			IsTracked = source.IsTracked;
			IsHighConfidence = source.IsHighConfidence;
			IsDominantHand = source.IsDominantHand;
			Config = source.Config;
			CopyPosesFrom(source);
		}

		public void CopyPosesFrom(HandDataAsset source)
		{
			Root = source.Root;
			RootPoseOrigin = source.RootPoseOrigin;
			Array.Copy(source.JointPoses, JointPoses, 26);
			Array.Copy(source.JointRadii, JointRadii, source.JointRadii.Length);
			Array.Copy(source.Joints, Joints, 26);
			Array.Copy(source.IsFingerPinching, IsFingerPinching, IsFingerPinching.Length);
			Array.Copy(source.IsFingerHighConfidence, IsFingerHighConfidence, IsFingerHighConfidence.Length);
			Array.Copy(source.FingerPinchStrength, FingerPinchStrength, FingerPinchStrength.Length);
			HandScale = source.HandScale;
			PointerPose = source.PointerPose;
			PointerPoseOrigin = source.PointerPoseOrigin;
			Config = source.Config;
		}
	}
	public class HandDataSourceConfig
